output.rtl/cascaded_encoder.v:
Module
// Encodes an N-bit input signal and outputs the index (M = log2(N) bits)
// of the highest-priority (MSB-first) active input. Defaults to 0 if none are active.
module priority_encoder #(parameter N = 8, parameter M = $clog2(N)) (
    input  [N-1:0] input_signal,
    output reg  [M-1:0] out
);
    integer i;
    always_comb begin
        out = {M{1'b0}};  // Default to 0 if no inputs are active
        // Scan from MSB to LSB to find the first active bit.
        // Note: This loop uses SystemVerilog's "break" statement.
        for (i = N-1; i >= 0; i = i - 1) begin
            if (input_signal[i]) begin
                out = i;  // 'i' is within [0, N-1] and fits in M bits.
                break;
            end
        end
    end
endmodule

// Cascaded Encoder Module
// Processes a large N-bit input by dividing it into two halves (upper and lower)
// and encoding each half using the parameterized priority_encoder.
// Outputs:
//   out           - M-bit output representing the index of the highest-priority active input.
//   out_upper_half - (M-1)-bit output for the upper half's highest-priority active input (for debug).
//   out_lower_half - (M-1)-bit output for the lower half's highest-priority active input (for debug).
module cascaded_encoder #(parameter N = 8, parameter M = $clog2(N)) (
    input  [N-1:0] input_signal,
    output [M-1:0] out,
    output [M-2:0] out_upper_half,
    output [M-2:0] out_lower_half
);
    // Define the half-width for splitting the input signal.
    localparam HALF = N/2;

    // Upper half: Most Significant Half
    wire [HALF-1:0] upper_input = input_signal[N-1:HALF];
    wire [M-2:0] upper_out;

    // Lower half: Least Significant Half
    wire [HALF-1:0] lower_input = input_signal[HALF-1:0];
    wire [M-2:0] lower_out;

    // Instantiate priority_encoder for the upper half.
    // For an input of width HALF, the required output width is log2(HALF) = M-1.
    priority_encoder #(.N(HALF), .M(M-1)) upper_encoder (
        .input_signal(upper_input),
        .out(upper_out)
    );

    // Instantiate priority_encoder for the lower half.
    priority_encoder #(.N(HALF), .M(M-1)) lower_encoder (
        .input_signal(lower_input),
        .out(lower_out)
    );

    // Final output combination:
    // If the upper half has an active input, add the offset (HALF) to its index.
    // Otherwise, use the lower half's index.
    always_comb begin
        if (upper_out != 0)
            out = upper_out + HALF;
        else
            out = {1'b0, lower_out};  // Zero-extend lower_out to M bits.
    end

    // Debug outputs for each half.
    assign out_upper_half = upper_out;
    assign out_lower_half = lower_out;

endmodule

output.rtl/Attenuator.sv:
module Attenuator (
    input        clk,
    input        reset,
    input  [4:0] data,
    output reg   ATTN_CLK,
    output reg   ATTN_DATA,
    output reg   ATTN_LE
);

  // Internal Signals
  reg        clk_div2;
  reg  [1:0] current_state;
  reg  [4:0] shift_reg;
  reg  [2:0] bit_count;
  reg  [4:0] old_data;

  // Parameters for FSM States
  localparam IDLE  = 2'b00,
             LOAD  = 2'b01,
             SHIFT = 2'b10,
             LATCH = 2'b11;

  // Reset Condition
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      clk_div2      <= 1'b0;
      current_state <= IDLE;
      ATTN_CLK      <= 1'b0;
      ATTN_DATA     <= 1'b0;
      ATTN_LE       <= 1'b0;
      shift_reg     <= 5'b00000;
      bit_count     <= 3'd0;
      old_data      <= 5'b00000;
    end else begin
      // Toggle the clock divider on every clock edge
      clk_div2 <= ~clk_div2;

      // Update FSM and outputs only when clk_div2 is high
      if (clk_div2) begin
        case (current_state)
          IDLE: begin
            // Transition to LOAD if new data is detected
            if (data !== old_data) begin
              old_data      <= data;
              current_state <= LOAD;
            end else begin
              current_state <= IDLE;
            end
            // In IDLE, all outputs remain inactive
            ATTN_CLK   <= 1'b0;
            ATTN_DATA  <= 1'b0;
            ATTN_LE    <= 1'b0;
          end

          LOAD: begin
            // Capture the new control word into the shift register
            shift_reg   <= data;
            bit_count   <= 3'd0;
            current_state <= SHIFT;
            // Outputs remain inactive during LOAD
            ATTN_CLK   <= 1'b0;
            ATTN_DATA  <= 1'b0;
            ATTN_LE    <= 1'b0;
          end

          SHIFT: begin
            // Output the most significant bit
            ATTN_DATA  <= shift_reg[4];
            // Shift the register left by one
            shift_reg  <= shift_reg << 1;
            // Increment the bit counter
            bit_count  <= bit_count + 1;
            // After shifting all 5 bits, transition to LATCH
            if (bit_count == 4) begin
              current_state <= LATCH;
            end else begin
              current_state <= SHIFT;
            end
            // Drive ATTN_CLK with the clock divider (or simply high)
            ATTN_CLK   <= clk_div2;
            ATTN_LE    <= 1'b0;
          end

          LATCH: begin
            // Pulse ATTN_LE high for one cycle to latch the data
            ATTN_LE    <= 1'b1;
            current_state <= IDLE;
            // Ensure other outputs are inactive
            ATTN_CLK   <= 1'b0;
            ATTN_DATA  <= 1'b0;
          end

          default: begin
            current_state <= IDLE;
          end
        endcase
      end
    end
  end

endmodule

output.rtl/GP.v:
module GP (
    input  wire i_A,
    input  wire i_B,
    input  wire i_Cin,
    output wire o_generate,
    output wire o_propagate,
    output wire o_Cout
);

    // Generate signal: true if both inputs are 1
    assign o_generate = i_A & i_B;

    // Propagate signal: true if either input is 1
    assign o_propagate = i_A | i_B;

    // Carry-out signal: computed using generate, propagate, and carry-in
    assign o_Cout = o_generate | (o_propagate & i_Cin);

endmodule

