output.rtl/serial_line_code_converter.sv:
module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic [2:0] mode,      // Mode selector
    output logic serial_out       // Serial output signal
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for sampling
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output (cumulative XOR)
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Clock Pulse Generation
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse   <= 0;
        end else begin
            if (clk_counter == CLK_DIV - 1) begin
                clk_pulse <= 1;
                clk_counter <= 0;
            end else begin
                clk_pulse   <= 0;
                clk_counter <= clk_counter + 1;
            end
        end
    end

    // Previous Serial Input Tracking
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            prev_value    <= 0;
            prev_serial_in<= 0;
        end else begin
            prev_value    <= serial_in;
            prev_serial_in<= prev_value;
        end
    end

    // NRZ Pass-Through (direct output of serial input)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            nrz_out <= 0;
        end else begin
            nrz_out <= serial_in;
        end
    end

    // Return-to-Zero (RZ) Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else begin
            if (clk_pulse && serial_in)
                rz_out <= 1;
            else
                rz_out <= 0;
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else begin
            diff_out <= serial_in ^ prev_serial_in;
        end
    end

    // Inverted NRZ Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else begin
            inv_nrz_out <= ~serial_in;
        end
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_state <= 0;
            alt_invert_out   <= 0;
        end else begin
            if (alt_invert_state)
                alt_invert_out <= ~serial_in;
            else
                alt_invert_out <= serial_in;
            alt_invert_state <= ~alt_invert_state;
        end
    end

    // Parity Bit Output (Odd Parity Calculation)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else begin
            parity_out <= parity_out ^ serial_in;
        end
    end

    // Scrambled NRZ (Simple XOR with a fixed pattern)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else begin
            scrambled_out <= serial_in ^ clk_counter[0];
        end
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else begin
            edge_triggered_out <= (serial_in & ~prev_serial_in);
        end
    end

    // Output Multiplexer
    always_comb begin
        case (mode)
            3'b000: serial_out = nrz_out;
            3'b001: serial_out = rz_out;
            3'b010: serial_out = diff_out;
            3'b011: serial_out = inv_nrz_out;
            3'b100: serial_out = alt_invert_out;
            3'b101: serial_out = ~parity_out; // Invert cumulative parity to yield odd parity
            3'b110: serial_out = scrambled_out;
            3'b111: serial_out = edge_triggered_out;
            default: serial_out = 1'b0;
        endcase
    end

endmodule

module serial_line_code_converter #(parameter CLK_DIV = 16)(
    input  logic clk,             // System clock
    input  logic reset_n,         // Active-low reset
    input  logic serial_in,       // Serial input signal
    input  logic enable,          // Enable signal to control module operation
    input  logic [2:0] mode,      // Mode selector for encoding
    output logic serial_out,      // Encoded output signal
    output logic error_flag,      // Flag indicating an error (invalid serial_in)
    output logic [15:0] diagnostic_bus  // 16-bit diagnostic output bus
);

    // Internal signals
    logic [3:0] clk_counter;      // Clock divider counter
    logic clk_pulse;              // Clock pulse for timing-specific encodings
    logic prev_serial_in;         // Previous serial input for edge detection
    logic prev_value;             // Holds the previous value of serial_in
    logic nrz_out;                // NRZ encoding output
    logic rz_out;                 // Return-to-Zero encoding output
    logic diff_out;               // Differential encoding output
    logic inv_nrz_out;            // Inverted NRZ output
    logic alt_invert_out;         // NRZ with alternating bit inversion output
    logic alt_invert_state;       // State for alternating inversion
    logic parity_out;             // Parity Bit Output (Odd Parity)
    logic scrambled_out;          // Scrambled NRZ output
    logic edge_triggered_out;     // Edge-Triggered NRZ output

    // Error detection signals
    logic [7:0] error_counter;    // 8-bit error counter

    //--------------------------------------------------------------------------
    // 1. Clock Pulse Generation
    //--------------------------------------------------------------------------
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            clk_counter <= 0;
            clk_pulse   <= 0;
        end else if (clk_counter == CLK_DIV - 1) begin
            clk_counter <= 0;
            clk_pulse   <= 1;
        end else begin
            clk_counter <= clk_counter + 1;
            clk_pulse   <= 0;
        end
    end

    //--------------------------------------------------------------------------
    // 2. Previous Serial Input Tracking (only update when enabled)
    //--------------------------------------------------------------------------
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            prev_value     <= 0;
            prev_serial_in <= 0;
        end else if (enable) begin
            prev_value     <= serial_in;
            prev_serial_in <= prev_value;
        end
    end

    //--------------------------------------------------------------------------
    // 3. Encoding Implementations (update only when enabled)
    //--------------------------------------------------------------------------
    // NRZ (Non-Return-to-Zero)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            nrz_out <= 0;
        end else if (enable) begin
            nrz_out <= serial_in;
        end
    end

    // RZ (Return-to-Zero)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            rz_out <= 0;
        end else if (enable) begin
            rz_out <= serial_in & clk_pulse; 
        end
    end

    // Differential Encoding
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            diff_out <= 0;
        end else if (enable) begin
            diff_out <= serial_in ^ prev_serial_in;
        end
    end

    // Inverted NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            inv_nrz_out <= 0;
        end else if (enable) begin
            inv_nrz_out <= ~serial_in;
        end
    end

    // NRZ with Alternating Bit Inversion
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            alt_invert_out    <= 0;
            alt_invert_state  <= 0;
        end else if (enable) begin
            alt_invert_state  <= ~alt_invert_state; 
            alt_invert_out    <= (alt_invert_state ? ~serial_in : serial_in);
        end
    end

    // Parity Bit Output (Odd Parity)
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            parity_out <= 0;
        end else if (enable) begin
            parity_out <= serial_in ^ parity_out; 
        end
    end

    // Scrambled NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            scrambled_out <= 0;
        end else if (enable) begin
            scrambled_out <= serial_in ^ clk_counter[0]; 
        end
    end

    // Edge-Triggered NRZ
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            edge_triggered_out <= 0;
        end else if (enable) begin
            edge_triggered_out <= (serial_in & ~prev_serial_in);
        end
    end

    //--------------------------------------------------------------------------
    // 4. Error Detection and Counter Update (active only when enabled)
    //--------------------------------------------------------------------------
    always_ff @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            error_flag   <= 0;
            error_counter<= 0;
        end else if (enable) begin
            // Check for invalid serial_in (1'bx or 1'bz)
            if ((serial_in !== 1'b0) && (serial_in !== 1'b1)) begin
                error_flag   <= 1;
                error_counter<= error_counter + 1;
            end else begin
                error_flag   <= 0;
            end
        end
    end

    //--------------------------------------------------------------------------
    // 5. Select Encoded Output Based on Mode and Enable Signal
    //--------------------------------------------------------------------------
    always_comb begin
        if (!enable) begin
            serial_out = 0;
        end else begin
            case (mode)
                3'b000: serial_out = nrz_out;                
                3'b001: serial_out = rz_out;                 
                3'b010: serial_out = diff_out;               
                3'b011: serial_out = inv_nrz_out;            
                3'b100: serial_out = alt_invert_out;         
                3'b101: serial_out = parity_out;             
                3'b110: serial_out = scrambled_out;          
                3'b111: serial_out = edge_triggered_out;     
                default: serial_out = 0;                     
            endcase
        end
    end

    //--------------------------------------------------------------------------
    // 6. Diagnostic Output Bus Construction
    //--------------------------------------------------------------------------
    // Bit Mapping:
    // [15:13] : Current mode (3 bits)
    // [12]    : Error flag
    // [11:4]  : Error counter (8 bits)
    // [3]     : Clock pulse status
    // [2]     : Encoded output (serial_out)
    // [1]     : Alternating bit inversion output (alt_invert_out)
    // [0]     : Parity bit output (parity_out)
    always_comb begin
        if (!enable) begin
            diagnostic_bus = 16'b0;
        end else begin
            diagnostic_bus[15:13] = mode;
            diagnostic_bus[12]    = error_flag;
            diagnostic_bus[11:4]  = error_counter;
            diagnostic_bus[3]     = clk_pulse;
            diagnostic_bus[2]     = serial_out;
            diagnostic_bus[1]     = alt_invert_out;
            diagnostic_bus[0]     = parity_out;
        end
    end

endmodule

input.rtl/String_to_ASCII_Converter.sv:
module String_to_ASCII_Converter (
    input wire clk,                       // Clock signal
    input wire reset,                     // Reset signal
    input wire start,                     // Start conversion
    input wire [7:0] char_in [7:0],       // 8-character input string (7 bits per character: 0-95)
    output reg [7:0] ascii_out,           // Final latched ASCII output
    output reg valid,                     // Indicates valid output
    output reg ready                      // Indicates module ready to accept input
);
    // Parameters for character type identification
    localparam DIGIT   = 2'd0;
    localparam UPPER   = 2'd1;
    localparam LOWER   = 2'd2;
    localparam SPECIAL = 2'd3;
    // ASCII Offsets
    localparam DIGIT_OFFSET   = 8'd48;    // '0' = 48
    localparam UPPER_OFFSET   = 8'd65;    // 'A' = 65
    localparam LOWER_OFFSET   = 8'd97;    // 'a' = 97
    localparam SPECIAL_OFFSET = 8'd33;   // First special character '!' = 33
    // Registers
    reg [3:0] index;                      // Index for current character
    reg active;                           // Indicates active conversion
    reg [1:0] char_type;                  // Current character type
    reg [7:0] intermediate_ascii;         // Combinational ASCII value
    // Function to determine character type
    function [1:0] determine_char_type;
        input [7:0] char;
        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

