        begin
            if (char < 8'd10)
                determine_char_type = DIGIT;    // '0'-'9'
            else if (char < 8'd36)
                determine_char_type = UPPER;    // 'A'-'Z'
            else if (char < 8'd62)
                determine_char_type = LOWER;    // 'a'-'z'
            else
                determine_char_type = SPECIAL;  // Special characters
        end
    endfunction
    // Combinational logic for ASCII calculation
    always @(*) begin
        // Determine character type
        char_type = determine_char_type(char_in[index]);
        // Calculate ASCII based on character type
        case (char_type)
            DIGIT:   intermediate_ascii = char_in[index] + DIGIT_OFFSET;          // '0'-'9'
            UPPER:   intermediate_ascii = (char_in[index] - 8'd10) + UPPER_OFFSET; // 'A'-'Z'
            LOWER:   intermediate_ascii = (char_in[index] - 8'd36) + LOWER_OFFSET; // 'a'-'z'
            SPECIAL: intermediate_ascii = (char_in[index] - 8'd62) + SPECIAL_OFFSET; // Special characters
            default: intermediate_ascii = 8'd0;
        endcase
    end
    // Sequential logic
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            index       <= 4'd0;
            ascii_out   <= 8'd0;
            valid       <= 1'b0;
            ready       <= 1'b1;
            active      <= 1'b0;
        end else begin
            if (start && ready) begin
                // Start conversion
                ready <= 1'b0;
                active <= 1'b1;
                index <= 4'd0;
                valid <= 1'b0;
            end else if (active) begin
                // Process current character
                if (index < 8) begin
                    ascii_out <= intermediate_ascii; // Latch current ASCII value
                    valid <= 1'b1; // Indicate valid output
                    index <= index + 1;
                end else begin
                    // Finish conversion
                    active <= 1'b0;
                    ready <= 1'b1;
                    valid <= 1'b0;
                end
            end
        end
    end
endmodule

output.rtl/sync_muller_c_element.sv:
module sync_muller_c_element #(
  parameter NUM_INPUT  = 2, // Number of input signals
  parameter PIPE_DEPTH = 1  // Number of pipeline stages
) (
  input  logic                  clk,   // Clock signal
  input  logic                  srst,  // Synchronous reset signal
  input  logic                  clr,   // Clear pipeline and output
  input  logic                  clk_en, // Clock enable signal
  input  logic  [NUM_INPUT-1:0] inp,   // Input signals (NUM_INPUT-width vector)
  output logic                  out    // Output signal
);

  // Pipeline to store intermediate states of inputs
  // Total bits = PIPE_DEPTH * NUM_INPUT
  logic [(PIPE_DEPTH*NUM_INPUT)-1:0] pipe;
  genvar i;

  // Generate block for pipeline implementation
  generate
    for (i = 0; i < PIPE_DEPTH; i = i + 1) begin : pipeline_stages
      always_ff @(posedge clk) begin
        // Priority: synchronous reset (srst) takes precedence, then clr.
        if (srst) begin
          pipe[i*NUM_INPUT +: NUM_INPUT] <= '0;
        end else if (clr) begin
          pipe[i*NUM_INPUT +: NUM_INPUT] <= '0;
        end else if (clk_en) begin
          // For the first stage, capture the input signals.
          if (i == 0)
            pipe[i*NUM_INPUT +: NUM_INPUT] <= inp;
          // For subsequent stages, propagate data from the previous stage.
          else
            pipe[i*NUM_INPUT +: NUM_INPUT] <= pipe[(i-1)*NUM_INPUT +: NUM_INPUT];
        end
        // If clk_en is low, the pipeline retains its current state.
      end
    end
  endgenerate

  // Output logic: Computed from the final pipeline stage.
  // The output is updated only when clk_en is high.
  // - If all bits in the final stage are high, out becomes 1.
  // - If all bits are low, out becomes 0.
  // - Otherwise, out retains its previous state.
  always_ff @(posedge clk) begin
    if (srst || clr) begin
      out <= 1'b0;
    end else if (clk_en) begin
      // Final pipeline stage is at index PIPE_DEPTH - 1.
      if (&pipe[(PIPE_DEPTH-1)*NUM_INPUT +: NUM_INPUT])
        out <= 1'b1;
      else if (!|pipe[(PIPE_DEPTH-1)*NUM_INPUT +: NUM_INPUT])
        out <= 1'b0;
      else
        out <= out; // Retain previous state when inputs are mixed.
    end
    // When clk_en is low, out remains unchanged.
  end

endmodule

output.rtl/adc_data_rotate.sv:
module adc_data_rotate #(
    parameter DATA_WIDTH = 8 // Parameterized data width
)(
    // Inputs
    input  logic                     i_clk,             // Clock signal
    input  logic                     i_rst_n,           // Active-low reset
    input  logic [DATA_WIDTH-1:0]    i_adc_data_in,     // Input ADC data
    input  logic [3:0]               i_shift_count,     // Number of bits to shift
    input  logic                     i_shift_direction, // Shift direction (0: Left, 1: Right)

    // Outputs
    output logic [DATA_WIDTH-1:0]   o_processed_data,  // Rotated output data
    output logic                    o_operation_status // Operation status
);

    // Synchronous process for rotation operation
    always_ff @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            o_processed_data  <= '0;
            o_operation_status<= 1'b0;
        end else begin
            // Calculate effective shift amount. If i_shift_count exceeds DATA_WIDTH,
            // no rotation is performed (shift_amount becomes 0).
            logic [DATA_WIDTH-1:0] shift_amount;
            if (i_shift_count >= DATA_WIDTH)
                shift_amount = 0;
            else
                shift_amount = i_shift_count;

            // If shift_amount is 0, no rotation is needed; data remains unchanged.
            if (shift_amount == 0) begin
                o_processed_data <= i_adc_data_in;
            end else if (i_shift_direction == 1'b0) begin
                // Left Rotate: Bits shifted out from the left re-enter on the right.
                o_processed_data <= { i_adc_data_in[DATA_WIDTH-shift_amount-1:0], i_adc_data_in[DATA_WIDTH-1:shift_amount] };
            end else begin
                // Right Rotate: Bits shifted out from the right re-enter on the left.
                o_processed_data <= { i_adc_data_in[shift_amount-1:0], i_adc_data_in[DATA_WIDTH-1:shift_amount] };
            end

            // Set operation status to active (1) if a rotation operation is performed.
            o_operation_status <= (shift_amount != 0);
        end
    end

endmodule

input.rtl/key_expansion_128aes.sv:
module key_expansion_128aes #(
    parameter NBW_KEY = 'd128,
    parameter NBW_OUT = 'd1408
) (
    input  logic               clk,
    input  logic               rst_async_n,
    input  logic               i_start,
    input  logic [NBW_KEY-1:0] i_key,
    output logic               o_done,
    output logic [NBW_OUT-1:0] o_expanded_key
);

localparam NBW_BYTE = 'd8;
localparam STEPS = 'd10;
localparam NBW_WORD = 'd32;

// Auxiliary wires
logic [NBW_BYTE-1:0] Rcon   [STEPS];
logic [NBW_KEY-1:0] valid_key;
logic [NBW_KEY-1:0] step_key[STEPS];
logic [NBW_OUT-1:0] expanded_key_nx;
logic [NBW_OUT-1:0] expanded_key_ff;

logic [STEPS:0] steps_ff;

logic [3:0] count_ff;
logic [3:0] count_nx;

always_ff @(posedge clk or negedge rst_async_n) begin : reset_regs
    if(~rst_async_n) begin
        expanded_key_ff <= {NBW_OUT{1'b0}};
        steps_ff <= 11'h400;
    end else begin
        expanded_key_ff <= expanded_key_nx;
        if(i_start || (|steps_ff[9:0])) begin
            steps_ff <= {steps_ff[STEPS-1:0], (i_start & o_done)};
        end
    end
end

assign o_done = steps_ff[STEPS];
assign o_expanded_key = expanded_key_ff;

assign Rcon[0] = 8'h01;
assign Rcon[1] = 8'h02;
assign Rcon[2] = 8'h04;
assign Rcon[3] = 8'h08;
assign Rcon[4] = 8'h10;
assign Rcon[5] = 8'h20;
assign Rcon[6] = 8'h40;
assign Rcon[7] = 8'h80;
assign Rcon[8] = 8'h1b;
assign Rcon[9] = 8'h36;

generate
    for(genvar i = 0; i < STEPS; i++) begin : steps
        logic [NBW_WORD-1:0] RotWord;
        logic [NBW_WORD-1:0] SubWord;
        logic [NBW_WORD-1:0] RconXor;

        sbox uu_sbox0 (
            .i_data(RotWord[31:24]),
            .o_data(SubWord[31:24])
        );

        sbox uu_sbox1 (
            .i_data(RotWord[23:16]),
            .o_data(SubWord[23:16])
        );

        sbox uu_sbox2 (
            .i_data(RotWord[15:8]),
            .o_data(SubWord[15:8])
        );

        sbox uu_sbox3 (
            .i_data(RotWord[7:0]),
            .o_data(SubWord[7:0])
        );

        always_comb begin
            RotWord = {expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-NBW_BYTE-1-:(NBW_WORD-NBW_BYTE)], expanded_key_ff[NBW_OUT-(i+1)*NBW_KEY+NBW_WORD-1-:NBW_BYTE]};
            RconXor = {SubWord[31:24]^Rcon[i], SubWord[23:0]};

            step_key[i][127:96] = expanded_key_ff[NBW_OUT-(4*i  )*NBW_WORD-1-:NBW_WORD] ^ RconXor;
            step_key[i][95 :64] = expanded_key_ff[NBW_OUT-(4*i+1)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][127:96];
            step_key[i][63 :32] = expanded_key_ff[NBW_OUT-(4*i+2)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][95 :64];
            step_key[i][31 :0 ] = expanded_key_ff[NBW_OUT-(4*i+3)*NBW_WORD-1-:NBW_WORD] ^ step_key[i][63 :32];
        end
    end
endgenerate

assign expanded_key_nx = {valid_key  , step_key[0], step_key[1], step_key[2],
                          step_key[3], step_key[4], step_key[5], step_key[6],
                          step_key[7], step_key[8], step_key[9]};

always_comb begin
    if (i_start & o_done) begin
        valid_key = i_key;
    end else begin
        valid_key = expanded_key_ff[NBW_OUT-1-:NBW_KEY];
    end
end

endmodule : key_expansion_128aes

