output.rtl/axi_register.sv:
module axi_register #(
  parameter ADDR_WIDTH = 32,
  parameter DATA_WIDTH = 32
)(
  input  logic                   clk_i,
  input  logic                   rst_n_i,
  // Write Address Channel
  input  logic [ADDR_WIDTH-1:0]  awaddr_i,
  input  logic                   awvalid_i,
  output logic                   awready_o,
  // Write Data Channel
  input  logic [DATA_WIDTH-1:0]  wdata_i,
  input  logic                   wvalid_i,
  output logic                   wready_o,
  input  logic [(DATA_WIDTH/8)-1:0] wstrb_i,
  output logic [1:0]             bresp_o,
  input  logic                   bready_i,
  // Read Address Channel
  input  logic [ADDR_WIDTH-1:0]  araddr_i,
  input  logic                   arvalid_i,
  output logic                   arready_o,
  // Read Data Channel
  output logic [DATA_WIDTH-1:0]  rdata_o,
  output logic                   rvalid_o,
  output logic [1:0]             rresp_o,
  // Register outputs
  output logic [19:0]            beat_o,
  output logic                   start_o,
  output logic                   writeback_o,
  // External done signal for Done register update
  input  logic                   done_i
);

  //-------------------------------------------------------------------------
  // Local Parameters and Constants
  //-------------------------------------------------------------------------
  localparam OKAY   = 2'b00;
  localparam SLVERR = 2'b10;

  // Register Map Addresses
  localparam BEAT_ADDR    = 32'h100;
  localparam START_ADDR   = 32'h200;
  localparam DONE_ADDR    = 32'h300;
  localparam WRITEBACK_ADDR = 32'h400;
  localparam ID_ADDR      = 32'h500;

  //-------------------------------------------------------------------------
  // State Machine Types for Write and Read Transactions
  //-------------------------------------------------------------------------
  typedef enum logic [1:0] {
    W_IDLE,
    W_ADDR,
    W_DATA,
    W_RESP
  } write_state_t;

  typedef enum logic [1:0] {
    R_IDLE,
    R_ADDR,
    R_DATA
  } read_state_t;

  //-------------------------------------------------------------------------
  // Internal Registers for AXI Handshake
  //-------------------------------------------------------------------------
  // Write transaction registers
  reg [ADDR_WIDTH-1:0] awaddr_reg;
  reg [DATA_WIDTH-1:0] wdata_reg;
  reg [(DATA_WIDTH/8)-1:0] wstrb_reg;

  // Internal registers for our hardware registers
  reg [19:0] beat_reg;
  reg        start_reg;
  reg        writeback_reg;
  reg        done_reg;

  //-------------------------------------------------------------------------
  // Output Assignments for Register Outputs
  //-------------------------------------------------------------------------
  assign beat_o       = beat_reg;
  assign start_o      = start_reg;
  assign writeback_o  = writeback_reg;

  //-------------------------------------------------------------------------
  // Write Address Channel FSM
  //-------------------------------------------------------------------------
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      awaddr_reg <= '0;
    end else begin
      case (write_state)
        W_IDLE: begin
          if (awvalid_i)
            awaddr_reg <= awaddr_i;
        end
        default: ;
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Write Data Channel FSM
  //-------------------------------------------------------------------------
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      wdata_reg  <= '0;
      wstrb_reg  <= '0;
    end else begin
      case (write_state)
        W_ADDR: begin
          if (wvalid_i) begin
            wdata_reg  <= wdata_i;
            wstrb_reg  <= wstrb_i;
          end
        end
        default: ;
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Write FSM State Register
  //-------------------------------------------------------------------------
  reg write_state_t write_state;
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i)
      write_state <= W_IDLE;
    else begin
      case (write_state)
        W_IDLE: begin
          if (awvalid_i)
            write_state <= W_ADDR;
        end
        W_ADDR: begin
          if (wvalid_i)
            write_state <= W_DATA;
        end
        W_DATA: begin
          write_state <= W_RESP;
        end
        W_RESP: begin
          if (bready_i)
            write_state <= W_IDLE;
        end
        default: write_state <= W_IDLE;
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Write Ready Signals
  //-------------------------------------------------------------------------
  // awready_o is asserted in W_IDLE state.
  always_comb begin
    awready_o = (write_state == W_IDLE);
  end

  // wready_o is asserted in W_DATA state.
  always_comb begin
    wready_o = (write_state == W_DATA);
  end

  //-------------------------------------------------------------------------
  // Write Response Generation
  //-------------------------------------------------------------------------
  reg bvalid_reg;
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      bvalid_reg  <= 1'b0;
      bresp_o     <= 2'b00;
    end else begin
      if (write_state == W_RESP) begin
        // Validate the address and strobe conditions.
        if ((awaddr_reg == BEAT_ADDR) ||
            (awaddr_reg == START_ADDR) ||
            (awaddr_reg == DONE_ADDR) ||
            (awaddr_reg == WRITEBACK_ADDR) ||
            (awaddr_reg == ID_ADDR))
        begin
          // Writing to the ID register is not allowed.
          if (awaddr_reg == ID_ADDR)
            bresp_o <= SLVERR;
          else
            bresp_o <= OKAY;
        end else begin
          bresp_o <= SLVERR;
        end
        bvalid_reg <= 1'b1;
      end else begin
        bvalid_reg <= 1'b0;
      end
    end
  end
  assign bvalid_o = bvalid_reg;

  //-------------------------------------------------------------------------
  // Register Update Logic on Write Data Acceptance
  //-------------------------------------------------------------------------
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      beat_reg      <= 20'd0;
      start_reg     <= 1'b0;
      writeback_reg <= 1'b0;
      done_reg      <= 1'b0;
    end else begin
      // Only update registers during the W_DATA state.
      if (write_state == W_DATA) begin
        case (awaddr_reg)
          BEAT_ADDR: begin
            // For the 20-bit Beat counter, require a full write:
            // wstrb_reg[3] must be asserted and lower three bytes enabled.
            if (wstrb_reg[3] && (wstrb_reg[2:0] == 3'b111))
              beat_reg <= wdata_reg[19:0];
          end
          START_ADDR: begin
            // Update Start signal if byte enable is valid.
            if (wstrb_reg[0])
              start_reg <= wdata_reg[0];
          end
          DONE_ADDR: begin
            // Clear Done register if LSB is 1.
            if (wstrb_reg[0] && wdata_reg[0])
              done_reg <= 1'b0;
          end
          WRITEBACK_ADDR: begin
            // Update Writeback signal if byte enable is valid.
            if (wstrb_reg[0])
              writeback_reg <= wdata_reg[0];
          end
          ID_ADDR: begin
            // No update for the read-only ID register.
          end
          default: ;
        endcase
      end
      // When not in a write transaction, update the Done register from the external done_i.
      else if (write_state == W_IDLE) begin
        done_reg <= done_i;
      end
    end
  end

  //-------------------------------------------------------------------------
  // Read Address Channel FSM
  //-------------------------------------------------------------------------
  reg read_state_t read_state;
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i)
      read_state <= R_IDLE;
    else begin
      case (read_state)
        R_IDLE: begin
          if (arvalid_i)
            read_state <= R_ADDR;
        end
        R_ADDR: begin
          if (rready_i)
            read_state <= R_IDLE;
        end
        default: read_state <= R_IDLE;
      endcase
    end
  end

  // arready_o is asserted in R_IDLE state.
  always_comb begin
    arready_o = (read_state == R_IDLE);
  end

  //-------------------------------------------------------------------------
  // Read Data Generation
  //-------------------------------------------------------------------------
  reg rvalid_reg;
  always_ff @(posedge clk_i or negedge rst_n_i) begin
    if (!rst_n_i) begin
      rdata_o   <= '0;
      rvalid_reg <= 1'b0;
      rresp_o   <= 2'b00;
    end else begin
      if (read_state == R_ADDR) begin
        case (araddr_i)
          BEAT_ADDR: begin
            // Pad the 20-bit beat counter to DATA_WIDTH.
            rdata_o <= { {(DATA_WIDTH-20){1'b0}}, beat_reg };
            rresp_o <= OKAY;
          end
          START_ADDR: begin
            rdata_o <= { {DATA_WIDTH{start_reg}} };
            rresp_o <= OKAY;
          end
          DONE_ADDR: begin
            rdata_o <= { {DATA_WIDTH{done_reg}} };
            rresp_o <= OKAY;
          end
          WRITEBACK_ADDR: begin
            rdata_o <= { {DATA_WIDTH{writeback_reg}} };
            rresp_o <= OKAY;
          end
          ID_ADDR: begin
            rdata_o <= 32'h00010001;
            rresp_o <= OKAY;
          end
          default: begin
            rdata_o <= '0;
            rresp_o <= SLVERR;
          end
        endcase
        rvalid_reg <= 1'b1;
      end else begin
        rvalid_reg <= 1'b0;
      end
    end
  end
  assign rvalid_o = rvalid_reg;

endmodule

output.rtl/axis_resize.sv:
module axis_resize (
  input  clk,          // Global clock signal: Signals are sampled on the rising edge of clk
  input  resetn,       // The global reset signal: resetn is synchronous active-LOW reset.
  input  s_valid,      // Indicates that the slave is driving a valid transfer.
  output reg s_ready,  // Indicates that the slave can accept a transfer in the current cycle.
  input  [15:0] s_data,  // Primary payload data from slave.
  output reg m_valid,   // Indicates that the master is driving a valid transfer.
  input  m_ready,      // Indicates that the master can accept a transfer in the current cycle.
  output reg [7:0] m_data  // Primary payload data to master.
);

  // State encoding:
  // 0 = IDLE: ready to accept new input.
  // 1 = OUTPUT_SECOND: currently outputting the second (lower) 8 bits.
  reg state;

  // Register to hold the 16-bit input data for splitting.
  reg [15:0] data_reg;

  always @(posedge clk) begin
    if (!resetn) begin
      // Asynchronous reset: clear all registers.
      state     <= 1'b0;
      data_reg  <= 16'd0;
      m_valid   <= 1'b0;
      m_data    <= 8'd0;
      s_ready   <= 1'b0;
    end else begin
      // s_ready is high only in the IDLE state.
      s_ready <= (state == 1'b0) ? 1'b1 : 1'b0;

      case (state)
        1'b0: begin
          // IDLE state: ready to accept new data.
          if (s_valid) begin
            // Capture the 16-bit input data.
            data_reg <= s_data;
            // Output the upper 8 bits.
            m_valid  <= 1'b1;
            m_data   <= data_reg[15:8];
            // Move to the state to output the lower 8 bits.
            state    <= 1'b1;
          end else begin
            m_valid <= 1'b0;
          end
        end

        1'b1: begin
          // Currently outputting the lower 8 bits.
          if (m_ready) begin
            // When the master is ready, send the lower 8 bits.
            m_data  <= data_reg[7:0];
            // Transaction complete; return to IDLE.
            state   <= 1'b0;
            m_valid <= 1'b0;
          end
          // If m_ready is not asserted, hold the current state and keep m_valid asserted.
        end

        default: begin
          // Should never reach here.
          state   <= 1'b0;
          m_valid <= 1'b0;
        end
      endcase
    end
  end

endmodule

output.rtl/axis_upscale.sv:
module axis_upscale (
    input  logic         clk,
    input  logic         resetn,
    input  logic         dfmt_enable,
    input  logic         dfmt_type,
    input  logic         dfmt_se,
    input  logic         s_axis_valid,
    input  logic [23:0]  s_axis_data,
    input  logic         m_axis_ready,
    output logic         s_axis_ready,
    output logic         m_axis_valid,
    output logic [31:0]  m_axis_data
);

  // Internal register to hold the captured upsized data and a valid flag.
  logic valid_reg;
  logic [31:0] data_reg;

  // One pipeline register stage: capture input when not busy,
  // and output registered data when the master is ready.
  always_ff @(posedge clk or negedge resetn) begin
    if (!resetn) begin
      valid_reg <= 1'b0;
      data_reg  <= 32'b0;
    end
    else begin
      // Capture new data if not busy and both sides are ready.
      if (!valid_reg && s_axis_valid && m_axis_ready) begin
        valid_reg <= 1'b1;
        // Compute the upsized 32-bit data.
        // If dfmt_enable is disabled, simply prepend 8'b0.
        // If dfmt_enable is enabled:
        //   - if dfmt_se is 1, then perform sign extension using the MSB of s_axis_data.
        //     The extension bit is taken as s_axis_data[23] normally, or its inverted value if dfmt_type is 1.
        //   - if dfmt_se is 0, then the upper 8 bits are zeros.
        data_reg <= (!dfmt_enable) ?
                      {8'b0, s_axis_data} :
                      (dfmt_enable) ?
                        (dfmt_se ?
                           (dfmt_type ?
                              {8{~s_axis_data[23]}, s_axis_data} :
                              {8{s_axis_data[23]}, s_axis_data}
                           ) :
                           {8'b0, s_axis_data}
                        ) :
                      {8'b0, s_axis_data};
      end
      // When the master is ready, clear the valid flag.
      if (valid_reg && m_axis_ready)
        valid_reg <= 1'b0;
    end
  end

  // Handshake signals: when not busy, assert s_axis_ready.
  assign s_axis_ready = !valid_reg;
  assign m_axis_valid = valid_reg;
  assign m_axis_data  = data_reg;

endmodule

output.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read Logic
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

// Determine destination port for read transaction based on address
always @*
begin
    // If the address has the high bit set (i.e. masked with PERIPH0_MASK equals PERIPH0_MASK),
    // then route to Peripheral0 (bit = 1), otherwise to Default (bit = 0).
    read_port_r = ((inport_araddr_i & PERIPH0_MASK) == PERIPH0_MASK) ? 1'b1 : 1'b0;
end

// Update pending read transactions count
always @*
begin
    if (inport_arvalid_i && inport_arready_o)
        read_pending_r = read_pending_q - 1;
    else if (inport_arvalid_i)
        read_pending_r = read_pending_q + 1;
    else
        read_pending_r = read_pending_q;
end

always @ (posedge clk_i )
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;

    // On successful handshake, update the port tracking register.
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

// AXI Read Data channel logic: forward read data and response from the selected interface.
always @ (posedge clk_i)
begin
    if (rst_i)
    begin
        inport_rvalid_o <= 1'b0;
        inport_rdata_o  <= {DATA_WIDTH{1'b0}};
        inport_rresp_o  <= 2'b0;
    end
    else
    begin
        if (read_port_r == `ADDR_SEL_W'd0)
        begin
            inport_rvalid_o <= outport_rvalid_i;
            inport_rdata_o  <= outport_rdata_i;
            inport_rresp_o  <= outport_rresp_i;
        end
        else
        begin
            inport_rvalid_o <= outport_peripheral0_rvalid_i;
            inport_rdata_o  <= outport_peripheral0_rdata_i;
            inport_rresp_o  <= outport_peripheral0_rresp_i;
        end
    end
end

//-------------------------------------------------------------
// Write Request Logic
//-------------------------------------------------------------
reg awvalid_q;
reg wvalid_q;

wire wr_cmd_accepted_w  = (inport_awvalid_i && inport_awready_o) || awvalid_q;
wire wr_data_accepted_w = (inport_wvalid_i  && inport_wready_o)  || wvalid_q;

always @ (posedge clk_i )
if (rst_i)
    awvalid_q <= 1'b0;
else if (inport_awvalid_i && inport_awready_o && (!wr_data_accepted_w))
    awvalid_q <= 1'b1;
else if (wr_data_accepted_w)
    awvalid_q <= 1'b0;

always @ (posedge clk_i )
if (rst_i)
    wvalid_q <= 1'b0;
else if (inport_wvalid_i && inport_wready_i && !wr_cmd_accepted_w)
    wvalid_q <= 1'b1;
else if (wr_cmd_accepted_w)
    wvalid_q <= 1'b0;

//-----------------------------------------------------------------
// AXI: Write Logic
//-----------------------------------------------------------------
// Declare registers to track write pending transactions and port selection.
reg [3:0]              write_pending_q;
reg [3:0]              write_pending_r;
reg [`ADDR_SEL_W-1:0]  write_port_q;
reg [`ADDR_SEL_W-1:0]  write_port_r;

// Determine destination port for write transaction based on address.
always @*
begin
    write_port_r = ((inport_awaddr_i & PERIPH0_MASK) == PERIPH0_MASK) ? 1'b1 : 1'b0;
end

// Update pending write transactions count.
always @*
begin
    if (inport_awvalid_i && inport_awready_o)
        write_pending_r = write_pending_q - 1;
    else if (inport_awvalid_i)
        write_pending_r = write_pending_q + 1;
    else
        write_pending_r = write_pending_q;
end

always @ (posedge clk_i )
if (rst_i)
begin
    write_pending_q <= 4'b0;
    write_port_q    <= `ADDR_SEL_W'b0;
end
else
begin
    write_pending_q <= write_pending_r;
    if (inport_awvalid_i && inport_awready_o)
    begin
         write_port_q <= write_port_r;
    end
end

wire write_accept_w      = (write_port_q == write_port_r && write_pending_q != 4'hF) || (write_pending_q == 4'h0);

assign outport_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd0);
assign outport_awaddr_o  = inport_awaddr_i;
assign outport_wvalid_o  = inport_wvalid_i & ~wvalid_q & (inport_awvalid_i || awvalid_q) & (write_port_r == `ADDR_SEL_W'd0);
assign outport_wdata_o   = inport_wdata_i;
assign outport_wstrb_o   = inport_wstrb_i;
assign outport_bready_o  = inport_bready_i;

assign outport_peripheral0_awvalid_o = inport_awvalid_i & ~awvalid_q & write_accept_w & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_awaddr_o  = inport_awaddr_i;
assign outport_peripheral0_wvalid_o  = inport_wvalid_i & ~wvalid_q & ((inport_awvalid_i && write_accept_w) || awvalid_q) & (write_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_wdata_o   = inport_wdata_i;
assign outport_peripheral0_wstrb_o   = inport_wstrb_i;
assign outport_peripheral0_bready_o  = inport_bready_i;

reg        outport_bvalid_r;
reg [1:0]  outport_bresp_r;

always @ *
begin
    case (write_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_bvalid_r = outport_peripheral0_bvalid_i;
        outport_bresp_r  = outport_peripheral0_bresp_i;
    end
    default:
    begin
        outport_bvalid_r = outport_bvalid_i;
        outport_bresp_r  = outport_bresp_i;
    end
    endcase
end

assign inport_bvalid_o  = outport_bvalid_r;
assign inport_bresp_o   = outport_bresp_r;

reg inport_awready_r;
reg inport_wready_r;

always @ *
begin
    case (write_port_r)
    `ADDR_SEL_W'd1:
    begin
        inport_awready_r = outport_peripheral0_awready_i;
        inport_wready_r  = outport_peripheral0_wready_i;
    end
    default:
    begin
        inport_awready_r = outport_awready_i;
        inport_wready_r  = outport_wready_i;        
    end        
    endcase
end

assign inport_awready_o = write_accept_w & ~awvalid_q & inport_awready_r;
assign inport_wready_o  = write_accept_w & ~wvalid_q & inport_wready_r;

endmodule

input.rtl/axi_tap.sv:
module axi_tap #(
    parameter ADDR_WIDTH = 32, // Width of AXI4-Lite Address
    parameter DATA_WIDTH = 32  // Width of AXI4-Lite Data
)(
    // Global Ports
    input           clk_i,
    input           rst_i,

    // Master Write Address Channel (AW)
    input           inport_awvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_awaddr_i,
    output          inport_awready_o,
    // Master Write Data Channel (W)
    input           inport_wvalid_i,
    input  [DATA_WIDTH-1:0]   inport_wdata_i,
    input  [3:0]    inport_wstrb_i,
    output          inport_wready_o,
    // Master Write Response Channel (B)
    input           inport_bready_i,
    output          inport_bvalid_o,
    output [1:0]    inport_bresp_o,
    // Master Read Address Channel (AR)
    input           inport_arvalid_i,
    input  [ADDR_WIDTH-1:0]   inport_araddr_i,
    output          inport_arready_o,
    // Master Read Data Channel (R)
    input           inport_rready_i,
    output          inport_rvalid_o,
    output [DATA_WIDTH-1:0]   inport_rdata_o,
    output [1:0]    inport_rresp_o,

    // Default AXI outport
    // Write Address Channel (AW)
    input           outport_awready_i,
    output          outport_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_awaddr_o,
    // Write Data Channel (W)
    input           outport_wready_i,
    output          outport_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_wdata_o,
    output [3:0]    outport_wstrb_o,
    // Write Response Channel (B)
    input           outport_bvalid_i,
    input  [1:0]    outport_bresp_i,
    output          outport_bready_o,
    // Read Address Channel (AR)
    input           outport_arready_i,
    output          outport_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_araddr_o,
    // Read Data Channel (R)
    input           outport_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_rdata_i,
    input  [1:0]    outport_rresp_i,
    output          outport_rready_o,

    // Peripheral 0 interface
    // Write Address Channel (AW)
    input           outport_peripheral0_awready_i,
    output          outport_peripheral0_awvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_awaddr_o,
    // Write Data Channel (W)
    input           outport_peripheral0_wready_i,
    output          outport_peripheral0_wvalid_o,
    output [DATA_WIDTH-1:0]   outport_peripheral0_wdata_o,
    output [3:0]    outport_peripheral0_wstrb_o,
    // Write Response Channel (B)
    input  [1:0]    outport_peripheral0_bresp_i,
    input           outport_peripheral0_bvalid_i,
    output          outport_peripheral0_bready_o,
    // Read Address Channel (AR)
    input           outport_peripheral0_arready_i,
    output          outport_peripheral0_arvalid_o,
    output [ADDR_WIDTH-1:0]   outport_peripheral0_araddr_o,
    // Read Data Channel (R)
    input  [1:0]    outport_peripheral0_rresp_i,
    input           outport_peripheral0_rvalid_i,
    input  [DATA_WIDTH-1:0]   outport_peripheral0_rdata_i,
    output          outport_peripheral0_rready_o
);

`define ADDR_SEL_W           1
`define PERIPH0_ADDR         32'h80000000
`define PERIPH0_MASK         32'h80000000

//-----------------------------------------------------------------
// AXI: Read
//-----------------------------------------------------------------
reg [3:0]              read_pending_q;
reg [3:0]              read_pending_r;
reg [`ADDR_SEL_W-1:0]  read_port_q;
reg [`ADDR_SEL_W-1:0]  read_port_r;

always @ *
begin
    read_port_r = `ADDR_SEL_W'b0;
    if ((inport_araddr_i & `PERIPH0_MASK) == `PERIPH0_ADDR) read_port_r = `ADDR_SEL_W'd1;
end

wire read_incr_w = (inport_arvalid_i && inport_arready_o);
wire read_decr_w = (inport_rvalid_o && inport_rready_i);

always @ *
begin
    read_pending_r = read_pending_q;

    if (read_incr_w && !read_decr_w)
        read_pending_r = read_pending_r + 4'd1;
    else if (!read_incr_w && read_decr_w)
        read_pending_r = read_pending_r - 4'd1;
end

always @ (posedge clk_i )
if (rst_i)
begin
    read_pending_q <= 4'b0;
    read_port_q    <= `ADDR_SEL_W'b0;
end
else 
begin
    read_pending_q <= read_pending_r;

    // Read command accepted
    if (inport_arvalid_i && inport_arready_o)
    begin
        read_port_q <= read_port_r;
    end
end

wire read_accept_w       = (read_port_q == read_port_r && read_pending_q != 4'hF) || (read_pending_q == 4'h0);

assign outport_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd0);
assign outport_araddr_o  = inport_araddr_i;
assign outport_rready_o  = inport_rready_i;

assign outport_peripheral0_arvalid_o = inport_arvalid_i & read_accept_w & (read_port_r == `ADDR_SEL_W'd1);
assign outport_peripheral0_araddr_o  = inport_araddr_i;
assign outport_peripheral0_rready_o  = inport_rready_i;

reg        outport_rvalid_r;
reg [DATA_WIDTH-1:0] outport_rdata_r;
reg [1:0]  outport_rresp_r;

always @ *
begin
    case (read_port_q)
    `ADDR_SEL_W'd1:
    begin
        outport_rvalid_r = outport_peripheral0_rvalid_i;
        outport_rdata_r  = outport_peripheral0_rdata_i;
        outport_rresp_r  = outport_peripheral0_rresp_i;
    end
    default:
    begin
        outport_rvalid_r = outport_rvalid_i;
        outport_rdata_r  = outport_rdata_i;
        outport_rresp_r  = outport_rresp_i;
    end
    endcase
end

assign inport_rvalid_o  = outport_rvalid_r;
assign inport_rdata_o   = outport_rdata_r;
assign inport_rresp_o   = outport_rresp_r;

reg inport_arready_r;
