// File: rtl/precision_counter_axi.sv
// Description: A configurable AXI4‐Lite Slave module implementing a high‐precision
// countdown counter with start/stop control, interrupt generation based on a configurable
// threshold, and elapsed time tracking after countdown completion.
//
// The module implements the AXI4‐Lite protocol with proper handshaking, flow control,
// and error responses for unsupported addresses.
//
// Register Map:
//   Offset  Register              Description
//   0x00    slv_reg_ctl           Control register (bit0: start/stop countdown; write resets elapsed time)
//   0x10    slv_reg_t             Elapsed time counter
//   0x20    slv_reg_v             Countdown value (decrements by 1 per clock when running)
//   0x24    slv_reg_irq_mask      Interrupt mask register (bit0 enables interrupts)
//   0x28    slv_reg_irq_thresh    Interrupt threshold register (interrupt asserted when slv_reg_v == this value)
//
// Additional outputs:
//   axi_ap_done - Asserted when countdown reaches 0.
//   irq         - Asserted when (slv_reg_v == slv_reg_irq_thresh) and irq mask is enabled.
//
// Default values on reset: All registers are 0 and the countdown is stopped.

module precision_counter_axi #(
  parameter C_S_AXI_DATA_WIDTH = 32,
  parameter C_S_AXI_ADDR_WIDTH = 8
)(
  input  wire                   axi_aclk,
  input  wire                   axi_aresetn,
  // Write Address Channel
  input  wire [C_S_AXI_ADDR_WIDTH-1:0] axi_awaddr,
  input  wire                   axi_awvalid,
  output reg                    axi_awready,
  // Write Data Channel
  input  wire [C_S_AXI_DATA_WIDTH-1:0] axi_wdata,
  input  wire [(C_S_AXI_DATA_WIDTH/8)-1:0] axi_wstrb,
  input  wire                   axi_wvalid,
  output reg                    axi_wready,
  // Write Response Channel
  output reg [1:0]              axi_bresp,
  output reg                    axi_bvalid,
  input  wire                   axi_bready,
  // Read Address Channel
  input  wire [C_S_AXI_ADDR_WIDTH-1:0] axi_araddr,
  input  wire                   axi_arvalid,
  output reg                    axi_arready,
  // Read Data Channel
  output reg [C_S_AXI_DATA_WIDTH-1:0] axi_rdata,
  output reg [1:0]              axi_rresp,
  output reg                    axi_rvalid,
  input  wire                   axi_rready,
  // Control Outputs
  output wire                   axi_ap_done,
  output wire                   irq
);

  //----------------------------------------------------------------

output.rtl/axis_image_border_gen.sv:
module axis_image_border_gen #(
    parameter IMG_WIDTH  = 336,               // Image width (X resolution)
    parameter IMG_HEIGHT = 256,              // Image height (Y resolution)
    parameter BORDER_COLOR = 16'hFFFF,       // Border pixel value
    parameter DATA_MASK    = 16'h0000        // Mask for input pixels
)(
    input  wire            clk,              // AXI clock
    input  wire            resetn,           // Active-low reset

    // AXI Stream input interface
    input  wire [15:0]     s_axis_tdata,     // Input stream data
    input  wire            s_axis_tvalid,    // Input data valid
    output wire            s_axis_tready,    // Ready to accept input
    input  wire            s_axis_tlast,     // Input last signal
    input  wire            s_axis_tuser,     // Frame start signal

    // AXI Stream output interface
    output wire [15:0]     m_axis_tdata,     // Output stream data
    output wire            m_axis_tvalid,    // Output data valid
    input  wire            m_axis_tready,    // Ready to accept output
    output wire            m_axis_tlast,     // Output last signal
    output wire            m_axis_tuser      // Frame start signal
);

   // State Definitions
   localparam [2:0] ST_IDLE       = 3'd0,
                     ST_ROW_FIRST  = 3'd1,
                     ST_PROCESS_ROW = 3'd2,
                     ST_BORDER_ROW  = 3'd3,
                     ST_ROW_LAST    = 3'd4;

   // State and Counter Registers
   reg [2:0] state;
   reg [15:0] x_count, y_count;
   reg border_valid;  // Not explicitly used but available if needed

   // Internal control signals for border detection (for completeness)
   wire is_top_row     = (y_count == 16'd0);
   wire is_bottom_row  = (y_count == IMG_HEIGHT + 1);
   wire is_left_border = (x_count == 16'd0);
   wire is_right_border= (x_count == IMG_WIDTH + 1);
   wire is_border_pixel = (is_top_row || is_bottom_row || is_left_border || is_right_border);

   // FSM Sequential Process
   always @(posedge clk or negedge resetn) begin
      if (!resetn) begin
         state      <= ST_IDLE;
         x_count    <= 16'd0;
         y_count    <= 16'd0;
      end else begin
         case (state)
            ST_IDLE: begin
               // Wait for a new frame start. When detected, reset counters and move to first row.
               if (s_axis_tvalid && s_axis_tuser) begin
                  state      <= ST_ROW_FIRST;
                  x_count    <= 16'd0;
                  y_count    <= 16'd0;
               end else begin
                  state      <= ST_IDLE;
                  x_count    <= 16'd0;  // Remain at 0 while idle
                  y_count    <= 16'd0;
               end
            end

            ST_ROW_FIRST: begin
               // Process the first (top) row: all pixels are border.
               x_count <= x_count + 1;
               if (s_axis_tlast) begin
                  y_count <= y_count + 1;
                  state   <= ST_PROCESS_ROW;
               end
            end

            ST_PROCESS_ROW: begin
               // Process middle rows.
               // For each row, output BORDER_COLOR at left (x==0) and right (x==IMG_WIDTH+1) edges.
               // For inner pixels, output (s_axis_tdata & DATA_MASK).
               x_count <= x_count + 1;
               if (s_axis_tlast) begin
                  y_count <= y_count + 1;
                  if (y_count == IMG_HEIGHT)
                     state <= ST_BORDER_ROW;
                  else
                     state <= ST_PROCESS_ROW;
               end
            end

            ST_BORDER_ROW: begin
               // Process the bottom row: all pixels are border.
               x_count <= x_count + 1;
               if (s_axis_tlast) begin
                  y_count <= y_count + 1;
                  state   <= ST_ROW_LAST;
               end
            end

            ST_ROW_LAST: begin
               // Final state: complete the frame and return to idle.
               state <= ST_IDLE;
            end

            default: begin
               state <= ST_IDLE;
            end
         endcase
      end
   end

   // AXI Stream Output Signal Assignments

   // Always ready to accept input
   assign s_axis_tready = 1'b1;

   // m_axis_tuser: Asserted at the start of a new frame (first word in frame)
   assign m_axis_tuser = (state == ST_ROW_FIRST && x_count == 16'd0) ? 1'b1 : 1'b0;

   // m_axis_tvalid: Asserted when valid pixel data is available.
   // Only states that output pixel data (ST_ROW_FIRST, ST_PROCESS_ROW, ST_BORDER_ROW) drive valid.
   assign m_axis_tvalid = ((state == ST_ROW_FIRST) ||
                           (state == ST_PROCESS_ROW) ||
                           (state == ST_BORDER_ROW)) ? 1'b1 : 1'b0;

   // m_axis_tdata: Generate output pixel data with border applied.
   // - In ST_ROW_FIRST and ST_BORDER_ROW, all pixels are border.
   // - In ST_PROCESS_ROW, left and right borders are BORDER_COLOR; inner pixels use (s_axis_tdata & DATA_MASK).
   assign m_axis_tdata = 
         (state == ST_ROW_FIRST) ? BORDER_COLOR :
         (state == ST_BORDER_ROW) ? BORDER_COLOR :
         (state == ST_PROCESS_ROW) ? ((x_count == 16'd0 || x_count == IMG_WIDTH+1) ? BORDER_COLOR : (s_axis_tdata & DATA_MASK)) : 16'h0000;

   // m_axis_tlast: Asserted on the last pixel of the frame (bottom row).
   assign m_axis_tlast = (state == ST_BORDER_ROW && x_count == IMG_WIDTH+1 && s_axis_tlast) ? 1'b1 : 1'b0;

endmodule

output.rtl/axis_joiner.sv:
module axis_joiner (
  input  logic         clk,
  input  logic         rst,
  // AXI Stream Input 1
  input  logic [7:0]   s_axis_tdata_1,
  input  logic         s_axis_tvalid_1,
  output logic         s_axis_tready_1,
  input  logic         s_axis_tlast_1,
  // AXI Stream Input 2
  input  logic [7:0]   s_axis_tdata_2,
  input  logic         s_axis_tvalid_2,
  output logic         s_axis_tready_2,
  input  logic         s_axis_tlast_2,
  // AXI Stream Input 3
  input  logic [7:0]   s_axis_tdata_3,
  input  logic         s_axis_tvalid_3,
  output logic         s_axis_tready_3,
  input  logic         s_axis_tlast_3,
  // Merged AXI Stream Output
  output logic [7:0]   m_axis_tdata,
  output logic         m_axis_tvalid,
  input  logic         m_axis_tready,
  output logic         m_axis_tlast,
  output logic [1:0]   m_axis_tuser,
  output logic         busy
);

  // FSM state encoding
  localparam integer STATE_IDLE = 0,
                    STATE_1    = 1,
                    STATE_2    = 2,
                    STATE_3    = 3;

  // Internal registers for FSM state and buffering
  reg [1:0] state;
  reg       temp_flag;          // Indicates that data is buffered
  reg [7:0] buffered_data;
  reg       buffered_last;
  reg [1:0] buffered_tuser;

  // Drive input ready signals based on active state
  assign s_axis_tready_1 = (state == STATE_1);
  assign s_axis_tready_2 = (state == STATE_2);
  assign s_axis_tready_3 = (state == STATE_3);

  // Drive merged AXI Stream output signals
  // When temp_flag is asserted, output the buffered data; otherwise, use the active input stream.
  assign m_axis_tvalid  = ((state != STATE_IDLE) || temp_flag);
  assign m_axis_tdata   = (temp_flag) ? buffered_data :
                            ( (state == STATE_1) ? s_axis_tdata_1 :
                              ( (state == STATE_2) ? s_axis_tdata_2 : s_axis_tdata_3) );
  assign m_axis_tlast   = (temp_flag) ? buffered_last :
                            ( (state == STATE_1) ? s_axis_tlast_1 :
                              ( (state == STATE_2) ? s_axis_tlast_2 : s_axis_tlast_3) );
  assign m_axis_tuser   = (temp_flag) ? buffered_tuser :
                            ( (state == STATE_1) ? 2'b01 :
                              ( (state == STATE_2) ? 2'b10 : 2'b11) );

  // busy indicates that the module is processing data (either actively transferring or buffering)
  assign busy = ((state != STATE_IDLE) || temp_flag);

  // FSM and buffering control logic
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state           <= STATE_IDLE;
      temp_flag       <= 1'b0;
      buffered_data   <= 8'd0;
      buffered_last   <= 1'b0;
      buffered_tuser  <= 2'd0;
    end
    else begin
      if (m_axis_tready) begin
        // If there is buffered data, output it and clear the buffer.
        if (temp_flag) begin
          temp_flag <= 1'b0;
        end

        // Update state machine based on current state and input valid signals.
        case (state)
          STATE_IDLE: begin
            if (s_axis_tvalid_1)
              state <= STATE_1;
            else if (s_axis_tvalid_2)
              state <= STATE_2;
            else if (s_axis_tvalid_3)
              state <= STATE_3;
            else
              state <= STATE_IDLE;
          end
          STATE_1: begin
            // Once the packet is complete (tlast asserted), return to idle.
            if (s_axis_tvalid_1 && s_axis_tlast_1)
              state <= STATE_IDLE;
            // Else remain in STATE_1 to continue transferring the packet.
          end
          STATE_2: begin
            if (s_axis_tvalid_2 && s_axis_tlast_2)
              state <= STATE_IDLE;
          end
          STATE_3: begin
            if (s_axis_tvalid_3 && s_axis_tlast_3)
              state <= STATE_IDLE;
          end
          default: begin
            state <= STATE_IDLE;
          end
        endcase
      end
      else begin
        // m_axis_tready is deasserted: buffer the current data from the active input stream.
        case (state)
          STATE_1: begin
            buffered_data <= s_axis_tdata_1;
            buffered_last <= s_axis_tlast_1;
            buffered_tuser <= 2'b01;  // TAG_ID for stream 1
            temp_flag     <= 1'b1;
          end
          STATE_2: begin
            buffered_data <= s_axis_tdata_2;
            buffered_last <= s_axis_tlast_2;
            buffered_tuser <= 2'b10;  // TAG_ID for stream 2
            temp_flag     <= 1'b1;
          end
          STATE_3: begin
            buffered_data <= s_axis_tdata_3;
            buffered_last <= s_axis_tlast_3;
            buffered_tuser <= 2'b11;  // TAG_ID for stream 3
            temp_flag     <= 1'b1;
          end
          default: begin
            // No buffering action when in idle.
          end
        endcase
      end
    end
  end

endmodule

output.rtl/axis_mux.sv:
module axis_mux #(
  parameter integer C_AXIS_DATA_WIDTH  = 32,
  parameter integer C_AXIS_TUSER_WIDTH = 4,
  parameter integer C_AXIS_TID_WIDTH   = 2,
  parameter integer C_AXIS_TDEST_WIDTH = 2,
  parameter integer NUM_INPUTS         = 4
)(
  input  wire                                   aclk,
  input  wire                                   aresetn,
  input  wire [$clog2(NUM_INPUTS)-1:0]          sel,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tvalid,
  output wire [NUM_INPUTS-1:0]                  s_axis_tready,
  input  wire [NUM_INPUTS*C_AXIS_DATA_WIDTH-1:0]   s_axis_tdata,
  input  wire [NUM_INPUTS*(C_AXIS_DATA_WIDTH/8)-1:0] s_axis_tkeep,
  input  wire [NUM_INPUTS-1:0]                  s_axis_tlast,
  input  wire [NUM_INPUTS*C_AXIS_TID_WIDTH-1:0] s_axis_tid,
  input  wire [NUM_INPUTS*C_AXIS_TDEST_WIDTH-1:0] s_axis_tdest,
  input  wire [NUM_INPUTS*C_AXIS_TUSER_WIDTH-1:0] s_axis_tuser,
  output wire                                   m_axis_tvalid,
  input  wire                                   m_axis_tready,
  output wire [C_AXIS_DATA_WIDTH-1:0]           m_axis_tdata,
  output wire [C_AXIS_DATA_WIDTH/8-1:0]         m_axis_tkeep,
  output wire                                   m_axis_tlast,
  output wire [C_AXIS_TID_WIDTH-1:0]            m_axis_tid,
  output wire [C_AXIS_TDEST_WIDTH-1:0]          m_axis_tdest,
  output wire [C_AXIS_TUSER_WIDTH-1:0]          m_axis_tuser
);

  //-------------------------------------------------------------------------
  // Internal signal declarations
  //-------------------------------------------------------------------------

  // Registered version of the selection signal
  reg [$clog2(NUM_INPUTS)-1:0] sel_reg;

  // Wires for the selected input stream signals
  wire [C_AXIS_DATA_WIDTH-1:0] sel_tdata;
  wire [C_AXIS_DATA_WIDTH/8-1:0] sel_tkeep;
  wire sel_tvalid;
  wire sel_tlast;
  wire [C_AXIS_TID_WIDTH-1:0] sel_tid;
  wire [C_AXIS_TDEST_WIDTH-1:0] sel_tdest;
  wire [C_AXIS_TUSER_WIDTH-1:0] sel_tuser;

  // Registered output stage signals
  reg  m_axis_tvalid_reg;
  reg  [C_AXIS_DATA_WIDTH-1:0] m_axis_tdata_reg;
  reg  [C_AXIS_DATA_WIDTH/8-1:0] m_axis_tkeep_reg;
  reg  m_axis_tlast_reg;
  reg  [C_AXIS_TID_WIDTH-1:0] m_axis_tid_reg;
  reg  [C_AXIS_TDEST_WIDTH-1:0] m_axis_tdest_reg;
  reg  [C_AXIS_TUSER_WIDTH-1:0] m_axis_tuser_reg;

  //-------------------------------------------------------------------------
  // Generate selected input signals from the concatenated buses
  //-------------------------------------------------------------------------
  assign sel_tdata  = s_axis_tdata [sel_reg*C_AXIS_DATA_WIDTH +: C_AXIS_DATA_WIDTH];
  assign sel_tkeep  = s_axis_tkeep [sel_reg*(C_AXIS_DATA_WIDTH/8) +: (C_AXIS_DATA_WIDTH/8)];
  assign sel_tvalid = s_axis_tvalid[sel_reg];
  assign sel_tlast  = s_axis_tlast [sel_reg];
  assign sel_tid    = s_axis_tid   [sel_reg*C_AXIS_TID_WIDTH +: C_AXIS_TID_WIDTH];
  assign sel_tdest  = s_axis_tdest [sel_reg*C_AXIS_TDEST_WIDTH +: C_AXIS_TDEST_WIDTH];
  assign sel_tuser  = s_axis_tuser [sel_reg*C_AXIS_TUSER_WIDTH +: C_AXIS_TUSER_WIDTH];

  //-------------------------------------------------------------------------
  // Register the selection signal
  //-------------------------------------------------------------------------
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn)
      sel_reg <= 0;
    else
      sel_reg <= sel;
  end

  //-------------------------------------------------------------------------
  // Registered output stage: capture selected input and handle backpressure
  //-------------------------------------------------------------------------
  always @(posedge aclk or negedge aresetn) begin
    if (!aresetn) begin
      m_axis_tvalid_reg  <= 1'b0;
      m_axis_tdata_reg   <= {C_AXIS_DATA_WIDTH{1'b0}};
      m_axis_tkeep_reg   <= {C_AXIS_DATA_WIDTH/8{1'b0}};
      m_axis_tlast_reg   <= 1'b0;
      m_axis_tid_reg     <= {C_AXIS_TID_WIDTH{1'b0}};
      m_axis_tdest_reg   <= {C_AXIS_TDEST_WIDTH{1'b0}};
      m_axis_tuser_reg   <= {C_AXIS_TUSER_WIDTH{1'b0}};
    end
    else begin
      if (m_axis_tready) begin
        // When the output is ready, capture new data from the selected input.
        m_axis_tvalid_reg  <= sel_tvalid;
        m_axis_tdata_reg   <= sel_tdata;
        m_axis_tkeep_reg   <= sel_tkeep;
        m_axis_tlast_reg   <= sel_tlast;
        m_axis_tid_reg     <= sel_tid;
        m_axis_tdest_reg   <= sel_tdest;
        m_axis_tuser_reg   <= sel_tuser;
      end
      else begin
        // Hold the captured data; if the selected input de-asserts valid, clear our valid.
        if (!sel_tvalid)
          m_axis_tvalid_reg <= 1'b0;
        else
          m_axis_tvalid_reg <= m_axis_tvalid_reg;

        // Hold other signals
        m_axis_tdata_reg   <= m_axis_tdata_reg;
        m_axis_tkeep_reg   <= m_axis_tkeep_reg;
        m_axis_tlast_reg   <= m_axis_tlast_reg;
        m_axis_tid_reg     <= m_axis_tid_reg;
        m_axis_tdest_reg   <= m_axis_tdest_reg;
        m_axis_tuser_reg   <= m_axis_tuser_reg;
      end
    end
  end

  //-------------------------------------------------------------------------
  // Drive the output interface signals
  //-------------------------------------------------------------------------
  assign m_axis_tvalid = m_axis_tvalid_reg;
  assign m_axis_tdata  = m_axis_tdata_reg;
  assign m_axis_tkeep  = m_axis_tkeep_reg;
  assign m_axis_tlast  = m_axis_tlast_reg;
  assign m_axis_tid    = m_axis_tid_reg;
  assign m_axis_tdest  = m_axis_tdest_reg;
  assign m_axis_tuser  = m_axis_tuser_reg;

  //-------------------------------------------------------------------------
  // Generate ready signals for each input stream.
  // Only the selected input is driven by m_axis_tready; all others get a high ready.
  //-------------------------------------------------------------------------
  genvar i;
  generate
    for (i = 0; i < NUM_INPUTS; i = i + 1) begin : gen_s_axis_tready
      assign s_axis_tready[i] = (sel_reg == i) ? m_axis_tready : 1'b1;
    end
  endgenerate

endmodule

output.rtl/barrel_shifter_8bit.sv:
module barrel_shifter_8bit (
    input  logic [7:0]  data_in,    // 8-bit input data
    input  logic [2:0]  shift_bits, // Number of bits to shift (0 to 7)
    input  logic        left_right, // Shift direction: 1 = left, 0 = right
    output logic [7:0]  data_out    // 8-bit output data
);

  // Combinational logic implementation of the barrel shifter.
  // For left shifts, zeros are inserted into the LSB positions.
  // For right shifts, zeros are inserted into the MSB positions.
  //
  // The barrel shifter uses a case statement to select the appropriate shift amount.
  //
  // Example:
  //   If data_in = 8'b11001100, shift_bits = 3'b100 (4), and left_right = 1,
  //   then data_out = 8'b11000000.
  //
  //   If data_in = 8'b11001100, shift_bits = 3'b100 (4), and left_right = 0,
  //   then data_out = 8'b00001100.

  always_comb begin
    unique case (shift_bits)
      3'b000: data_out = data_in;
      3'b001: data_out = left_right ? (data_in << 1) : (data_in >> 1);
      3'b010: data_out = left_right ? (data_in << 2) : (data_in >> 2);
      3'b011: data_out = left_right ? (data_in << 3) : (data_in >> 3);
      3'b100: data_out = left_right ? (data_in << 4) : (data_in >> 4);
      3'b101: data_out = left_right ? (data_in << 5) : (data_in >> 5);
      3'b110: data_out = left_right ? (data_in << 6) : (data_in >> 6);
      3'b111: data_out = left_right ? (data_in << 7) : (data_in >> 7);
      default: data_out = data_in;
    endcase
  end

endmodule

input.rtl/barrel_shifter_8bit.sv:
module barrel_shifter_8bit(input [7:0]data_in,input [2:0] shift_bits, input left_right, output [7:0]data_out);
assign data_out = left_right ? (data_in << shift_bits) : (data_in >> shift_bits);
endmodule

output.rtl/barrel_shifter.sv:
module barrel_shifter #(parameter data_width = 16, parameter shift_bits_width = 4)
(
    input  [data_width-1:0] data_in,
    input  [shift_bits_width-1:0] shift_bits,
    input  left_right,
    input  rotate_left_right,
    output [data_width-1:0] data_out
);

  // If shift_bits is 0, no shifting or rotation is performed.
  // Otherwise, based on the rotate_left_right signal, perform either a standard shift
  // or a rotate operation. The left_right signal determines the direction.
  assign data_out = (shift_bits == 0) ? data_in :
                    (rotate_left_right ?
                        (left_right ?
                            // Left rotate: bits shifted out from the left end are inserted on the right.
                            {data_in[data_width-1:shift_bits], data_in[shift_bits-1:0]} :
                            // Right rotate: bits shifted out from the right end are inserted on the left.
                            {data_in[shift_bits-1:0], data_in[data_width-1:shift_bits]}
                        ) :
                        (left_right ? (data_in << shift_bits) : (data_in >> shift_bits))
                    );

endmodule

input.rtl/barrel_shifter.sv:
module barrel_shifter #(
    parameter data_width = 16,      // Change data_width to 16
    parameter shift_bits_width = 4  // Update shift_bits_width to handle shifts for 16-bit width
)(
    input [data_width-1:0] data_in,
    input [shift_bits_width-1:0] shift_bits,
    input left_right,               // 1: left shift, 0: right shift
    input rotate_left_right,        // 1: rotate, 0: shift
    input arithmetic_shift,         // 1: arithmetic shift, 0: logical shift
    output reg [data_width-1:0] data_out
);

always @(*) begin
    if (rotate_left_right) begin
        // Rotation logic
        if (left_right)
            data_out = (data_in << shift_bits) | (data_in >> (data_width - shift_bits)); // Rotate left
        else
            data_out = (data_in >> shift_bits) | (data_in << (data_width - shift_bits)); // Rotate right
    end else begin
        // Shift logic
        if (left_right)
            data_out = data_in << shift_bits;  // Left shift
        else if (arithmetic_shift)
            // Arithmetic right shift: explicitly sign-extend data_in to ensure the MSB (sign bit) is preserved
            data_out = $signed(data_in) >>> shift_bits;
        else
            data_out = data_in >> shift_bits;  // Logical right shift
    end
end

endmodule

