module bcd_to_excess_3(
    input [3:0] bcd,          // 4-bit BCD input
    output reg [3:0] excess3, // 4-bit Excess-3 output
    output reg error          // Error flag to indicate invalid input
);

// The always block triggers on any change to the BCD input.
always @(bcd)
begin
    error = 1'b0; 
    case(bcd)
        4'b0000: excess3 = 4'b0011;  
        4'b0001: excess3 = 4'b0100;  
        4'b0010: excess3 = 4'b0101;  
        4'b0011: excess3 = 4'b0110;  
        4'b0100: excess3 = 4'b0111;  
        4'b0101: excess3 = 4'b1000;  
        4'b0110: excess3 = 4'b1001;  
        4'b0111: excess3 = 4'b1010;  
        4'b1000: excess3 = 4'b1011;  
        4'b1001: excess3 = 4'b1100;  
        default: begin
            excess3 = 4'b0000;   // Set output to 0 on invalid input.
            error = 1'b1;        // Set error flag to 1 to indicate an invalid input was received.
        end
    endcase
end
endmodule

output.rtl/bcd_to_excess_3.sv:
module bcd_to_excess_3(
    input clk,
    input rst,
    input enable,
    input [3:0] bcd,
    output reg [3:0] excess3,
    output reg error,
    output reg parity,
    output reg [1:0] error_code
);

  // Synchronous process triggered on the rising edge of clk or asynchronous reset.
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      excess3      <= 4'b0000;
      error        <= 1'b0;
      parity       <= 1'b0;
      error_code   <= 2'b00;
    end else if (enable) begin
      // Calculate parity as the XOR of all bits in bcd.
      parity <= bcd[0] ^ bcd[1] ^ bcd[2] ^ bcd[3];

      // Check if the bcd input is within the valid range 0 to 9.
      if ((bcd >= 4'b0000) && (bcd <= 4'b1001)) begin
        // Valid input: perform BCD to Excess-3 conversion.
        case (bcd)
          4'b0000: excess3 <= 4'b0011;
          4'b0001: excess3 <= 4'b0100;
          4'b0010: excess3 <= 4'b0101;
          4'b0011: excess3 <= 4'b0110;
          4'b0100: excess3 <= 4'b0111;
          4'b0101: excess3 <= 4'b1000;
          4'b0110: excess3 <= 4'b1001;
          4'b0111: excess3 <= 4'b1010;
          4'b1000: excess3 <= 4'b1011;
          4'b1001: excess3 <= 4'b1100;
          default: excess3 <= 4'b0000; // Should not occur for valid input.
        endcase
        error       <= 1'b0;
        error_code  <= 2'b00;
      end else begin
        // Invalid input: set outputs to indicate error.
        excess3   <= 4'b0000;
        error     <= 1'b1;
        error_code<= 2'b01;
      end
    end
    // When enable is not asserted, the outputs retain their previous values.
  end

endmodule

output.rtl/binary_multiplier.sv:
module binary_multiplier #(
    parameter WIDTH = 32  // Bit-width of operands A and B
)(
    input  logic         clk,
    input  logic         rst_n,   // Active-low asynchronous reset
    input  logic         valid_in,   // Indicates when inputs are valid
    input  logic [WIDTH-1:0] A,          // Input A
    input  logic [WIDTH-1:0] B,          // Input B
    output logic [2*WIDTH-1:0] Product,    // Final multiplication result
    output logic         valid_out   // Indicates when Product is valid
);

    // Internal registers to latch inputs and hold intermediate values
    logic [WIDTH-1:0] a_reg;
    logic [WIDTH-1:0] b_reg;
    integer           counter;
    logic [2*WIDTH-1:0] acc;
    logic [2*WIDTH-1:0] product_reg0;
    logic [2*WIDTH-1:0] product_reg1;

    // State encoding for the sequential multiplier
    typedef enum logic [1:0] {
        IDLE   = 2'd0,
        CALC   = 2'd1,
        PIPE1  = 2'd2,
        PIPE2  = 2'd3
    } state_t;

    state_t state;

    // Sequential process: asynchronous reset, state machine, and pipeline registers
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state          <= IDLE;
            a_reg          <= '0;
            b_reg          <= '0;
            counter        <= 0;
            acc            <= '0;
            product_reg0   <= '0;
            product_reg1   <= '0;
            Product        <= '0;
            valid_out      <= 1'b0;
        end else begin
            case (state)
                IDLE: begin
                    Product   <= '0;
                    valid_out <= 1'b0;
                    // Latch inputs when valid_in is asserted and start the operation
                    if (valid_in) begin
                        a_reg  <= A;
                        b_reg  <= B;
                        counter<= 0;
                        acc    <= '0;
                        state  <= CALC;
                    end
                end
                CALC: begin
                    // Perform the add-shift multiplication for each bit of latched A
                    if (counter < WIDTH) begin
                        if (a_reg[counter])
                            acc <= acc + (b_reg << counter);
                        counter <= counter + 1;
                        if (counter == WIDTH)
                            state <= PIPE1;
                    end
                end
                PIPE1: begin
                    // First pipeline stage: latch the computed accumulator
                    product_reg0 <= acc;
                    state        <= PIPE2;
                end
                PIPE2: begin
                    // Second pipeline stage: register the final product and assert valid_out
                    product_reg1 <= product_reg0;
                    Product      <= product_reg1;
                    valid_out    <= 1'b1;
                    state        <= IDLE;
                end
            endcase
        end
    end

endmodule

output.rtl/binary_to_bcd.sv:
module binary_to_bcd (
    input logic [7:0] binary_in,  // 8-bit binary input
    output logic [11:0] bcd_out   // 12-bit BCD output (3 digits)
);

    // Intermediate 20-bit shift register: 12 bits for BCD and 8 bits for binary input
    logic [19:0] shift_reg;
    integer i;

    always_comb begin
        // Step 1: Initialize the shift register with 12 leading zeros and the binary input in the lower 8 bits
        shift_reg = {12'd0, binary_in};

        // Double Dabble algorithm: Process each bit of the binary input (8 iterations)
        for (i = 0; i < 8; i = i + 1) begin
            // Left shift the entire register by 1 bit.
            shift_reg = shift_reg << 1;

            // Adjust each 4-bit BCD digit in the high 12 bits.
            // The BCD digits are located at bits [19:16], [15:12], and [11:8].
            if (shift_reg[19:16] >= 5)
                shift_reg[19:16] = (shift_reg[19:16] + 3) & 4'hF;
            if (shift_reg[15:12] >= 5)
                shift_reg[15:12] = (shift_reg[15:12] + 3) & 4'hF;
            if (shift_reg[11:8] >= 5)
                shift_reg[11:8] = (shift_reg[11:8] + 3) & 4'hF;
        end

        // The final BCD result is contained in the upper 12 bits of the shift register.
        bcd_out = shift_reg[19:8];
    end

endmodule

