    // Initialize the shift register with 12'b0 in the upper part and the binary input in the lower part.
    // This ordering is chosen so that the binary input is processed bit‐by‐bit.
    shift_reg = {12'd0, binary_in};
    for (i = 0; i < 8; i = i + 1) begin
      if (shift_reg[11:8] >= 5)
        shift_reg[11:8] = shift_reg[11:8] + 3;
      if (shift_reg[15:12] >= 5)
        shift_reg[15:12] = shift_reg[15:12] + 3;
      if (shift_reg[19:16] >= 5)
        shift_reg[19:16] = shift_reg[19:16] + 3;
      shift_reg = shift_reg << 1;
    end
    bcd_out = shift_reg[19:8];
  end
