            if (req2)
                next_state = GRANT_2; // Grant Master 2 if req2 is asserted
            else if (req1)
                next_state = GRANT_1; // Grant Master 1 if only req1 is asserted
            else
                next_state = IDLE; // No requests, transition to IDLE
        end
        CLEAR: begin
            if (req2)
                next_state = GRANT_2;
            else if (req1)
                next_state = GRANT_1;
            else
                next_state = IDLE; // Default to IDLE if no requests
        end
        default: next_state = IDLE;
    endcase
end

// Output Logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        grant1 <= 1'b0;
        grant2 <= 1'b0;
    end else begin
        case (next_state)
            IDLE: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
            GRANT_1: begin
                grant1 <= 1'b1;
                grant2 <= 1'b0;
            end
            GRANT_2: begin
                grant1 <= 1'b0;
                grant2 <= 1'b1;
            end
            MASTER1_PRI: begin
                grant1 <= 1'b0; // During this state, neither master is granted
                grant2 <= 1'b0;
            end
            CLEAR: begin
                grant1 <= 1'b0;
                grant2 <= 1'b0;
            end
        endcase
    end
end

