                            min_count = frequency[index][(n * COUNTERW) +: COUNTERW];
                            min_way = n;
                        end else if (frequency[index][(n * COUNTERW) +: COUNTERW] == min_count && n < min_way) begin
                            // Tie-breaker: select the way with the lower index.
                            min_way = n;
