module caesar_cipher #(
    parameter PHRASE_WIDTH = 32,  // e.g., enough for 4 chars (4×8=32)
    parameter PHRASE_LEN   = PHRASE_WIDTH / 8
)(
    input  wire [PHRASE_WIDTH-1:0]       input_phrase,
    input  wire [(PHRASE_LEN * 5) - 1:0] key_phrase,
    input  wire                          decrypt,
    output reg  [PHRASE_WIDTH-1:0]       output_phrase
);

    integer i;
    reg [7:0] current_char;
    reg [4:0] current_key;

    always @(*) begin
        // Initialize output to zero
        output_phrase = {PHRASE_WIDTH{1'b0}};

        if (PHRASE_LEN > 0) begin
            for (i = 0; i < PHRASE_LEN; i = i + 1) begin
                // Extract current character & key
                current_char = input_phrase[i * 8 +: 8];
                current_key  = key_phrase[i * 5 +: 5];

                if (decrypt) begin
                    // Decryption mode
                    if (current_char >= "A" && current_char <= "Z") begin
                        // For uppercase, subtract key with wrap-around
                        output_phrase[i * 8 +: 8] = ((current_char - "A" - current_key + 26) % 26) + "A";
                    end
                    else if (current_char >= "a" && current_char <= "z") begin
                        // For lowercase, subtract key with wrap-around
                        output_phrase[i * 8 +: 8] = ((current_char - "a" - current_key + 26) % 26) + "a";
                    end
                    else begin
                        // Non-alphabetic: if key==0, leave unchanged; else subtract key
                        if (current_key == 0)
                            output_phrase[i * 8 +: 8] = current_char;
                        else
                            output_phrase[i * 8 +: 8] = current_char - current_key;
                    end
                end
                else begin
                    // Encryption mode
                    if (current_char >= "A" && current_char <= "Z") begin
                        // For uppercase, add key with wrap-around
                        output_phrase[i * 8 +: 8] = ((current_char - "A" + current_key) % 26) + "A";
                    end
                    else if (current_char >= "a" && current_char <= "z") begin
                        // For lowercase, add key with wrap-around
                        output_phrase[i * 8 +: 8] = ((current_char - "a" + current_key) % 26) + "a";
                    end
                    else begin
                        // Non-alphabetic: if key==0, leave unchanged; else add key
                        if (current_key == 0)
                            output_phrase[i * 8 +: 8] = current_char;
                        else
                            output_phrase[i * 8 +: 8] = current_char + current_key;
                    end
                end
            end
        end
    end

endmodule

module caesar_cipher(
    input  wire [7:0] input_char, // 8-bit ASCII character
    input  wire [3:0] key,        // 4-bit shift key
    output reg  [7:0] output_char // 8-bit shifted output character
);

  // Define ASCII constants and number of letters for clarity
  localparam ASCII_A = 8'h41;
  localparam ASCII_Z = 8'h5A;
  localparam ASCII_a = 8'h61;
  localparam ASCII_z = 8'h7A;
  localparam NUM_LETTERS = 26;

  always @(*) begin
    // For uppercase letters, expand the 4-bit key to 8 bits to avoid truncation
    if (input_char >= ASCII_A && input_char <= ASCII_Z) begin
      output_char = ((input_char - ASCII_A + {4'b0, key}) % NUM_LETTERS) + ASCII_A;
    end
    // For lowercase letters, similarly expand the 4-bit key
    else if (input_char >= ASCII_a && input_char <= ASCII_z) begin
      output_char = ((input_char - ASCII_a + {4'b0, key}) % NUM_LETTERS) + ASCII_a;
    end
    else begin
      output_char = input_char;
    end
  end

endmodule

