    parameter IN_DATA_WIDTH = 16,
    parameter IN_DATA_NS    = 4
)(
    input  logic         clk,
    input  logic         rst_n,
    input  logic         i_valid,
    input  logic [IN_DATA_WIDTH*IN_DATA_NS-1:0] i_data,
