module enhanced_fsm_signal_processor(
    input  wire         i_clk,
    input  wire         i_rst_n,
    input  wire         i_enable,
    input  wire         i_clear,
    input  wire         i_ack,
    input  wire         i_fault,
    input  wire [4:0]   i_vector_1,
    input  wire [4:0]   i_vector_2,
    input  wire [4:0]   i_vector_3,
    input  wire [4:0]   i_vector_4,
    input  wire [4:0]   i_vector_5,
    input  wire [4:0]   i_vector_6,
    output reg  [7:0]   o_vector_1,
    output reg  [7:0]   o_vector_2,
    output reg  [7:0]   o_vector_3,
    output reg  [7:0]   o_vector_4,
    output reg          o_ready,
    output reg          o_error,
    output reg  [1:0]   o_fsm_status
);

    // FSM state encoding
    localparam IDLE    = 2'b00;
    localparam PROCESS = 2'b01;
    localparam READY   = 2'b10;
    localparam FAULT   = 2'b11;

    reg [1:0] state;
    reg [31:0] data_bus; // holds the 32-bit processed bus

    // State and data_bus update
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state      <= IDLE;
            data_bus   <= 32'd0;
        end else begin
            // Fault condition takes precedence
            if (i_fault)
                state <= FAULT;
            else begin
                case (state)
                    IDLE: begin
                        if (i_enable)
                            state <= PROCESS;
                        else
                            state <= IDLE;
                    end
                    PROCESS: begin
                        state <= READY;
                    end
                    READY: begin
                        if (i_ack)
                            state <= IDLE;
                        else
                            state <= READY;
                    end
                    FAULT: begin
                        if (i_clear && !i_fault)
                            state <= IDLE;
                        else
                            state <= FAULT;
                    end
                    default: state <= IDLE;
                endcase
            end

            // In PROCESS state, compute the 32-bit bus:
            // Concatenate six 5-bit vectors and append 2'b11 at the LSB.
            if (state == PROCESS)
                data_bus <= { i_vector_1, i_vector_2, i_vector_3, i_vector_4, i_vector_5, i_vector_6, 2'b11 };
            else
                data_bus <= data_bus; // hold previous value
        end
    end

    // Output logic (all outputs are synchronous to i_clk)
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            o_vector_1  <= 8'd0;
            o_vector_2  <= 8'd0;
            o_vector_3  <= 8'd0;
            o_vector_4  <= 8'd0;
            o_ready     <= 1'b0;
            o_error     <= 1'b0;
            o_fsm_status<= 2'b00;
        end else begin
            // Fault condition takes precedence for outputs as well
            if (i_fault) begin
                o_vector_1  <= 8'd0;
                o_vector_2  <= 8'd0;
                o_vector_3  <= 8'd0;
                o_vector_4  <= 8'd0;
                o_ready     <= 1'b0;
                o_error     <= 1'b1;
                o_fsm_status<= 2'b11;
            end else begin
                case (state)
                    IDLE: begin
                        o_vector_1  <= 8'd0;
                        o_vector_2  <= 8'd0;
                        o_vector_3  <= 8'd0;
                        o_vector_4  <= 8'd0;
                        o_ready     <= 1'b0;
                        o_error     <= 1'b0;
                        o_fsm_status<= 2'b00;
                    end
                    PROCESS: begin
                        // Split the 32-bit bus into four 8-bit outputs.
                        o_vector_1  <= data_bus[31:24];
                        o_vector_2  <= data_bus[23:16];
                        o_vector_3  <= data_bus[15:8];
                        o_vector_4  <= data_bus[7:0];
                        o_ready     <= 1'b0;
                        o_error     <= 1'b0;
                        o_fsm_status<= 2'b01;
                    end
                    READY: begin
                        // Hold the computed outputs and assert o_ready.
                        o_vector_1  <= data_bus[31:24];
                        o_vector_2  <= data_bus[23:16];
                        o_vector_3  <= data_bus[15:8];
                        o_vector_4  <= data_bus[7:0];
                        o_ready     <= 1'b1;
                        o_error     <= 1'b0;
                        o_fsm_status<= 2'b10;
                    end
                    FAULT: begin
                        o_vector_1  <= 8'd0;
                        o_vector_2  <= 8'd0;
                        o_vector_3  <= 8'd0;
                        o_vector_4  <= 8'd0;
                        o_ready     <= 1'b0;
                        o_error     <= 1'b1;
                        o_fsm_status<= 2'b11;
                    end
                    default: begin
                        o_vector_1  <= 8'd0;
                        o_vector_2  <= 8'd0;
                        o_vector_3  <= 8'd0;
                        o_vector_4  <= 8'd0;
                        o_ready     <= 1'b0;
                        o_error     <= 1'b0;
                        o_fsm_status<= 2'b00;
                    end
                endcase
            end
        end
    end

endmodule

output.rtl/low_pass_filter.sv:
module low_pass_filter #(
    parameter integer DATA_WIDTH = 16,
    parameter integer COEFF_WIDTH = 16,
    parameter integer NUM_TAPS = 8,
    // NBW_MULT is derived internally as DATA_WIDTH + COEFF_WIDTH
    parameter integer NBW_MULT = DATA_WIDTH + COEFF_WIDTH
)(
    input  logic clk,
    input  logic reset,
    // Packed input: NUM_TAPS samples of signed DATA_WIDTH-bit values
    input  logic [DATA_WIDTH*NUM_TAPS-1:0] data_in,
    input  logic valid_in,
    // Packed coefficients: NUM_TAPS samples of signed COEFF_WIDTH-bit values
    input  logic [COEFF_WIDTH*NUM_TAPS-1:0] coeffs,
    // Output width: NBW_MULT + $clog2(NUM_TAPS)
    output logic [NBW_MULT+$clog2(NUM_TAPS)-1:0] data_out,
    output logic valid_out
);

    // Calculate the number of bits needed to represent NUM_TAPS
    localparam int NUM_TAPS_LOG = $clog2(NUM_TAPS);
    // Define the output width to accommodate the sum of up to NUM_TAPS products
    localparam int OUT_WIDTH = NBW_MULT + NUM_TAPS_LOG;

    // Internal registers to hold the unpacked input data and coefficients.
    // These registers are updated only when valid_in is asserted, or cleared on reset.
    logic signed [DATA_WIDTH-1:0] data_reg [0:NUM_TAPS-1];
    logic signed [COEFF_WIDTH-1:0] coeff_reg [0:NUM_TAPS-1];

    // Synchronous process: Register input data and coefficients.
    // If valid_in is high, unpack the packed vectors into the internal arrays.
    // Otherwise, retain the previously registered values.
    always_ff @(posedge clk) begin
        if (reset) begin
            for (int i = 0; i < NUM_TAPS; i++) begin
                data_reg[i] <= '0;
                coeff_reg[i] <= '0;
            end
            valid_out <= 1'b0;
        end else begin
            if (valid_in) begin
                for (int i = 0; i < NUM_TAPS; i++) begin
                    // Unpack the packed bit vectors into arrays.
                    // Each element is extracted using a part-select with the -: operator.
                    data_reg[i] <= data_in[((i+1)*DATA_WIDTH)-1 -: DATA_WIDTH];
                    coeff_reg[i] <= coeffs[((i+1)*COEFF_WIDTH)-1 -: COEFF_WIDTH];
                end
            end
            // The valid signal is registered to introduce a one-cycle latency.
            valid_out <= valid_in;
        end
    end

    // Combinational logic to perform the FIR convolution.
    // The coefficients are applied in reverse order relative to the input data.
    // Intermediate multiplication results are computed in NBW_MULT bits.
    // The summation is performed in an adder tree to accumulate the products.
    logic signed [NBW_MULT-1:0] product;
    logic signed [OUT_WIDTH-1:0] sum;
    always_comb begin
        sum = '0;
        for (int i = 0; i < NUM_TAPS; i++) begin
            // Multiply data_reg[i] with the corresponding reversed coefficient.
            product = data_reg[i] * coeff_reg[NUM_TAPS-1-i];
            sum = sum + product;
        end
    end

    // Register the computed sum to produce the final output.
    // This introduces a one-cycle latency, ensuring that data_out and valid_out are synchronized.
    always_ff @(posedge clk) begin
        if (reset)
            data_out <= '0;
        else
            data_out <= sum;
    end

endmodule

