  logic signed [DATA_WIDTH-1:0] new_sum;
  logic signed [DATA_WIDTH-1:0] sat_sum;

  always_ff @(posedge clk or posedge reset) begin
    if (reset)
      weighted_in_reg <= 0;
    else if (enable && data_valid) begin
      if (WEIGHT == 1)
        weighted_in_reg <= data_in;
      else
        weighted_in_reg <= data_in * WEIGHT;
    end else
      weighted_in_reg <= weighted_in_reg;
  end

  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      new_sum <= 0;
      sat_sum <= 0;
    end else if (enable && data_valid) begin
      new_sum <= sum_accum + weighted_in_reg;
      if ((sum_accum + weighted_in_reg) > SAT_MAX)
        sat_sum <= SAT_MAX;
      else if ((sum_accum + weighted_in_reg) < SAT_MIN)
        sat_sum <= SAT_MIN;
      else
        sat_sum <= sum_accum + weighted_in_reg;
    end
  end

  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      state <= IDLE;
      sum_accum <= 0;
      sample_count <= 0;
    end else if (accum_clear) begin
      state <= IDLE;
      sum_accum <= 0;
      sample_count <= 0;
    end else if (enable && data_valid) begin
      case (state)
        IDLE: begin
          state <= ACCUM;
          sum_accum <= sat_sum;
          sample_count <= 1;
        end
        ACCUM: begin
          sum_accum <= sat_sum;
          sample_count <= sample_count + 1;
          if (ACCUM_MODE == 1) begin
            if ((sample_count + 1) >= window_size)
              state <= DONE;
          end else begin
            if (((sat_sum >= THRESHOLD_VALUE_1) || (sat_sum <= -THRESHOLD_VALUE_1)) ||
                ((sat_sum >= THRESHOLD_VALUE_2) || (sat_sum <= -THRESHOLD_VALUE_2)) ||
                ((sat_sum >= THRESHOLD_VALUE_3) || (sat_sum <= -THRESHOLD_VALUE_3)))
              state <= DONE;
          end
        end
        DONE: begin
          state <= IDLE;
          sum_accum <= 0;
          sample_count <= 0;
        end
        default: state <= IDLE;
      endcase
    end
  end

  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      sum_out <= 0;
      avg_out <= 0;
      sum_ready <= 0;
      threshold_1 <= 0;
      threshold_2 <= 0;
      threshold_3 <= 0;
      busy <= 0;
    end else begin
      busy <= (state == ACCUM);
      if (state == DONE) begin
        sum_out <= sum_accum;
        avg_out <= (ACCUM_MODE == 1) ? (sum_accum / sample_count) : 0;
        sum_ready <= 1;
        if ((sum_accum >= THRESHOLD_VALUE_1) || (sum_accum <= -THRESHOLD_VALUE_1))
          threshold_1 <= 1;
        else
          threshold_1 <= 0;
        if ((sum_accum >= THRESHOLD_VALUE_2) || (sum_accum <= -THRESHOLD_VALUE_2))
          threshold_2 <= 1;
        else
          threshold_2 <= 0;
        if ((sum_accum >= THRESHOLD_VALUE_3) || (sum_accum <= -THRESHOLD_VALUE_3))
          threshold_3 <= 1;
        else
          threshold_3 <= 0;
      end else begin
        sum_out <= 0;
        avg_out <= 0;
        sum_ready <= 0;
        threshold_1 <= 0;
        threshold_2 <= 0;
        threshold_3 <= 0;
      end
    end
  end

endmodule

output.rtl/convolutional_encoder.sv:
module convolutional_encoder (
    input  logic         clk,
    input  logic         rst,
    input  logic         data_in,
    output logic         encoded_bit1,
    output logic         encoded_bit2
);

  // 2-bit shift register to hold the previous 2 bits (k-1 = 2 bits)
  logic [1:0] shift_reg;

  // Update the shift register on each clock cycle.
  // The new bit (data_in) is inserted at the LSB.
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      shift_reg <= 2'b00;
    end else begin
      // Shift left: the older bit (shift_reg[0]) becomes the new MSB,
      // and data_in becomes the new LSB.
      shift_reg <= { shift_reg[0], data_in };
    end
  end

  // Generate the encoded outputs using the generator polynomials.
  // g1(x) = x^2 + x + 1 corresponds to: encoded_bit1 = data_in XOR shift_reg[1] XOR shift_reg[0]
  // g2(x) = x^2 + 1 corresponds to: encoded_bit2 = data_in XOR shift_reg[0]
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      encoded_bit1 <= 1'b0;
      encoded_bit2 <= 1'b0;
    end else begin
      encoded_bit1 <= data_in ^ shift_reg[1] ^ shift_reg[0];
      encoded_bit2 <= data_in ^ shift_reg[0];
    end
  end

endmodule

module convolutional_encoder (
    input  wire         clk,
    input  wire         rst,
    input  wire         data_in,
    output reg          encoded_bit1,
    output reg          encoded_bit2
);

    // Shift register to hold the previous two bits (constraint length k=3)
    // shift_reg[1] holds the oldest bit (s2)
    // shift_reg[0] holds the more recent bit (s1)
    reg [1:0] shift_reg;

    // On each clock cycle, update the shift register and compute the encoded bits.
    // Generator polynomials:
    //   g1(x) = x^2 + x + 1  => encoded_bit1 = s0 XOR s1 XOR s2
    //   g2(x) = x^2 + 1      => encoded_bit2 = s0 XOR s2
    // Here, s0 is the current input (data_in), s1 is shift_reg[0], and s2 is shift_reg[1].
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            shift_reg      <= 2'b00;
            encoded_bit1   <= 1'b0;
            encoded_bit2   <= 1'b0;
        end else begin
            // Shift the register: the new input becomes the least significant bit.
            shift_reg <= {shift_reg[0], data_in};

            // Compute encoded outputs based on generator polynomials.
            encoded_bit1 <= data_in ^ shift_reg[0] ^ shift_reg[1];
            encoded_bit2 <= data_in ^ shift_reg[1];
        end
    end

endmodule

output.rtl/crossbar_switch.sv:
module crossbar_switch #(
    parameter DATA_WIDTH = 8,  // Parameterized data width
    localparam NUM_PORTS = 4,
    localparam DATA_WIDTH_IN = (DATA_WIDTH + $clog2(NUM_PORTS))
)(
    input  logic                        clk,        // Clock signal
    input  logic                        reset,      // Reset signal (asynchronous, active low)
    // Input data and destination IDs
    input  logic [DATA_WIDTH_IN-1 :0]  in0, in1, in2, in3,  // Input data (upper 2 bits = destination ID)
    input  logic                       valid_in0, valid_in1, valid_in2, valid_in3,  // Input valid signals
    // Output data
    output logic  [DATA_WIDTH-1:0]      out0, out1, out2, out3,  // Output data
    output logic                        valid_out0, valid_out1, valid_out2, valid_out3  // Output valid signals
);

    // Internal signals to extract destination IDs from input data
    logic [$clog2(NUM_PORTS)-1 : 0] dest0, dest1, dest2, dest3;

    // ----------------------------------------
    // - Procedural blocks
    // ----------------------------------------
    always @(posedge clk or negedge reset) begin
        if (!reset) begin
            out0    <= '0;
            out1    <= '0;
            out2    <= '0;
            out3    <= '0;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;
        end else begin
            // Default assignments: clear outputs
            out0    <= '0;
            out1    <= '0;
            out2    <= '0;
            out3    <= '0;
            valid_out0 <= 1'b0;
            valid_out1 <= 1'b0;
            valid_out2 <= 1'b0;
            valid_out3 <= 1'b0;

            // Only the highest priority valid input is processed.
            if (valid_in0) begin
                case (dest0)
                    2'd0: begin
                        out0    <= in0[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'd1: begin
                        out1    <= in0[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'd2: begin
                        out2    <= in0[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'd3: begin
                        out3    <= in0[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in1) begin
                case (dest1)
                    2'd0: begin
                        out0    <= in1[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'd1: begin
                        out1    <= in1[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'd2: begin
                        out2    <= in1[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'd3: begin
                        out3    <= in1[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in2) begin
                case (dest2)
                    2'd0: begin
                        out0    <= in2[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'd1: begin
                        out1    <= in2[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'd2: begin
                        out2    <= in2[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'd3: begin
                        out3    <= in2[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                    default: ;
                endcase
            end else if (valid_in3) begin
                case (dest3)
                    2'd0: begin
                        out0    <= in3[DATA_WIDTH-1:0];
                        valid_out0 <= 1'b1;
                    end
                    2'd1: begin
                        out1    <= in3[DATA_WIDTH-1:0];
                        valid_out1 <= 1'b1;
                    end
                    2'd2: begin
                        out2    <= in3[DATA_WIDTH-1:0];
                        valid_out2 <= 1'b1;
                    end
                    2'd3: begin
                        out3    <= in3[DATA_WIDTH-1:0];
                        valid_out3 <= 1'b1;
                    end
                    default: ;
                endcase
            end else begin
                // No valid input: outputs remain cleared.
            end
        end
    end

    // ----------------------------------------
    // - Combinational Assignments
    // ----------------------------------------
    assign dest0 = in0 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in0 data
    assign dest1 = in1 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in1 data
    assign dest2 = in2 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in2 data
    assign dest3 = in3 [DATA_WIDTH_IN-1 : DATA_WIDTH_IN-2] ; // Destination port ID for in3 data

endmodule

output.rtl/data_bus_controller.sv:
module data_bus_controller #(
  parameter AFINITY = 0
)(
  input         clk,
  input         rst_n,

  output        m0_read,
  input         m0_valid,
  input  [31:0] m0_data,

  output        m1_read,
  input         m1_valid,
  input  [31:0] m1_data,

  input         s_read,
  output        s_valid,
  output [31:0] s_data
);

  // State encoding: 0 = IDLE, 1 = FORWARD
  localparam IDLE     = 1'b0;
  localparam FORWARD  = 1'b1;

  // Internal registers
  reg         state;          // Current state of the controller
  reg [31:0]  pending_data;   // Holds the captured transaction data
  reg         s_read_reg;     // Registered version of s_read for sampling

  // Masters ready signals: when in IDLE state the controller is ready to accept a transaction.
  assign m0_read = (state == IDLE);
  assign m1_read = (state == IDLE);

  // Slave interface: when in FORWARD state and s_read is high, output the captured transaction.
  assign s_valid = (state == FORWARD) ? s_read : 1'b0;
  assign s_data  = (state == FORWARD) ? pending_data : 32'b0;

  // State machine to implement one-cycle latency and arbitration.
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      state        <= IDLE;
      pending_data <= 32'b0;
      s_read_reg   <= 1'b0;
    end else begin
      // Register the slave ready signal from the previous cycle.
      s_read_reg <= s_read;

      case (state)
        IDLE: begin
          // When in IDLE, if the slave was ready in the previous cycle,
          // capture a transaction from the masters.
          if (s_read_reg) begin
            if (m0_valid && ~m1_valid) begin
              pending_data <= m0_data;
            end else if (~m0_valid && m1_valid) begin
              pending_data <= m1_data;
            end else if (m0_valid && m1_valid) begin
              // If both masters are valid simultaneously, use AFINITY to decide.
              if (AFINITY == 0)
                pending_data <= m0_data;
              else
                pending_data <= m1_data;
            end
            // Move to FORWARD state to output the captured transaction.
            state <= FORWARD;
          end
          // Else remain in IDLE.
        end

        FORWARD: begin
          // In FORWARD state, if the slave is ready, output the transaction and return to IDLE.
          if (s_read)
            state <= IDLE;
          // Otherwise, hold the transaction (waiting for the slave to accept it).
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

input.rtl/data_serializer.sv:
module data_serializer #(
  parameter DATA_W   = 8,
  parameter BIT_ORDER= 0,
  parameter PARITY   = 0
)(
  input                  clk,
  input                  reset,
  // Parallel data interface
  input                  p_valid_i,
  input  [DATA_W-1:0]    p_data_i,
  output                 p_ready_o,
  // Serial data interface
  output                 s_valid_o,
  output                 s_data_o,
  input                  s_ready_i,
  // Transmission enable
  input                  tx_en_i
);

  // Local constants
  localparam ST_RX = 1'b0;
  localparam ST_TX = 1'b1;

  // If PARITY != 0 => We use 1 extra bit for parity
  localparam EXTRA_BIT = (PARITY == 0) ? 0 : 1;
  localparam SHIFT_W   = DATA_W + EXTRA_BIT;

  // Internal regs
  reg                    state_q, state_d;
  reg  [SHIFT_W-1:0]     shift_reg_q, shift_reg_d;
  reg  [$clog2(SHIFT_W)-1:0] count_q, count_d;

  // Parity calculation
  wire parity_bit_even = ^p_data_i;   // XOR => "even"
  wire parity_bit_odd  = ~^p_data_i;  // invert XOR => "odd"

  wire parity_bit = (PARITY == 1) ? parity_bit_even :
                    (PARITY == 2) ? parity_bit_odd  :
                                    1'b0; // NONE

  // Sequential state & register updates
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      state_q     <= ST_RX;
      shift_reg_q <= {SHIFT_W{1'b0}};
      count_q     <= 0;
    end else begin
      state_q     <= state_d;
      shift_reg_q <= shift_reg_d;
      count_q     <= count_d;
    end
  end

  // Next-state logic
  always @* begin
    // Default assignments
    state_d     = state_q;
    shift_reg_d = shift_reg_q;
    count_d     = count_q;

    case (state_q)

      // ST_RX: Load parallel data + parity
      ST_RX: begin
        if (p_valid_i) begin
          if (BIT_ORDER == 0) begin
            // LSB-first => store LSB in shift_reg_d[0]
            if (EXTRA_BIT == 1)
              shift_reg_d = {parity_bit, p_data_i};  // 9 bits if PARITY!=0
            else
              shift_reg_d = p_data_i;                // 8 bits if PARITY=0
          end
          else begin
            // MSB-first => store MSB in shift_reg_d[SHIFT_W-1]
            // If parity is used, it goes in the LSB or SHIFT_W-1?
            // We'll put it in the LSB if EXTRA_BIT=1
            if (EXTRA_BIT == 1) begin
              shift_reg_d[8:4] = {p_data_i[4:0],parity_bit};
              shift_reg_d[3:0] = p_data_i[8:5];
            end else
              shift_reg_d = p_data_i;
          end

          count_d = 0;
          state_d = ST_TX;
        end
      end

      // ST_TX: Shift bits out until SHIFT_W done
      ST_TX: begin
        // Only shift if s_ready_i & tx_en_i
        if (s_ready_i && tx_en_i) begin
          if (count_q == (SHIFT_W - 1)) begin
            // Done sending SHIFT_W bits
            state_d   = ST_RX;
            count_d   = 0;
          end
          else begin
            if (BIT_ORDER == 1) begin
              if (EXTRA_BIT == 1) begin
                // SHIFT left by 2 bits
                shift_reg_d[SHIFT_W-1:2] = shift_reg_q[SHIFT_W-3:0];
                shift_reg_d[1:0]         = 2'b00;
                count_d                  = count_q + 2;
              end
              else begin
                // Normal MSB-first => shift left by 1
                shift_reg_d = {shift_reg_q[SHIFT_W-2:0], 1'b0};
                count_d     = count_q + 1;
              end
            end
            else begin
              // LSB-first => shift right by 1 (no bug)
              shift_reg_d = {1'b0, shift_reg_q[SHIFT_W-1:1]};
              count_d     = count_q + 1;
            end
          end
        end
      end

      default: begin
        state_d = ST_RX; // safe fallback
      end
    endcase
  end

  // Outputs
  assign s_valid_o = (state_q == ST_TX);

  // LSB-first => s_data_o = shift_reg_q[0]
  // MSB-first => s_data_o = shift_reg_q[SHIFT_W-1]
  assign s_data_o  = (BIT_ORDER == 0) ? shift_reg_q[0] : shift_reg_q[SHIFT_W-1];

  assign p_ready_o = (state_q == ST_RX);

endmodule

