output.rtl/data_width_converter.sv:
module data_width_converter(
    input  logic         clk,
    input  logic         reset,
    input  logic [31:0]  data_in,
    input  logic         data_valid,
    output logic [127:0] o_data_out,
    output logic         o_data_out_valid
);

    // Internal buffer to store four 32-bit data samples
    logic [31:0] data_buffer [0:3];
    // Counter to track the number of valid samples received (0 to 4)
    logic [2:0]  sample_count;

    always_ff @(posedge clk or posedge reset) begin
        if (reset) begin
            sample_count         <= 3'd0;
            data_buffer[0]       <= 32'd0;
            data_buffer[1]       <= 32'd0;
            data_buffer[2]       <= 32'd0;
            data_buffer[3]       <= 32'd0;
            o_data_out_valid     <= 1'b0;
        end else begin
            if (data_valid) begin
                // Store the incoming data sample into the buffer at the current index
                data_buffer[sample_count] <= data_in;
                // Increment the sample counter
                sample_count <= sample_count + 1;

                // When four valid samples have been received, generate the output
                if (sample_count == 3'd4) begin
                    // Concatenate the four samples in order (first sample is MSB)
                    o_data_out <= { data_buffer[3], data_buffer[2], data_buffer[1], data_buffer[0] };
                    o_data_out_valid <= 1'b1;
                    // Reset the counter and buffer for the next set of inputs
                    sample_count <= 3'd0;
                end else begin
                    o_data_out_valid <= 1'b0;
                end
            end else begin
                o_data_out_valid <= 1'b0;
            end
        end
    end

endmodule

output.rtl/dbi_enc.sv:
module dbi_enc (
  input  logic         clk,
  input  logic         rst_n,
  input  logic [39:0]  data_in,
  output logic [39:0]  data_out,
  output logic [1:0]   dbi_cntrl
);

  // Register to hold previous data for comparison
  logic [39:0] prev_data;

  // Function to count the number of ones in a 20-bit vector
  function automatic int count_ones(input logic [19:0] value);
    int count;
    begin
      count = 0;
      for (int i = 0; i < 20; i++) begin
         if (value[i])
           count++;
      end
      count_ones = count;
    end
  endfunction

  // Internal signals for splitting data into groups and computing differences
  logic [19:0] group1, group0;          // Current groups from data_in
  logic [19:0] prev_group1, prev_group0; // Previous groups from prev_data
  logic [19:0] diff1, diff0;             // Difference between current and previous groups
  logic [19:0] group1_out, group0_out;   // Output groups after potential inversion

  // Sequential logic: process on rising edge of clk or asynchronous reset
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      // Reset: clear outputs and previous data
      data_out   <= 40'b0;
      dbi_cntrl  <= 2'b00;
      prev_data  <= 40'b0;
    end else begin
      // Split the 40-bit input into two 20-bit groups
      group1 = data_in[39:20];
      group0 = data_in[19:0];

      // Extract previous groups from stored previous data
      prev_group1 = prev_data[39:20];
      prev_group0 = prev_data[19:0];

      // Compute the bitwise differences between current and previous groups
      diff1 = group1 ^ prev_group1;
      diff0 = group0 ^ prev_group0;

      // Determine control bits: if more than 10 bits differ, set control bit to 1
      if (count_ones(diff1) > 10)
        dbi_cntrl[1] = 1'b1;
      else
        dbi_cntrl[1] = 1'b0;

      if (count_ones(diff0) > 10)
        dbi_cntrl[0] = 1'b1;
      else
        dbi_cntrl[0] = 1'b0;

      // Generate output groups: invert if control bit is high, pass through if low
      if (dbi_cntrl[1])
        group1_out = ~group1;
      else
        group1_out = group1;

      if (dbi_cntrl[0])
        group0_out = ~group0;
      else
        group0_out = group0;

      // Combine the two groups to form the 40-bit data_out
      data_out <= {group1_out, group0_out};

      // Update previous data with the current cycle's encoded output
      prev_data <= data_out;
    end
  end

endmodule

output.rtl/dbi_dec.sv:
module dbi_dec (
   // Inputs
   input  wire        rst_n,     // Asynchronous reset (active low)
   input  wire        clk,       // Clock
   input  wire [39:0] data_in,   // 40-bit data input before DBI decoding
   input  wire [1:0]  dbi_cntrl, // Control signals for DBI decoding (LSB for LSB group, MSB for MSB group)
   // Outputs
   output wire [39:0] data_out   // 40-bit data output after DBI decoding
);

   // On every rising edge of clk or when rst_n is low, update data_out.
   // When rst_n is low, data_out is reset to 0.
   // Otherwise, decode data_in by splitting into two 20-bit groups and conditionally inverting each group.
   always @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         data_out <= 40'b0;
      end else begin
         data_out <= { (dbi_cntrl[1] ? ~data_in[39:20] : data_in[39:20]),
                       (dbi_cntrl[0] ? ~data_in[19:0] : data_in[19:0]) };
      end
   end

endmodule

output.rtl/cvdp_copilot_decode_firstbit.sv:
module cvdp_copilot_decode_firstbit (
  input  logic                  Clk,
  input  logic                  Rst,
  input  logic [InWidth_g-1:0]  In_Data,
  input  logic                  In_Valid,
  output logic [$clog2(InWidth_g)-1:0] Out_FirstBit,
  output logic                  Out_Found,
  output logic                  Out_Valid
);

  // Parameters
  parameter int InWidth_g = 32;
  parameter bit   InReg_g  = 1;
  parameter bit   OutReg_g = 1;
  parameter int   PlRegs_g = 1;

  // Calculate the number of bits required to encode the index of the first set bit.
  localparam int BinBits_c = $clog2(InWidth_g);

  // Determine the padded width: if InWidth_g is not a power of two, pad it to the next power of two.
  localparam int PaddedWidth = (InWidth_g == (1 << BinBits_c)) ? InWidth_g : (1 << (BinBits_c+1));

  //-------------------------------------------------------------------------
  // Input registration (if enabled)
  //-------------------------------------------------------------------------
  reg [InWidth_g-1:0] data_reg;
  reg                  in_valid_reg;

  always_ff @(posedge Clk or posedge Rst) begin
    if (Rst) begin
      data_reg     <= '0;
      in_valid_reg <= 1'b0;
    end
    else if (InReg_g) begin
      data_reg     <= In_Data;
      in_valid_reg <= In_Valid;
    end
  end

  //-------------------------------------------------------------------------
  // Pad the input data to the nearest power-of-two width.
  //-------------------------------------------------------------------------
  wire [PaddedWidth-1:0] padded_data;
  assign padded_data = { data_reg, {PaddedWidth - InWidth_g{1'b0}} };

  //-------------------------------------------------------------------------
  // Combinational logic to decode the first set bit.
  // ffs() returns the index (starting at 0) of the first set bit.
  // If padded_data is zero, then no bit is found.
  //-------------------------------------------------------------------------
  wire [$clog2(InWidth_g)-1:0] comb_firstbit;
  wire                         comb_found;
  assign {comb_found, comb_firstbit} = (padded_data != 0) ?
      { 1'b1, ffs(padded_data) } : { 1'b0, {BinBits_c{1'b0}} };

  //-------------------------------------------------------------------------
  // Pipeline registers for the first-bit decoding logic.
  // Stage 0 is driven by the combinational result.
  // Additional stages (PlRegs_g) introduce latency.
  //-------------------------------------------------------------------------
  reg [$clog2(InWidth_g)-1:0] pipe_firstbit [0:PlRegs_g];
  reg                         pipe_found   [0:PlRegs_g];
  reg                         pipe_valid   [0:PlRegs_g];

  integer i;
  always_ff @(posedge Clk or posedge Rst) begin
    if (Rst) begin
      for (i = 0; i <= PlRegs_g; i = i + 1) begin
        pipe_firstbit[i] <= '0;
        pipe_found[i]    <= 1'b0;
        pipe_valid[i]    <= 1'b0;
      end
    end
    else begin
      // Stage 0: capture combinational result
      pipe_firstbit[0] <= comb_firstbit;
      pipe_found[0]    <= comb_found;
      pipe_valid[0]    <= in_valid_reg;
      // Pipeline stages: register the output of the previous stage
      for (i = 1; i <= PlRegs_g; i = i + 1) begin
        pipe_firstbit[i] <= pipe_firstbit[i-1];
        pipe_found[i]    <= pipe_found[i-1];
        pipe_valid[i]    <= pipe_valid[i-1];
      end
    end
  end

  //-------------------------------------------------------------------------
  // Output registration (if enabled)
  //-------------------------------------------------------------------------
  reg [$clog2(InWidth_g)-1:0] out_firstbit_reg;
  reg                         out_found_reg;
  reg                         out_valid_reg;

  always_ff @(posedge Clk or posedge Rst) begin
    if (Rst) begin
      out_firstbit_reg <= '0;
      out_found_reg    <= 1'b0;
      out_valid_reg    <= 1'b0;
    end
    else if (OutReg_g) begin
      out_firstbit_reg <= pipe_firstbit[PlRegs_g];
      out_found_reg    <= pipe_found[PlRegs_g];
      out_valid_reg    <= pipe_valid[PlRegs_g];
    end
  end

  //-------------------------------------------------------------------------
  // Drive the outputs.
  //-------------------------------------------------------------------------
  assign Out_FirstBit = out_firstbit_reg;
  assign Out_Found    = out_found_reg;
  assign Out_Valid    = out_valid_reg;

endmodule

