module decoder_8b10b (
    input  logic        clk_in,       // trigger on rising edge
    input  logic        reset_in,     // reset_in, assert HI
    input  logic [9:0]  decoder_in,   // 10-bit input
    output logic [7:0]  decoder_out,  // 8-bit decoded output
    output logic        control_out   // control char, assert HI for control words
);

    // Internal registers
    logic [9:0] s_in_10b_reg;  
    logic [7:0] s_decoder_out; 
    logic       s_control_out;     

    always_ff @(posedge clk_in or posedge reset_in) begin
        if (reset_in) begin
            s_in_10b_reg   <= 10'b0000000000;
            s_decoder_out  <= 8'b00000000;
            s_control_out  <= 1'b0;
        end else begin
            s_in_10b_reg   <= decoder_in;
            // Default values
            s_decoder_out  <= 8'b00000000;
            s_control_out  <= 1'b0;

            // Decode the incoming 10-bit code using valid control symbols
            case (decoder_in)
                // K.28.0
                10'b0011110100: begin
                    s_decoder_out <= 8'b00011100; // 0x1C
                    s_control_out <= 1'b1;
                end
                10'b1100001011: begin
                    s_decoder_out <= 8'b00011100;
                    s_control_out <= 1'b1;
                end
                // K.28.1
                10'b0011111001: begin
                    s_decoder_out <= 8'b00111100; // 0x3C
                    s_control_out <= 1'b1;
                end
                10'b1100000110: begin
                    s_decoder_out <= 8'b00111100;
                    s_control_out <= 1'b1;
                end
                // K.28.2
                10'b0011110101: begin
                    s_decoder_out <= 8'b01011100; // 0x5C
                    s_control_out <= 1'b1;
                end
                10'b1100001010: begin
                    s_decoder_out <= 8'b01011100;
                    s_control_out <= 1'b1;
                end
                // K.28.3
                10'b0011110011: begin
                    s_decoder_out <= 8'b01111100; // 0x7C
                    s_control_out <= 1'b1;
                end
                10'b1100001100: begin
                    s_decoder_out <= 8'b01111100;
                    s_control_out <= 1'b1;
                end
                // K.28.4
                10'b0011110010: begin
                    s_decoder_out <= 8'b10011100; // 0x9C
                    s_control_out <= 1'b1;
                end
                10'b1100001101: begin
                    s_decoder_out <= 8'b10011100;
                    s_control_out <= 1'b1;
                end
                // K.28.5
                10'b0011111010: begin
                    s_decoder_out <= 8'b10111100; // 0xBC
                    s_control_out <= 1'b1;
                end
                10'b1100000101: begin
                    s_decoder_out <= 8'b10111100;
                    s_control_out <= 1'b1;
                end
                // K.28.6
                10'b0011110110: begin
                    s_decoder_out <= 8'b11011100; // 0xDC
                    s_control_out <= 1'b1;
                end
                10'b1100001001: begin
                    s_decoder_out <= 8'b11011100;
                    s_control_out <= 1'b1;
                end
                // K.28.7
                10'b0011111000: begin
                    s_decoder_out <= 8'b11111100; // 0xFC
                    s_control_out <= 1'b1;
                end
                10'b1100000111: begin
                    s_decoder_out <= 8'b11111100;
                    s_control_out <= 1'b1;
                end
                // K.23.7
                10'b1110101000: begin
                    s_decoder_out <= 8'b11110111; // 0xF7
                    s_control_out <= 1'b1;
                end
                10'b0001010111: begin
                    s_decoder_out <= 8'b11110111;
                    s_control_out <= 1'b1;
                end
                // K.27.7
                10'b1101101000: begin
                    s_decoder_out <= 8'b11111011; // 0xFB
                    s_control_out <= 1'b1;
                end
                10'b0010010111: begin
                    s_decoder_out <= 8'b11111011;
                    s_control_out <= 1'b1;
                end
                // K.29.7
                10'b1011101000: begin
                    s_decoder_out <= 8'b11111101; // 0xFD
                    s_control_out <= 1'b1;
                end
                10'b0100010111: begin
                    s_decoder_out <= 8'b11111101;
                    s_control_out <= 1'b1;
                end
                // K.30.7
                10'b0111101000: begin
                    s_decoder_out <= 8'b11111110; // 0xFE
                    s_control_out <= 1'b1;
                end
                10'b1000010111: begin
                    s_decoder_out <= 8'b11111110;
                    s_control_out <= 1'b1;
                end
                // Invalid control symbol: default case
                default: begin
                    s_decoder_out <= 8'b00000000;
                    s_control_out <= 1'b0;
                end
            endcase
        end
    end

    // Output assignments
    assign decoder_out = s_decoder_out;
    assign control_out = s_control_out;

endmodule

output.rtl/digital_dice_roller.sv:
module digital_dice_roller (
    input  logic         clk,
    input  logic         reset_n,
    input  logic         button,
    output logic [2:0]   dice_value
);

  // Define FSM states
  typedef enum logic { IDLE, ROLLING } state_t;
  state_t state, next_state;

  // Internal 3-bit counter used during rolling
  logic [2:0] counter;

  // Next state combinational logic
  always_comb begin
    // Default: hold current state
    next_state = state;
    case (state)
      IDLE: begin
        // Transition to ROLLING if button is pressed
        if (button)
          next_state = ROLLING;
      end
      ROLLING: begin
        // Return to IDLE when button is released
        if (!button)
          next_state = IDLE;
      end
    endcase
  end

  // Sequential logic for state, counter, and output update
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      // Asynchronous reset: go to IDLE and initialize dice_value and counter to 1
      state      <= IDLE;
      counter    <= 3'd1;
      dice_value <= 3'd1;
    end
    else begin
      // Update state
      state <= next_state;

      // In ROLLING state: update counter on button press; latch last value on release
      if (state == ROLLING) begin
        if (button)
          counter <= (counter == 3'd6) ? 3'd1 : counter + 1;
        else
          dice_value <= counter;  // Latch the last value when button is released
      end
      // In IDLE state: if button is pressed, prepare for a new roll by setting dice_value to 1;
      // otherwise, hold the current dice_value.
      else begin  // state == IDLE
        if (button)
          dice_value <= 3'd1;
        else
          dice_value <= dice_value;
      end
    end
  end

endmodule

input.rtl/digital_dice_roller.sv:
module digital_dice_roller #(
    parameter int DICE_MAX  = 6,                    // Maximum dice value
    parameter int BIT_WIDTH = $clog2(DICE_MAX) + 1  // Bit width to represent dice value
) (
    input wire clk,
    input wire reset,  // Asynchronous reset signal
    input wire button,
    output reg [BIT_WIDTH-1:0] dice_value
);

  // State encoding
  typedef enum logic [1:0] {
    IDLE    = 2'b00,
    ROLLING = 2'b01
  } state_t;

  state_t current_state, next_state;
  reg [BIT_WIDTH-1:0] counter;  // Counter to represent dice values

  // State transition and asynchronous reset logic (sequential)
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset to initial values when async_reset is asserted
      current_state <= IDLE;
      counter <= 1;
      dice_value <= 1;
    end else begin
      current_state <= next_state;
    end
  end

  // Next state logic and counter increment (combinational)
  always_comb begin
    next_state = current_state;

    case (current_state)
      IDLE: begin
        if (button) next_state = ROLLING;
      end

      ROLLING: begin
        if (!button) next_state = IDLE;
      end
    endcase
  end

  // Counter logic to simulate rolling dice values from 1 to DICE_MAX
  always_ff @(posedge clk or negedge reset) begin
    if (!reset) begin
      // Reset counter and dice value when async_reset is asserted
      counter <= 1;
      dice_value <= 1;
    end else if (current_state == ROLLING) begin
      if (counter == DICE_MAX) counter <= 1;  // Reset to 1 after reaching DICE_MAX
      else counter <= counter + 1;
    end else if (current_state == IDLE) begin
      dice_value <= counter;  // Latch the final value
    end
  end
endmodule

