output.rtl/dig_stopwatch.sv:
module dig_stopwatch #(
    parameter integer CLK_FREQ = 50000000
) (
    input  logic clk,
    input  logic reset,
    input  logic start_stop,
    output logic [5:0] seconds,
    output logic [5:0] minutes,
    output logic hour
);

  // Internal registers for clock division
  // clk_div_counter counts clock cycles to generate a one-second pulse.
  logic [31:0] clk_div_counter;
  logic sec_pulse;

  // Synchronous process with asynchronous reset
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      clk_div_counter <= 32'd0;
      sec_pulse       <= 1'd0;
      seconds         <= 6'd0;
      minutes         <= 6'd0;
      hour            <= 1'd0;
    end
    else begin
      // Clock divider: generate a one-cycle pulse every CLK_FREQ cycles.
      if (clk_div_counter == CLK_FREQ - 1) begin
        clk_div_counter <= 32'd0;
        sec_pulse       <= 1'd1;
      end
      else begin
        clk_div_counter <= clk_div_counter + 1;
        sec_pulse       <= 1'd0;
      end

      // Update stopwatch counters on the rising edge of the one-second pulse,
      // but only if the stopwatch is running and not already at one hour.
      if (sec_pulse && start_stop && (hour != 1)) begin
        seconds <= seconds + 1;
        if (seconds == 6'd60) begin
          seconds <= 6'd0;
          minutes <= minutes + 1;
          if (minutes == 6'd60) begin
            minutes <= 6'd0;
            hour    <= 1'd1;
          end
        end
      end
    end
  end

endmodule

input.rtl/dig_stopwatch.sv:
module dig_stopwatch #(
    parameter CLK_FREQ = 50000000  // Default clock frequency is 50 MHz
)(
    input wire clk,                // Input clock (parameterized frequency)
    input wire reset,              // Reset signal
    input wire start_stop,         // Start/Stop control
    output reg [5:0] seconds,      // Seconds counter (0-59)
    output reg [5:0] minutes,      // Minutes counter (0-59)
    output reg hour                // Hour counter 
);

    localparam COUNTER_MAX = CLK_FREQ - 1;  // Calculate max counter value
    reg [$clog2(COUNTER_MAX):0] counter;    // Clock divider counter width based on CLK_FREQ
    reg one_sec_pulse;                      // One second pulse signal

    // Clock divider to create a 1 Hz clock pulse from parameterized frequency
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            counter <= 0;
            one_sec_pulse <= 0;
        end else begin
            if (start_stop) begin
                if (counter == COUNTER_MAX) begin
                    counter <= 0;
                    one_sec_pulse <= 1'b1;        // Generate a pulse every second
                end else begin
                    counter <= counter + 1;
                    one_sec_pulse <= 1'b0;
                end
            end else begin
                one_sec_pulse <= 1'b0;           // Ensure one_sec_pulse is cleared if paused
            end
        end
    end

    // Stopwatch logic
    always @(posedge one_sec_pulse or posedge reset) begin
        if (reset) begin
            seconds <= 6'b0;
            minutes <= 6'b0;
            hour <= 1'b0;
        end else if (start_stop == 1 && hour == 0) begin
            if (seconds < 59) begin
                seconds <= seconds + 1'b1;
            end else begin
                seconds <= 6'b0;
                if (minutes < 59) begin
                    minutes <= minutes + 1'b1;
                end else begin
                    minutes <= 6'b0;
                    hour <= 1'b1;
                end
            end
        end
    end

endmodule

