      max_request <= {[$clog2(N){1'b0}};
      min_request <= N-1;
      integer i;
      for (i = 0; i < N; i = i + 1) begin
        if (call_requests_internal[i]) begin
          if (i > max_request)
            max_request <= i;
          if (i < min_request)
            min_request <= i;
        end
      end
    end
  end

