  always @(*) begin
    next_state      = present_state;
    current_floor_next = current_floor_reg;
    case (present_state)
      IDLE: begin
        if (overload_detected)
          next_state = OVERLOAD_HALT;
        else if (emergency_stop)
          next_state = EMERGENCY_HALT;
        else if (call_requests_internal != 0) begin
