    current_floor_next = current_floor_reg;

    case(present_state)
        IDLE:begin
            if(overload_detected) begin
                next_state = OVERLOAD_HALT;
            end else if(emergency_stop) begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal != 0)begin
                if(max_request > current_floor_reg)begin
                    next_state = MOVING_UP;
                end else if(min_request < current_floor_reg) begin
                    next_state = MOVING_DOWN;
                end
            end
        end

        MOVING_UP: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg+1]) begin
                current_floor_next = current_floor_reg + 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg >= max_request) begin
                // If we reach the highest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg + 1;
                next_state = MOVING_UP;
            end
        end

        MOVING_DOWN: begin
            if(emergency_stop)begin
                next_state = EMERGENCY_HALT;
            end else if(call_requests_internal[current_floor_reg-1]) begin
                current_floor_next = current_floor_reg - 1;
                next_state = DOOR_OPEN;
            end else if(current_floor_reg <= min_request) begin
                // If we reach the lowest request, go idle
                next_state = IDLE;
            end else begin
                current_floor_next = current_floor_reg - 1;
                next_state = MOVING_DOWN;
            end
        end

        EMERGENCY_HALT: begin
            if (!emergency_stop) begin
                next_state = IDLE;
                current_floor_next = 0; // Optionally reset to ground floor
            end
        end

        DOOR_OPEN: begin
            if(overload_detected) begin
                next_state = OVERLOAD_HALT;
            end else if (door_open_counter == 0) begin
                next_state = IDLE;
            end else begin
                next_state = DOOR_OPEN;
            end
        end

        OVERLOAD_HALT: begin
            if(!overload_detected) begin
                if(door_open) begin
                    next_state = DOOR_OPEN;
                end else begin
                    next_state = IDLE;
                end
            end
        end
    endcase
end


// Door open control logic
always @(posedge clk or posedge reset) begin
    if (reset) begin
        door_open <= 0;
    end else begin
        if (present_state == OVERLOAD_HALT) begin
            door_open <= 1;
        end else if (present_state == DOOR_OPEN) begin
            if (door_open_counter > 0) begin
                door_open <= 1;
            end else begin
                door_open <= 0;
            end
        end else begin
            door_open <= 0;
        end
    end
end


always@(*) begin
    if(present_state == OVERLOAD_HALT) begin
        door_open <= 1;
    end else if(present_state == DOOR_OPEN) begin
        door_open <= 1;
    end else begin
        door_open <= 0;
    end
end


always @(posedge clk or posedge reset) begin
    if(reset) begin
        door_open_counter <= DOOR_OPEN_CYCLES;
    end else if( present_state == DOOR_OPEN) begin
        if(door_open_counter > 0 ) begin
            door_open_counter = door_open_counter - 1;
        end else begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end
    end else begin
        door_open_counter <= DOOR_OPEN_CYCLES;
    end

end


// Call request management
always@(*)begin
    if(reset) begin
        call_requests_internal = 0;
    end else begin
        if(call_requests_internal[current_floor_reg])begin
            call_requests_internal[current_floor_reg] = 0;      // Clear served request
        end
        call_requests_internal = call_requests_internal | call_requests;    // Update requests
    end
end

// Direction control logic
always@(*)begin
    if(reset) begin
        direction = 1;
    end else begin
        if(present_state == MOVING_UP)begin
            direction = 1;
        end else if (present_state == MOVING_DOWN) begin
            direction = 0;
        end else begin
            direction = 1;
        end
    end
end


// Seven-segment display converter instantiation
floor_to_seven_segment floor_display_converter (
    .clk(clk),
    .floor_display({{8-($clog2(N)){1'b0}},current_floor_reg}),
    .seven_seg_out(seven_seg_out),
    .seven_seg_out_anode(seven_seg_out_anode),
    .thousand(thousand), .hundred(hundred),.ten(ten),.one(one)
);

endmodule

output.rtl/elevator_control_system.sv:
module elevator_control_system #(
    parameter N = 8,           // Number of floors
    parameter DOOR_OPEN_TIME_MS = 500 // Door open time in milliseconds
) ( 
    input wire clk,                   // 100MHz clock input
    input wire reset,                 // Active-high reset signal
    input wire [N-1:0] call_requests, // External Floor call requests
    input wire emergency_stop,        // Emergency stop signal
    input wire overload_detected,
    output wire [$clog2(N)-1:0] current_floor, // Current floor of the elevator
    output reg direction,             // Elevator direction: 1 = up, 0 = down
    output reg door_open,             // Door open signal
    output reg [2:0] system_status,    // Elevator system state indicator
    output overload_warning,          // Overload warning signal
    output [3:0] thousand,
    output [3:0] hundred, 
    output [3:0] ten, 
    output [3:0] one,
    output wire [6:0] seven_seg_out,    // Seven-segment display output for current floor visualization
    output wire [3:0] seven_seg_out_anode // Signal for switching between ones, tens, hundred, thousand place on seven segment
);

    // State Encoding
    localparam IDLE          = 3'b000; // Elevator is idle
    localparam MOVING_UP     = 3'b001; // Elevator moving up
    localparam MOVING_DOWN   = 3'b010; // Elevator moving down
    localparam EMERGENCY_HALT= 3'b011; // Emergency halt state
    localparam DOOR_OPEN     = 3'b100; // Door open state
    localparam OVERLOAD_HALT = 3'b101; // Overload condition state

    // Internal registers
    reg [N-1:0] call_requests_internal;   // Internal copy of call requests
    reg [2:0] present_state, next_state;   // FSM current and next states
    reg [$clog2(N)-1:0] max_request;       // Highest requested floor
    reg [$clog2(N)-1:0] min_request;        // Lowest requested floor

    // Door open time configuration
    `ifdef SIMULATION
        localparam CLK_FREQ_MHZ = 100;  // Clock frequency in MHz
        localparam SIM_DOOR_OPEN_TIME_MS = 0.05; // Shorter door open time for simulation
        localparam DOOR_OPEN_CYCLES = (SIM_DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000); // Door open cycles for simulation   
    `else
        // Calculating door open cycles based on time and clock frequency
        localparam CLK_FREQ_MHZ = 100;  // Clock frequency in MHz
        localparam DOOR_OPEN_CYCLES = (DOOR_OPEN_TIME_MS * CLK_FREQ_MHZ * 1000);   // Door open cycles for real implementation
    `endif

    reg [$clog2(DOOR_OPEN_CYCLES)-1:0] door_open_counter; // Counter for door open duration

    reg [$clog2(N)-1:0] current_floor_reg, current_floor_next;
    assign current_floor = current_floor_reg;

    // Update overload warning signal
    assign overload_warning = (overload_detected && present_state == OVERLOAD_HALT);

    // FSM state transition (using non-blocking assignments)
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            present_state   <= IDLE;
            system_status   <= IDLE;
            current_floor_reg <= 0;        
        end else begin
            present_state   <= next_state;
            system_status   <= next_state;
            current_floor_reg <= current_floor_next;
        end
    end

    // Compute max and min request (combinational logic without reset branch)
    always @(*) begin
        max_request = 0;
        min_request = {$clog2(N){1'b1}};
        for (integer i = 0; i < N; i = i + 1) begin
            if (call_requests_internal[i]) begin
                if (i > max_request)
                    max_request = i[$clog2(N)-1:0];
                if (i < min_request)
                    min_request = i[$clog2(N)-1:0];
            end
        end
    end

    // FSM next state logic with complete case coverage
    always @(*) begin
        next_state = present_state;
        current_floor_next = current_floor_reg;

        case(present_state)
            IDLE: begin
                if (overload_detected) begin
                    next_state = OVERLOAD_HALT;
                end else if (emergency_stop) begin
                    next_state = EMERGENCY_HALT;
                end else if (call_requests_internal != 0) begin
                    if (max_request > current_floor_reg)
                        next_state = MOVING_UP;
                    else if (min_request < current_floor_reg)
                        next_state = MOVING_DOWN;
                end
            end

            MOVING_UP: begin
                if (emergency_stop) begin
                    next_state = EMERGENCY_HALT;
                end else if (call_requests_internal[current_floor_reg+1]) begin
                    current_floor_next = current_floor_reg + 1;
                    next_state = DOOR_OPEN;
                end else if (current_floor_reg >= max_request) begin
                    next_state = IDLE;
                end else begin
                    current_floor_next = current_floor_reg + 1;
                    next_state = MOVING_UP;
                end
            end

            MOVING_DOWN: begin
                if (emergency_stop) begin
                    next_state = EMERGENCY_HALT;
                end else if (call_requests_internal[current_floor_reg-1]) begin
                    current_floor_next = current_floor_reg - 1;
                    next_state = DOOR_OPEN;
                end else if (current_floor_reg <= min_request) begin
                    next_state = IDLE;
                end else begin
                    current_floor_next = current_floor_reg - 1;
                    next_state = MOVING_DOWN;
                end
            end

            EMERGENCY_HALT: begin
                if (!emergency_stop) begin
                    next_state = IDLE;
                    current_floor_next = 0; // Optionally reset to ground floor
                end
            end

            DOOR_OPEN: begin
                if (overload_detected) begin
                    next_state = OVERLOAD_HALT;
                end else if (door_open_counter == 0) begin
                    next_state = IDLE;
                end else begin
                    next_state = DOOR_OPEN;
                end
            end

            OVERLOAD_HALT: begin
                if (!overload_detected) begin
                    if (door_open)
                        next_state = DOOR_OPEN;
                    else
                        next_state = IDLE;
                end
            end

            default: begin
                next_state = present_state;
                current_floor_next = current_floor_reg;
            end
        endcase
    end

    // Door open control logic (only one sequential always block drives door_open)
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            door_open <= 0;
        end else begin
            if (present_state == OVERLOAD_HALT)
                door_open <= 1;
            else if (present_state == DOOR_OPEN) begin
                if (door_open_counter > 0)
                    door_open <= 1;
                else
                    door_open <= 0;
            end else begin
                door_open <= 0;
            end
        end
    end

    // Door open counter logic using non-blocking assignment
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end else if (present_state == DOOR_OPEN) begin
            if (door_open_counter > 0)
                door_open_counter <= door_open_counter - 1;
            else
                door_open_counter <= DOOR_OPEN_CYCLES;
        end else begin
            door_open_counter <= DOOR_OPEN_CYCLES;
        end
    end

    // Synchronous update for call_requests_internal (converted from combinational to clocked)
    always @(posedge clk or posedge reset) begin
        if (reset)
            call_requests_internal <= 0;
        else begin
            // Merge new call requests
            call_requests_internal <= call_requests_internal | call_requests;
            // Clear the served request
            if (call_requests_internal[current_floor_reg])
                call_requests_internal[current_floor_reg] <= 0;
        end
    end

    // Direction control logic
    always @(*) begin
        if (reset)
            direction = 1;
        else begin
            if (present_state == MOVING_UP)
                direction = 1;
            else if (present_state == MOVING_DOWN)
                direction = 0;
            else
                direction = 1;
        end
    end

    // Seven-segment display converter instantiation
    floor_to_seven_segment floor_display_converter (
        .clk(clk),
        .floor_display({{8-($clog2(N)){1'b0}}, current_floor_reg}),
        .seven_seg_out(seven_seg_out),
        .seven_seg_out_anode(seven_seg_out_anode),
        .thousand(thousand),
        .hundred(hundred),
        .ten(ten),
        .one(one)
    );

endmodule

output.rtl/ethernet_parser.v:
module ethernet_parser(
    input         clk,
    input         rst,
    input         vld,
    input         sof,
    input  [31:0] data,
    input         eof,
    output reg    ack,
    output reg [15:0] field,
    output reg    field_vld
);

  // State encoding
  localparam [1:0] IDLE       = 2'b00;
  localparam [1:0] EXTRACTING = 2'b01;
  localparam [1:0] DONE       = 2'b10;
  localparam [1:0] FAIL_FINAL = 2'b11;

  reg [1:0] state;
  reg [3:0] beat_cnt;
  reg [15:0] temp_extracted_field;

  // Synchronous state machine
  always @(posedge clk) begin
    if (rst) begin
      state            <= IDLE;
      beat_cnt         <= 4'd0;
      temp_extracted_field <= 16'd0;
      field            <= 16'd0;
      field_vld        <= 1'b0;
    end else begin
      case (state)
        IDLE: begin
          if (sof && vld) begin
            state            <= EXTRACTING;
            beat_cnt         <= 4'd0;
          end else begin
            state            <= IDLE;
          end
        end

        EXTRACTING: begin
          if (eof) begin
            state <= FAIL_FINAL;
          end else if (vld) begin
            if (beat_cnt == 4'd0) begin
              // On the first beat (starting from 0), the next beat (beat_cnt becomes 1)
              // is the 2nd beat. Capture the upper 16 bits.
              beat_cnt         <= 4'd1;
              temp_extracted_field <= data[31:16];
              state            <= DONE;
            end else begin
              beat_cnt <= beat_cnt + 1;
            end
          end else begin
            state <= EXTRACTING;
          end
        end

        DONE: begin
          if (eof) begin
            state <= FAIL_FINAL;
          end else begin
            state <= DONE;
          end
        end

        FAIL_FINAL: begin
          state <= IDLE;
        end

        default: state <= IDLE;
      endcase
    end
  end

  // The ack signal is always high.
  always @(*) begin
    ack = 1'b1;
  end

  // Drive the field output and its valid flag.
  // Once extraction is complete in DONE state, field holds the captured value and field_vld is asserted.
  always @(*) begin
    if (state == DONE)
      field = temp_extracted_field;
    else
      field = 16'd0;
    field_vld = (state == DONE);
  end

endmodule

output.rtl/apb_controller.sv:
module apb_controller (
    input  logic         clk,
    input  logic         reset_n,
    input  logic         select_a_i,
    input  logic         select_b_i,
    input  logic         select_c_i,
    input  logic [31:0]  addr_a_i,
    input  logic [31:0]  data_a_i,
    input  logic [31:0]  addr_b_i,
    input  logic [31:0]  data_b_i,
    input  logic [31:0]  addr_c_i,
    input  logic [31:0]  data_c_i,
    input  logic         apb_pready_i,
    output reg           apb_psel_o,
    output reg           apb_penable_o,
    output reg           apb_pwrite_o,
    output reg [31:0]    apb_paddr_o,
    output reg [31:0]    apb_pwdata_o
);

  // State encoding
  localparam IDLE   = 2'b00;
  localparam SETUP  = 2'b01;
  localparam ACCESS = 2'b10;

  reg [1:0] state, next_state;
  reg [31:0] captured_addr;
  reg [31:0] captured_data;
  reg [3:0]  timeout_counter;

  // Sequential logic: state register, capture registers, and timeout counter
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      state            <= IDLE;
      captured_addr    <= 32'b0;
      captured_data    <= 32'b0;
      timeout_counter  <= 4'b0;
    end else begin
      state <= next_state;

      // In IDLE state, capture the address and data if an event is triggered.
      if (state == IDLE) begin
        if (select_a_i) begin
          captured_addr <= addr_a_i;
          captured_data <= data_a_i;
        end else if (select_b_i) begin
          captured_addr <= addr_b_i;
          captured_data <= data_b_i;
        end else if (select_c_i) begin
          captured_addr <= addr_c_i;
          captured_data <= data_c_i;
        end
      end

      // In ACCESS state, update the timeout counter if the peripheral is not ready.
      if (state == ACCESS) begin
        if (!apb_pready_i)
          timeout_counter <= timeout_counter + 1;
        else
          timeout_counter <= 4'b0;
      end
    end
  end

  // Combinational logic: next state and output logic
  always_comb begin
    // Default assignments
    next_state        = state; // Default: remain in the same state
    apb_psel_o        = 1'b0;
    apb_penable_o     = 1'b0;
    apb_pwrite_o      = 1'b0;
    apb_paddr_o       = 32'b0;
    apb_pwdata_o      = 32'b0;

    case (state)
      IDLE: begin
        // If any event is triggered, prioritize select_a_i, then select_b_i, then select_c_i.
        if (select_a_i || select_b_i || select_c_i) begin
          // Transition to SETUP state; capture occurs in the sequential block.
          next_state = SETUP;
        end else begin
          next_state = IDLE;
        end
      end

      SETUP: begin
        // Assert APB signals for write transaction.
        apb_psel_o    = 1'b1;
        apb_pwrite_o  = 1'b1;
        apb_paddr_o   = captured_addr;
        apb_pwdata_o  = captured_data;
        // apb_penable_o remains deasserted in SETUP.
        next_state = ACCESS;
      end

      ACCESS: begin
        // Assert APB enable signal during ACCESS phase.
        apb_psel_o    = 1'b1;
        apb_pwrite_o  = 1'b1;
        apb_paddr_o   = captured_addr;
        apb_pwdata_o  = captured_data;
        apb_penable_o = 1'b1;

        // Check for transaction completion or timeout.
        if (apb_pready_i) begin
          // Peripheral is ready: complete the transaction.
          next_state = IDLE;
        end else if (timeout_counter >= 15) begin
          // Timeout reached: abort the transaction and return to IDLE.
          next_state = IDLE;
        end else begin
          // Remain in ACCESS state waiting for the peripheral.
          next_state = ACCESS;
        end
      end

      default: next_state = IDLE;
    endcase
  end

endmodule

output.rtl/factorial.sv:
module factorial(
    input  logic         clk,
    input  logic         arst_n,
    input  logic [4:0]   num_in,
    input  logic         start,
    output logic         busy,
    output logic         done,
    output logic [63:0]  fact
);

  // FSM state encoding: IDLE, BUSY, DONE
  typedef enum logic [1:0] {
    IDLE = 2'b00,
    BUSY = 2'b01,
    DONE = 2'b10
  } state_t;

  state_t state, next_state;

  // Internal registers to hold the captured input, product, and iteration counter
  logic [4:0] n_reg;       // Captured input number
  logic [63:0] product;    // Running product for factorial computation
  logic [4:0] counter;     // Iteration counter

  // Output assignments: busy is high in BUSY state, done is high in DONE state.
  // fact is valid only in DONE state; otherwise it is 0.
  always_comb begin
    busy = (state == BUSY);
    done = (state == DONE);
    if (state == DONE)
      fact = product;
    else
      fact = 64'd0;
  end

  // FSM sequential process with asynchronous active low reset
  always_ff @(posedge clk or negedge arst_n) begin
    if (!arst_n) begin
      state         <= IDLE;
      n_reg         <= 5'd0;
      product       <= 64'd1;
      counter       <= 5'd0;
      // busy and done are driven by the state combinational logic
    end else begin
      case (state)
        IDLE: begin
          // Accept new input only if start is asserted and design is not busy.
          if (start && !busy) begin
            n_reg     <= num_in;   // Capture the input number
            product   <= 64'd1;    // Initialize product to 1
            counter   <= 5'd0;     // Start counter at 0
            state     <= BUSY;     // Transition to BUSY state
          end else begin
            state <= IDLE;
          end
        end

        BUSY: begin
          // Perform one multiplication per cycle.
          // Multiply product by (counter + 1) and increment counter.
          if (counter < n_reg) begin
            product   <= product * (counter + 1);
            counter   <= counter + 1;
            state     <= BUSY;
          end else begin
            state <= DONE;  // All iterations done; move to DONE state.
          end
        end

        DONE: begin
          // In DONE state, fact is output (see combinational block).
          // Then clear internal registers and return to IDLE.
          state     <= IDLE;
          product   <= 64'd1;
          counter   <= 5'd0;
          n_reg     <= 5'd0;
        end

        default: state <= IDLE;
      endcase
    end
  end

endmodule

output.rtl/fan_controller.sv:
module fan_controller (
    input  wire         clk,                 // System clock
    input  wire         reset,               // Reset signal
    output reg          fan_pwm_out,         // PWM output for fan control

    // APB signals
    input  wire         psel,                // Slave select
    input  wire         penable,             // Enable signal
    input  wire         pwrite,              // Write control
    input  wire [7:0]   paddr,               // Address bus
    input  wire [7:0]   pwdata,              // Write data bus
    output reg  [7:0]   prdata,              // Read data bus
    output reg          pready,              // Ready signal
    output reg          pslverr              // Slave error
);

  //-------------------------------------------------------------------------
  // Internal registers for temperature thresholds and sensor data
  //-------------------------------------------------------------------------
  reg [7:0] TEMP_LOW;    // Maximum temperature for low category
  reg [7:0] TEMP_MED;    // Maximum temperature for medium category
  reg [7:0] TEMP_HIGH;   // Maximum temperature for high category
  reg [7:0] temp_adc_in; // Simulated ADC input for current temperature

  //-------------------------------------------------------------------------
  // PWM counter for generating PWM signal
  // The counter period is fixed at 256 clock cycles.
  //-------------------------------------------------------------------------
  reg [7:0] pwm_counter;

  //-------------------------------------------------------------------------
  // APB Interface: Implement AMBA APB protocol with setup and access phases.
  // - Setup Phase: psel is asserted while penable is deasserted.
  // - Access Phase: Both psel and penable are asserted.
  // During the access phase, the module performs read/write operations
  // based on paddr and asserts pready upon completion. If an invalid address
  // is accessed, pslverr is asserted.
  //-------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      // Reset all registers and status signals to default values.
      TEMP_LOW    <= 8'd0;
      TEMP_MED    <= 8'd0;
      TEMP_HIGH   <= 8'd0;
      temp_adc_in <= 8'd0;
      pready      <= 1'b0;
      pslverr     <= 1'b0;
    end else begin
      // Default: clear status signals.
      pready   <= 1'b0;
      pslverr  <= 1'b0;

      if (psel) begin
        if (penable) begin
          // Access phase: perform the requested operation.
          case (paddr)
            8'h0a: begin // TEMP_LOW register
              if (pwrite)
                TEMP_LOW <= pwdata;
              else
                prdata  <= TEMP_LOW;
            end
            8'h0b: begin // TEMP_MED register
              if (pwrite)
                TEMP_MED <= pwdata;
              else
                prdata  <= TEMP_MED;
            end
            8'h0c: begin // TEMP_HIGH register
              if (pwrite)
                TEMP_HIGH <= pwdata;
              else
                prdata  <= TEMP_HIGH;
            end
            8'h0f: begin // temp_adc_in register (simulated sensor data)
              if (pwrite)
                temp_adc_in <= pwdata;
              else
                prdata  <= temp_adc_in;
            end
            default: begin
              // Invalid address access; assert error signal.
              pslverr <= 1'b1;
            end
          endcase
          pready <= 1'b1; // Indicate transaction complete.
        end
        // Setup phase: psel asserted but penable not asserted; no operation.
      end
      // If module is not selected (psel=0), status signals remain cleared.
    end
  end

  //-------------------------------------------------------------------------
  // PWM Signal Generation: Dynamically adjust fan speed based on temperature.
  // Duty cycle selection based on temp_adc_in and threshold registers:
  //   • Below TEMP_LOW: 25% duty cycle (counter < 64)
  //   • Between TEMP_LOW and TEMP_MED: 50% duty cycle (counter < 128)
  //   • Between TEMP_MED and TEMP_HIGH: 75% duty cycle (counter < 192)
  //   • Above TEMP_HIGH: 100% duty cycle (counter < 255)
  // The PWM counter runs from 0 to 255 (256 clock cycles period).
  //-------------------------------------------------------------------------
  always @(posedge clk or posedge reset) begin
    if (reset) begin
      pwm_counter   <= 8'd0;
      fan_pwm_out   <= 1'b0;
    end else begin
      // Update PWM counter; reset to 0 after reaching 255.
      if (pwm_counter == 8'd255)
        pwm_counter <= 8'd0;
      else
        pwm_counter <= pwm_counter + 1;

      // Generate PWM signal based on current temperature reading.
      if (temp_adc_in < TEMP_LOW)
        fan_pwm_out <= (pwm_counter < 8'd64);
      else if (temp_adc_in < TEMP_MED)
        fan_pwm_out <= (pwm_counter < 8'd128);
      else if (temp_adc_in < TEMP_HIGH)
        fan_pwm_out <= (pwm_counter < 8'd192);
      else
        fan_pwm_out <= (pwm_counter < 8'd255);
    end
  end

endmodule

