module FindFasterClock(
    input  wire clk_A,
    input  wire clk_B,
    input  wire rst_n,            // Active-low reset
    output reg  A_faster_than_B,  // 1 if clk_A is measured faster
    output reg  valid             // 1 once both clocks have measured a period
);

    // Internal signals
    reg        measure_B;          
    reg [31:0] b_count;            
    reg [31:0] periodA;            
    reg        done_A;             
    reg        measure_A;
    reg [31:0] a_count;
    reg [31:0] periodB;            
    reg        done_B;

    // A-domain FSM for measuring "periodA"
    reg [1:0] stateA;  
    localparam A_IDLE    = 2'd0,
               A_COUNT   = 2'd1,
               A_DONE    = 2'd2;
    // B-domain FSM for measuring "periodB"
    reg [1:0] stateB;
    localparam B_IDLE    = 2'd0,
               B_COUNT   = 2'd1,
               B_DONE    = 2'd2;

    // Clock A FSM
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            stateA      <= A_IDLE;
            measure_B   <= 0;
            b_count     <= 0;
            periodA     <= 0;
            done_A      <= 0;
        end else begin
            case (stateA)
                A_IDLE: begin
                    // Start measurement: enable counting in B-domain
                    measure_B <= 1;
                    b_count   <= 0;
                    periodA   <= 0;
                    done_A    <= 0;
                    stateA    <= A_COUNT;
                end
                A_COUNT: begin
                    // Capture the count from B-domain and mark measurement complete
                    periodA   <= b_count;
                    done_A    <= 1;
                    measure_B <= 0;  // Disable further counting in B-domain
                    stateA    <= A_DONE;
                end
                A_DONE: begin
                    // Remain in DONE state (one-shot measurement)
                    stateA    <= A_DONE;
                end
                default: stateA <= A_IDLE;
            endcase
        end
    end

    // Clock B FSM
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            stateB      <= B_IDLE;
            measure_A   <= 0;
            a_count     <= 0;
            periodB     <= 0;
            done_B      <= 0;
        end else begin
            case (stateB)
                B_IDLE: begin
                    // Start measurement: enable counting in A-domain
                    measure_A <= 1;
                    a_count   <= 0;
                    periodB   <= 0;
                    done_B    <= 0;
                    stateB    <= B_COUNT;
                end
                B_COUNT: begin
                    // Capture the count from A-domain and mark measurement complete
                    periodB   <= a_count;
                    done_B    <= 1;
                    measure_A <= 0;  // Disable further counting in A-domain
                    stateB    <= B_DONE;
                end
                B_DONE: begin
                    // Remain in DONE state (one-shot measurement)
                    stateB    <= B_DONE;
                end
                default: stateB <= B_IDLE;
            endcase
        end
    end

    // In B-domain, if measure_B=1, increment b_count on each B rising edge
    always @(posedge clk_B or negedge rst_n) begin
        if (!rst_n) begin
            b_count <= 0;
        end else if (measure_B) begin
            b_count <= b_count + 1;
        end
    end

    // In A-domain, if measure_A=1, increment a_count on each A rising edge
    always @(posedge clk_A or negedge rst_n) begin
        if (!rst_n) begin
            a_count <= 0;
        end else if (measure_A) begin
            a_count <= a_count + 1;
        end
    end

    // Combine results: valid is asserted when both measurements are complete.
    // If periodB > periodA then clk_A is faster, so set A_faster_than_B to 1.
    always @(*) begin
        if (!rst_n) begin
            valid             = 0;
            A_faster_than_B  = 0;
        end else begin
            valid = (done_A && done_B);
            if (valid) begin
                if (periodB > periodA)
                    A_faster_than_B = 1;
                else
                    A_faster_than_B = 0;
            end else begin
                A_faster_than_B = 0;
            end
        end
    end

endmodule

