////////////////////////////////////////////////
module reg18 (
    input  logic        clk,
    input  logic        reset,
    input  logic [17:0] data_in,
    output logic [17:0] data_out
);
    always_ff @(posedge clk) begin
        if (reset) 
            data_out <= 18'd0;
        else
            data_out <= data_in;
    end
endmodule

