         A_ff  <= 'b0;
         B_ff  <= 'b0;
         k_ff  <= 'b0;
         OUT_ff <= 'b0;
      end else begin
         A_ff  <= next_A_ff;
         B_ff  <= next_B_ff;
         k_ff  <= next_k_ff;
         OUT_ff <= next_OUT;
      end
   end

   // OUT is driven from register
   assign OUT = OUT_ff;

endmodule


// Control Path for Stein's Algorithm GCD
module gcd_controlpath (
   input                    clk,
   input                    rst,
   input                    go,
   input                    equal,
   output logic [1:0]       controlpath_state,
   output logic             done
);
   localparam S0 = 2'd0;
   localparam S1 = 2'd1;
   localparam S2 = 2'd2;

   logic [1:0] curr_state, next_state;

   // Combinational next state logic
   always_comb begin
      next_state = curr_state;
      case (curr_state)
         S0: begin
            if (!go) 
               next_state = S0;
            else 
               // After loading, we go to processing step
               next_state = S2;
         end
         S1: begin
            // Done state, return to idle
            next_state = S0;
         end
         S2: begin
            // While processing, if equal => done
            if (equal) 
               next_state = S1;
            else
               next_state = S2; // continue processing
         end
         default: begin
            next_state = S0;
         end
      endcase
   end

   // Sequential state update
   always_ff @(posedge clk) begin
      if (rst)
         curr_state <= S0;
      else
         curr_state <= next_state;
   end

   // Done signal
   always_ff @(posedge clk) begin
      if (rst)
         done <= 1'b0;
      else
         done <= (curr_state == S1);
   end

   assign controlpath_state = curr_state;

endmodule

