module generic_counter #(parameter N = 8) (
    input  logic         clk_in,          // Clock input
    input  logic         rst_in,          // Active HIGH Reset input (synchronous)
    input  logic [2:0]   mode_in,         // Mode input (3 bits)
    input  logic         enable_in,       // Enable input
    input  logic [N-1:0] ref_modulo,      // Reference modulo value for Modulo-N counter
    output logic [N-1:0] o_count          // Output count (N bits)
);

    parameter BINARY_UP   = 3'b000;
    parameter BINARY_DOWN = 3'b001;
    parameter MODULO_N    = 3'b010;
    parameter JOHNSON     = 3'b011;
    parameter GRAY        = 3'b100;
    parameter RING        = 3'b101;

    logic [N-1:0] count_mux;
    logic [N-1:0] count_bin_up;
    logic [N-1:0] count_bin_down;
    logic [N-1:0] count_modulo;
    logic [N-1:0] count_johnson;
    logic [N-1:0] count_gray;
    logic [N-1:0] count_ring;

    // BINARY_UP count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_bin_up <= {N{1'b0}};
        else if (enable_in)
            count_bin_up <= count_bin_up + 1;
        else
            count_bin_up <= count_bin_up;
    end

    // BINARY_DOWN count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_bin_down <= {N{1'b0}};
        else if (enable_in)
            count_bin_down <= count_bin_down - 1;
        else
            count_bin_down <= count_bin_down;
    end

    // MODULO_N count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_modulo <= {N{1'b0}};
        else if (enable_in) begin
            if (count_modulo == ref_modulo)
                count_modulo <= {N{1'b0}};
            else
                count_modulo <= count_modulo + 1;
        end else
            count_modulo <= count_modulo;
    end

    // JOHNSON count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_johnson <= {N{1'b0}};
        else if (enable_in)
            count_johnson <= {~count_johnson[0], count_johnson[N-1:1]};
        else
            count_johnson <= count_johnson;
    end

    // GRAY count logic (internal count)
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_gray <= {N{1'b0}};
        else if (enable_in)
            count_gray <= count_gray + 1;
        else
            count_gray <= count_gray;
    end

    // RING count logic
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count_ring <= {N{1'b0}};
        else if (enable_in) begin
            if (count_ring == {N{1'b0}})
                count_ring <= {{(N-1){1'b0}}, 1'b1};
            else
                count_ring <= {count_ring[N-2:0], count_ring[N-1]};
        end else
            count_ring <= count_ring;
    end

    // Multiplexer to select the count based on mode_in
    always_comb begin
        case (mode_in)
            BINARY_UP:   count_mux = count_bin_up;
            BINARY_DOWN: count_mux = count_bin_down;
            MODULO_N:    count_mux = count_modulo;
            JOHNSON:     count_mux = count_johnson;
            GRAY:        count_mux = count_gray;
            RING:        count_mux = count_ring;
            default:     count_mux = {N{1'b0}};
        endcase
    end

    assign o_count = (mode_in == GRAY) ? (count_mux ^ (count_mux >> 1)) : count_mux;

endmodule

output.rtl/generic_counter.sv:
module generic_counter #(parameter N = 8) (
    input  logic         clk_in,          // Clock input
    input  logic         rst_in,          // Active HIGH Reset input (synchronous)
    input  logic [2:0]   mode_in,         // Mode input (3 bits)
    input  logic         enable_in,       // Enable input
    input  logic [N-1:0] ref_modulo,      // Reference modulo value for Modulo-N counter
    output logic [N-1:0] o_count          // Output count (N bits)
);

    // Mode parameters
    parameter BINARY_UP   = 3'b000;
    parameter BINARY_DOWN = 3'b001;
    parameter MODULO_N    = 3'b010;
    parameter JOHNSON     = 3'b011;
    parameter GRAY        = 3'b100;
    parameter RING        = 3'b101;

    // Single register for all counter modes
    logic [N-1:0] count;

    // Single always_ff block to update the counter based on mode
    always_ff @(posedge clk_in) begin
        if (rst_in)
            count <= '0;
        else if (enable_in)
            case (mode_in)
                BINARY_UP:   count <= count + 1;
                BINARY_DOWN: count <= count - 1;
                MODULO_N:    count <= (count == ref_modulo) ? '0 : count + 1;
                JOHNSON:     count <= {~count[0], count[N-1:1]};
                RING:        count <= (count == '0) ? { {(N-1){1'b0}}, 1'b1 } : {count[N-2:0], count[N-1]};
                default:     count <= count;
            endcase
    end

    // Single always_comb block to compute the output.
    // For GRAY mode, perform Gray code conversion; otherwise, pass the count directly.
    always_comb begin
        if (mode_in == GRAY)
            o_count = (count ^ (count >> 1));
        else
            o_count = count;
    end

endmodule

output.rtl/gf_multiplier.sv:
module gf_multiplier(
    input  logic [3:0] A,    // Multiplicand (4-bit)
    input  logic [3:0] B,    // Multiplier (4-bit)
    output logic [3:0] result // GF(2^4) product (4-bit)
);

  // This combinational block implements GF(2^4) multiplication using the
  // irreducible polynomial x^4 + x + 1 (represented as 5'b10011).
  // The algorithm iterates over each bit of B (from LSB to MSB), conditionally
  // XORs the current multiplicand into the result, shifts the multiplicand left,
  // and performs polynomial reduction if an overflow (MSB=1) occurs.
  //
  // A 5-bit temporary variable (tmp) is used to hold the multiplicand during
  // shifting so that any overflow can be detected and reduced.
  //
  // Polynomial reduction:
  //   If after shifting, the MSB of tmp (bit[4]) is 1, then:
  //     tmp = {1'b0, (tmp XOR 5'b10011)[3:0]}
  //   This ensures that only the lower 4 bits are retained.
  //
  // The multiplication result is accumulated in result_reg.

  always_comb begin
    reg [3:0] result_reg;  // Intermediate 4-bit result
    reg [4:0] tmp;          // 5-bit temporary variable for multiplicand
    integer i;

    result_reg = 4'b0;
    // Initialize tmp with A in the lower 4 bits and MSB = 0.
    tmp = {1'b0, A};

    // Iterate over each bit of multiplier B (4 iterations for 4-bit values)
    for (i = 0; i < 4; i = i + 1) begin
      // If the current bit of B is 1, XOR the current multiplicand (lower 4 bits)
      // into the result.
      if (B[i])
        result_reg = result_reg ^ tmp[3:0];

      // Shift the multiplicand left by 1 bit.
      tmp = tmp << 1;

      // If an overflow occurs (MSB of tmp is 1), perform polynomial reduction.
      if (tmp[4])
        tmp = {1'b0, (tmp ^ 5'b10011)[3:0]};
    end

    result = result_reg;
  end

endmodule

output.rtl/gf_mac.sv:
module gf_mac #(
    parameter WIDTH = 8  // Configurable input width (must be a multiple of 8)
) (
    input  [WIDTH-1:0] a,
    input  [WIDTH-1:0] b,
    output [7:0] result
);

    // Calculate the number of 8-bit segments
    localparam NUM_SEGMENTS = WIDTH / 8;

    // Array to hold the result of each 8-bit GF multiplication
    wire [7:0] seg_result [0:NUM_SEGMENTS-1];

    // Instantiate a gf_multiplier for each 8-bit segment
    genvar i;
    generate
        for (i = 0; i < NUM_SEGMENTS; i = i + 1) begin : gf_mult_inst
            gf_multiplier u_gf_multiplier (
                .A(a[(i*8)+:8]),
                .B(b[(i*8)+:8]),
                .result(seg_result[i])
            );
        end
    endgenerate

    // Accumulate the segment results using XOR for the MAC operation
    reg [7:0] temp_result;
    integer j;
    always_comb begin
        temp_result = 8'b0;
        for (j = 0; j < NUM_SEGMENTS; j = j + 1) begin
            temp_result = temp_result ^ seg_result[j];
        end
    end

    assign result = temp_result;

endmodule

