module gmii_rx_to_axi_stream (
    // GMII Input Signals:
    input  wire        gmii_rx_clk,
    input  wire [7:0]  gmii_rxd,
    input  wire        gmii_rx_dv,

    // AXI-Stream Output Signals:
    output wire [7:0]  m_axis_tdata,
    output wire        m_axis_tvalid,
    input  wire        m_axis_tready,
    output wire        m_axis_tlast
);

    // State definitions
    localparam IDLE      = 2'b00,
               RECEIVING = 2'b01,
               FINISHED  = 2'b10;

    // Define a fixed frame length (number of bytes per frame)
    parameter FRAME_LENGTH = 8;

    // State and byte counter registers
    reg [1:0] state;
    reg [2:0] byte_counter;  // 3 bits are enough for FRAME_LENGTH = 8

    // Register to hold the current data word
    reg [7:0] data_reg;

    // State Machine: Synchronous process on gmii_rx_clk
    always_ff @(posedge gmii_rx_clk) begin
        case (state)
            IDLE: begin
                // Wait for gmii_rx_dv to indicate start of frame
                if (gmii_rx_dv) begin
                    state      <= RECEIVING;
                    byte_counter <= 0;
                end
            end

            RECEIVING: begin
                if (gmii_rx_dv) begin
                    // Only transfer data when downstream is ready
                    if (m_axis_tready) begin
                        data_reg <= gmii_rxd;  // Capture data
                        // If this is the last byte of the frame, prepare to finish
                        if (byte_counter == FRAME_LENGTH - 1)
                            state <= FINISHED;
                        else
                            byte_counter <= byte_counter + 1;
                    end
                end
                else begin
                    // If gmii_rx_dv goes low unexpectedly, end the frame
                    state <= FINISHED;
                end
            end

            FINISHED: begin
                // Wait until gmii_rx_dv is low to return to IDLE
                if (!gmii_rx_dv)
                    state <= IDLE;
            end

            default: state <= IDLE;
        endcase
    end

    // AXI-Stream Output Assignments (combinational)
    assign m_axis_tdata = (state == RECEIVING && gmii_rx_dv && m_axis_tready) ? data_reg : 8'b0;
    assign m_axis_tvalid = (state == RECEIVING && gmii_rx_dv && m_axis_tready) ? 1'b1 : 1'b0;
    assign m_axis_tlast  = (state == RECEIVING && gmii_rx_dv && m_axis_tready && (byte_counter == FRAME_LENGTH - 1)) ? 1'b1 : 1'b0;

endmodule

output.rtl/gray_to_binary.sv:
module gray_to_binary #(
    parameter WIDTH      = 4,  // Specify the width of the Gray code input
    parameter DEBUG_MODE = 0   // Debug mode: 0 = Disabled, 1 = Enabled
) (
    input  logic [WIDTH-1:0] gray_in,     
    output logic [WIDTH-1:0] binary_out, 
    output logic [WIDTH-1:0] debug_mask,  
    output logic             parity,   
    output logic             valid        
);

  // Internal signals for processing stages
  logic [WIDTH-1:0] intermediate_stage_1; 
  logic [WIDTH-1:0] intermediate_stage_2;  
  logic [WIDTH-1:0] masked_output;
  logic [WIDTH-1:0] final_binary;  
  logic             valid_stage_1;  
  logic             valid_stage_2;  

  // Combinational always block for conversion and debugging
  always @* begin

    // Stage 1: Intermediate Binary Computation
    intermediate_stage_1[WIDTH-1] = gray_in[WIDTH-1];
    for (int i = WIDTH - 2; i >= 0; i--) begin
      intermediate_stage_1[i] = intermediate_stage_1[i+1] ^ gray_in[i];
    end
    valid_stage_1 = 1'b1;  

    // Stage 2: Debugging and Masking
    if (DEBUG_MODE) begin
      // When debugging is enabled, invert the intermediate binary to produce debug mask
      masked_output = ~intermediate_stage_1;
      debug_mask = masked_output;
    end else begin
      // When debugging is disabled, pass the computed binary directly and set debug mask to zero
      masked_output = intermediate_stage_1;
      debug_mask = {WIDTH{1'b0}};
    end
    valid_stage_2 = 1'b1;  

    // Stage 3: Final Outputs
    final_binary = masked_output;
    binary_out = final_binary;
    // Compute parity: reduction XOR to determine if even (0) or odd (1)
    parity = ^final_binary;
    valid = valid_stage_1 && valid_stage_2; // Both stages valid

  end

endmodule

