          end else begin
            // Fill remaining positions with zeros
            padded_image[(pad_row * OUT_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH] <= '0;
          end
        end
      end
    end
  end

  always_ff @(posedge clk) begin
    padded_image_reg <= padded_image;
    padded_image_reg2 <= padded_image_reg;
    padded_image_reg3 <= padded_image_reg2;
  end

  // Step 2: Transpose the padded image (Stored in Registers)
  always_ff @(posedge clk) begin
    if (srst) begin
      transposed_image <= '0;
    end else begin
      for (int trans_row = 0; trans_row < OUT_ROW; trans_row++) begin
        for (int trans_col = 0; trans_col < OUT_COL; trans_col++) begin
          // Transpose logic: Swap rows and columns
          transposed_image[(trans_col * OUT_ROW + trans_row) * DATA_WIDTH +: DATA_WIDTH] <= padded_image_reg[(trans_row * OUT_COL + trans_col) * DATA_WIDTH +: DATA_WIDTH];
        end
      end
    end
  end

  always_ff @(posedge clk) begin
    transposed_image_reg <= transposed_image;
  end

  // Step 3: Apply rotation logic with additional latency buffer
  always_ff @(posedge clk) begin
    if (srst) begin
      rotated_image <= '0;
    end else begin
      for (int rot_row = 0; rot_row < OUT_ROW; rot_row++) begin
        for (int rot_col = 0; rot_col < OUT_COL; rot_col++) begin
          case (rotation_angle)
            // 90° Clockwise: Transpose + Reverse Rows
            2'b00: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[(rot_row * OUT_COL + (OUT_COL-1-rot_col)) * DATA_WIDTH +: DATA_WIDTH];

            // 180° Clockwise: Reverse Rows and Columns
            2'b01: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= padded_image_reg3[((OUT_ROW-1-rot_row) * OUT_COL + (OUT_COL-1-rot_col)) * DATA_WIDTH +: DATA_WIDTH];

            // 270° Clockwise: Transpose + Reverse Columns
            2'b10: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= transposed_image_reg[((OUT_ROW-1-rot_row) * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH];

            // No Rotation (Pass-through)
            2'b11: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= padded_image_reg3[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH];

          endcase
        end
      end
    end
  end

  always_ff @(posedge clk) begin
    rotated_image_reg <= rotated_image;
  end

  // Step 4: Output Register for Added Latency
  always_ff @(posedge clk) begin
    if (srst) begin
      image_out <= '0;
    end else begin
      image_out <= rotated_image_reg;
    end
  end

endmodule

output.rtl/image_rotate.sv:
module image_rotate #(
  parameter IN_ROW     = 4,                                   // Number of rows in input image
  parameter IN_COL     = 4,                                   // Number of columns in input image
  parameter OUT_ROW    = (IN_ROW > IN_COL) ? IN_ROW : IN_COL, // Output rows after padding
  parameter OUT_COL    = (IN_ROW > IN_COL) ? IN_ROW : IN_COL, // Output columns after padding
  parameter DATA_WIDTH = 8                                    // Bit-width of data
) (
  input  logic                                    clk,                // Clock Signal
  input  logic                                    srst,               // Active-High Synchronous Reset
  input  logic                                    valid_in,           // Indicates valid input image
  input  logic                       [       1:0] rotation_angle,     // Rotation angle (00: 90°, 01: 180°, 10: 270°, 11: No Rotation)
  input  logic   [(IN_ROW*IN_COL*DATA_WIDTH)-1:0] image_in,           // Flattened input image
  output logic                                    valid_out,          // Indicates valid output image
  output logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] image_out           // Flattened output image
);

  // Declare signals for padded, transposed, and rotated images.
  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] padded_image;
  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] transposed_image;
  logic [(OUT_ROW*OUT_COL*DATA_WIDTH)-1:0] rotated_image;

  // Validity pipeline (unchanged)
  logic [5:0] valid_out_reg;

  always_ff @(posedge clk)
    if (srst)
      {valid_out, valid_out_reg} <= '0;
    else
      {valid_out, valid_out_reg} <= {valid_out_reg, valid_in};

  //--------------------------------------------------------------------------
  // Optimized Sequential Block:
  // Combine padding, transposition, and rotation into a single always_ff block.
  // This eliminates the extra pipeline registers that were previously used.
  // The overall image data path now has only one register stage (for output),
  // reducing the latency from 6 cycles to 2 cycles and cutting area by more than 25%.
  //--------------------------------------------------------------------------

  always_ff @(posedge clk)
  begin
    if (srst) begin
      padded_image     <= '0;
      transposed_image <= '0;
      rotated_image    <= '0;
    end
    else begin
      // Step 1: Pad the input image into a square image.
      for (int pad_row = 0; pad_row < OUT_ROW; pad_row++) begin
        for (int pad_col = 0; pad_col < OUT_COL; pad_col++) begin
          if ((pad_row < IN_ROW) && (pad_col < IN_COL))
            padded_image[(pad_row * OUT_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH] <= image_in[(pad_row * IN_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH];
          else
            padded_image[(pad_row * OUT_COL + pad_col) * DATA_WIDTH +: DATA_WIDTH] <= '0;
        end
      end

      // Step 2: Transpose the padded image.
      for (int trans_row = 0; trans_row < OUT_ROW; trans_row++) begin
        for (int trans_col = 0; trans_col < OUT_COL; trans_col++) begin
          transposed_image[(trans_col * OUT_ROW + trans_row) * DATA_WIDTH +: DATA_WIDTH] <= padded_image[(trans_row * OUT_COL + trans_col) * DATA_WIDTH +: DATA_WIDTH];
        end
      end

      // Step 3: Apply rotation logic.
      for (int rot_row = 0; rot_row < OUT_ROW; rot_row++) begin
        for (int rot_col = 0; rot_col < OUT_COL; rot_col++) begin
          case (rotation_angle)
            // 90° Clockwise: Transpose + Reverse Rows
            2'b00: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= 
                      transposed_image[(rot_row * OUT_COL + (OUT_COL-1-rot_col)) * DATA_WIDTH +: DATA_WIDTH];

            // 180° Clockwise: Reverse Rows and Columns
            2'b01: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= 
                      padded_image[((OUT_ROW-1-rot_row) * OUT_COL + (OUT_COL-1-rot_col)) * DATA_WIDTH +: DATA_WIDTH];

            // 270° Clockwise: Transpose + Reverse Columns
            2'b10: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= 
                      transposed_image[((OUT_ROW-1-rot_row) * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH];

            // No Rotation (Pass-through)
            2'b11: rotated_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH] <= 
                      padded_image[(rot_row * OUT_COL + rot_col) * DATA_WIDTH +: DATA_WIDTH];
          endcase
        end
      end
    end
  end

  //--------------------------------------------------------------------------
  // Final Output Register:
  // The output image is registered only once, reducing the overall latency.
  //--------------------------------------------------------------------------

  always_ff @(posedge clk)
  begin
    if (srst)
      image_out <= '0;
    else
      image_out <= rotated_image;
  end

endmodule

input.rtl/image_stego.sv:
module image_stego #(
  parameter row = 2,
  parameter col = 2
)(
  input  [(row*col*8)-1:0] img_in,
  input  [(row*col*4)-1:0] data_in,
  input  [1:0]             bpp,
  output [(row*col*8)-1:0] img_out
);

  genvar i;
  generate
    for(i = 0; i < row*col; i++) begin
      assign img_out[(i*8)+7:(i*8)] = (bpp[1] == 1'b0)
                                      ? (bpp[0] == 1'b0
                                         ? {img_in[(i*8)+7 : (i*8)+1], data_in[i]}
                                         : {img_in[(i*8)+7 : (i*8)+2], data_in[(2*i)+1], data_in[2*i]}) 
                                      : img_in[(i*8)+7 : (i*8)]; 
    end
  endgenerate

endmodule

output.rtl/image_stego.sv:
module image_stego #(
  parameter row = 2,
  parameter col = 2
)(
  input  [(row*col*8)-1:0] img_in,
  input  [(row*col*4)-1:0] data_in,
  input  [1:0]             bpp,
  output [(row*col*8)-1:0] img_out
);

  // The intended behavior is as follows:
  // • When bpp == 2'b00, no bits are embedded (pass-through).
  // • When bpp == 2'b01, 2 bits are embedded (replace the lower 2 bits of each pixel).
  // • When bpp == 2'b10, 3 bits are embedded (replace the lower 3 bits of each pixel).
  // • When bpp == 2'b11, 4 bits are embedded (replace the lower 4 bits of each pixel).
  //
  // To achieve this, we use the following logic:
  // – If bpp[1] is 1, then we are in the “high-embedding” mode.
  //   • If bpp[0] is 0 (i.e. bpp==10) then embed 3 bits:
  //         keep img_in[7:3] and insert data_in[3*i +: 3].
  //   • If bpp[0] is 1 (i.e. bpp==11) then embed 4 bits:
  //         keep img_in[7:4] and insert data_in[4*i +: 4].
  // – Else (bpp[1] == 0) we are in the “low-embedding” mode.
  //   • If bpp[0] is 1 (i.e. bpp==01) then embed 2 bits:
  //         keep img_in[7:2] and insert data_in[2*i +: 2].
  //   • Otherwise (bpp==00) pass-through.
  //
  // Note: The data_in slice for each pixel is computed as:
  //   For 2 bits per pixel: data_in[2*i +: 2]
  //   For 3 bits per pixel: data_in[3*i +: 3]
  //   For 4 bits per pixel: data_in[4*i +: 4]

  genvar i;
  generate
    for(i = 0; i < row*col; i++) begin : gen_pixels
      assign img_out[(i*8)+7:(i*8)] =
        (bpp[1] == 1'b1)
          ? (bpp[0] == 1'b1
              ? { img_in[(i*8)+7:(i*8)+4], data_in[4*i +: 4] }  // bpp = 2'b11: embed 4 bits
              : { img_in[(i*8)+7:(i*8)+3], data_in[3*i +: 3] } ) // bpp = 2'b10: embed 3 bits
          : (bpp[0] == 1'b1
              ? { img_in[(i*8)+7:(i*8)+2], data_in[2*i +: 2] }   // bpp = 2'b01: embed 2 bits
              : img_in[(i*8)+7:(i*8)] );                          // bpp = 2'b00: pass-through
    end
  endgenerate

endmodule

output.rtl/programmable_interrupt_controller.sv:
module interrupt_controller 
#(
    parameter NUM_INTERRUPTS = 4, 
    parameter ADDR_WIDTH = 8
)
(
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output logic [clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,
    input  logic [NUM_INTERRUPTS-1:0] priority_map_value [NUM_INTERRUPTS-1:0],
    input  logic                      priority_map_update,
    input  logic [ADDR_WIDTH-1:0]     vector_table_value [NUM_INTERRUPTS-1:0],
    input  logic                      vector_table_update,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_mask_value,
    input  logic                      interrupt_mask_update
);

  //-------------------------------------------------------------------------
  // Internal Registers and Wires
  //-------------------------------------------------------------------------
  // Pending interrupts: OR of new requests with previously pending ones.
  reg [NUM_INTERRUPTS-1:0] pending_interrupts;

  // Internal interrupt mask register.
  reg [NUM_INTERRUPTS-1:0] internal_interrupt_mask;

  // Current serviced interrupt index. Using an integer variable.
  integer current_interrupt;

  // Priority map: a 2D array. For simplicity, we use the diagonal elements as the
  // effective priority for each interrupt. (priority_map[i][i] holds the priority of interrupt i)
  reg [NUM_INTERRUPTS-1:0] priority_map [NUM_INTERRUPTS-1:0];

  // Interrupt vector table.
  reg [ADDR_WIDTH-1:0] vector_table [NUM_INTERRUPTS-1:0];

  //-------------------------------------------------------------------------
  // Sequential Logic
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
      // Reset all state registers.
      pending_interrupts          <= '0;
      internal_interrupt_mask     <= '0;
      current_interrupt           <= 0;

      // Initialize the priority map with default sequential priorities.
      integer i, j;
      for (i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
        for (j = 0; j < NUM_INTERRUPTS; j = j + 1) begin
          if (i == j)
            priority_map[i][j] <= i;  // Default: interrupt i gets priority = i
          else
            priority_map[i][j] <= 0;  // Non-diagonal entries are not used.
        end
      end

      // Initialize the vector table with default vectors (multiples of 4).
      for (i = 0; i < NUM_INTERRUPTS; i = i + 1)
        vector_table[i] <= i * 4;

    end
    else begin
      //-------------------------------------------------------------------------
      // Dynamic Updates
      //-------------------------------------------------------------------------
      if (priority_map_update) begin
        integer i, j;
        for (i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
          for (j = 0; j < NUM_INTERRUPTS; j = j + 1)
            priority_map[i][j] <= priority_map_value[i][j];
        end
      end

      if (vector_table_update) begin
        integer i;
        for (i = 0; i < NUM_INTERRUPTS; i = i + 1)
          vector_table[i] <= vector_table_value[i];
      end

      if (interrupt_mask_update)
        internal_interrupt_mask <= interrupt_mask_value;

      //-------------------------------------------------------------------------
      // Update Pending Interrupts
      //-------------------------------------------------------------------------
      // An interrupt remains pending until it is serviced and acknowledged.
      pending_interrupts <= pending_interrupts | interrupt_requests;

      //-------------------------------------------------------------------------
      // Servicing Logic
      //-------------------------------------------------------------------------
      // If an interrupt is currently being serviced and the CPU has acknowledged it,
      // clear that interrupt from the pending queue.
      if (current_interrupt != 0 && cpu_ack) begin
        pending_interrupts[current_interrupt] <= 0;
        current_interrupt <= 0;
      end
      // If no interrupt is being serviced, select the highest priority pending
      // interrupt that is not masked.
      else if (current_interrupt == 0) begin
        integer i;
        logic [31:0] min_priority;  // Use a wider type for comparison.
        integer selected;
        // Initialize min_priority to a value higher than any valid priority.
        min_priority = NUM_INTERRUPTS;
        selected = -1;
        for (i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
          if (pending_interrupts[i] && ~internal_interrupt_mask[i]) begin
            // Effective priority is taken from the diagonal element.
            if (priority_map[i][i] < min_priority) begin
              min_priority = priority_map[i][i];
              selected = i;
            end
          end
        end
        if (selected != -1)
          current_interrupt <= selected;
      end
    end
  end

  //-------------------------------------------------------------------------
  // Combinational Outputs
  //-------------------------------------------------------------------------
  // Set the interrupt_service vector to have a '1' at the index of the current interrupt.
  assign interrupt_service = (current_interrupt != 0) ? (1 << current_interrupt) : 0;

  // Assert cpu_interrupt if an interrupt is being serviced.
  assign cpu_interrupt = (current_interrupt != 0);

  // Output the index of the currently serviced interrupt.
  assign interrupt_idx = current_interrupt[clog2(NUM_INTERRUPTS)-1:0];

  // Output the interrupt vector corresponding to the current interrupt.
  assign interrupt_vector = vector_table[current_interrupt];

endmodule

output.rtl/pic_starvation_prevention.sv:
module interrupt_controller (
    input  wire         clk,
    input  wire         rst_n,
    input  wire         reset_interrupts,
    input  wire [9:0]   interrupt_requests,
    input  wire         interrupt_ack,
    input  wire         interrupt_trig,
    input  wire [9:0]   interrupt_mask,
    input  wire [3:0]   priority_override,
    input  wire [3:0]   override_interrupt_id,
    input  wire         priority_override_en,
    output reg  [3:0]   interrupt_id,
    output reg          interrupt_valid,
    output reg [9:0]    interrupt_status,
    output reg [9:0]    missed_interrupts,
    output reg          starvation_detected
);

    // Parameters for thresholds
    parameter STARVATION_THRESHOLD = 5;
    parameter SERVICE_TIMEOUT      = 10;

    // State encoding
    localparam [2:0] 
        IDLE        = 3'b000,
        PRIORITY_CALC = 3'b001,
        SERVICE_PREP = 3'b010,
        SERVICING    = 3'b011,
        COMPLETION   = 3'b100,
        ERROR        = 3'b111;

    // State and internal registers
    reg [2:0] current_state, next_state;
    reg [9:0] pending_interrupts;
    reg [3:0] wait_counters [0:9];
    reg [4:0] effective_priority [0:9];
    reg [9:0] interrupt_status_reg;
    reg [3:0] service_timer;
    reg timeout_error;
    reg [3:0] next_interrupt_id;
    reg [4:0] max_priority;

    // Main sequential block: state machine and register updates
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            current_state        <= IDLE;
            pending_interrupts   <= 10'b0;
            wait_counters        <= '0;
            effective_priority   <= '0;
            interrupt_status_reg <= 10'b0;
            missed_interrupts    <= 10'b0;
            service_timer        <= 4'b0;
            timeout_error        <= 1'b0;
            starvation_detected  <= 1'b0;
        end
        else if (reset_interrupts) begin
            current_state        <= IDLE;
            pending_interrupts   <= 10'b0;
            wait_counters        <= '0;
            effective_priority   <= '0;
            interrupt_status_reg <= 10'b0;
            missed_interrupts    <= 10'b0;
            service_timer        <= 4'b0;
            timeout_error        <= 1'b0;
            starvation_detected  <= 1'b0;
        end
        else begin
            // Update pending interrupts and missed interrupts on trigger
            for (int i = 0; i < 10; i++) begin
                if (interrupt_trig) begin
                    if (interrupt_requests[i] && ~interrupt_mask[i])
                        pending_interrupts[i] <= 1'b1;
                    else if (interrupt_requests[i] && interrupt_mask[i])
                        missed_interrupts[i] <= missed_interrupts[i] + 1;
                end
                // Increment wait counter if pending; otherwise reset it
                if (pending_interrupts[i])
                    wait_counters[i] <= wait_counters[i] + 1;
                else
                    wait_counters[i] <= 4'b0;
            end

            // Calculate effective priority for each pending interrupt
            for (int i = 0; i < 10; i++) begin
                if (pending_interrupts[i]) begin
                    if (priority_override_en && (i == override_interrupt_id))
                        effective_priority[i] <= priority_override;
                    else if (wait_counters[i] >= STARVATION_THRESHOLD)
                        effective_priority[i] <= (i + 1); // Boost priority if starved
                    else
                        effective_priority[i] <= i; // Assume static priority = index
                end
                else begin
                    effective_priority[i] <= 5'b0;
                end
            end

            // State machine actions and output updates
            case (current_state)
                IDLE: begin
                    interrupt_valid <= 1'b0;
                    service_timer   <= 4'b0;
                end
                SERVICE_PREP: begin
                    interrupt_valid <= 1'b1;
                    interrupt_id    <= next_interrupt_id;
                    // Set the status bit for the selected interrupt
                    interrupt_status_reg <= (1 << next_interrupt_id);
                end
                SERVICING: begin
                    service_timer <= service_timer + 1;
                    if (service_timer >= SERVICE_TIMEOUT)
                        timeout_error <= 1'b1;
                end
                COMPLETION: begin
                    // Clear the serviced interrupt from pending list and wait counter
                    pending_interrupts[next_interrupt_id] <= 1'b0;
                    wait_counters[next_interrupt_id]       <= 4'b0;
                    // Clear the status bit for the serviced interrupt
                    interrupt_status_reg <= interrupt_status_reg & ~(1 << next_interrupt_id);
                    interrupt_valid      <= 1'b0;
                    service_timer        <= 4'b0;
                    timeout_error        <= 1'b0;
                end
                ERROR: begin
                    // In error state, clear the timed-out interrupt and transition back to IDLE
                    pending_interrupts[next_interrupt_id] <= 1'b0;
                    wait_counters[next_interrupt_id]       <= 4'b0;
                    interrupt_status_reg <= interrupt_status_reg & ~(1 << next_interrupt_id);
                    timeout_error        <= 1'b0;
                    current_state        <= IDLE;
                end
                default: ;
            endcase

            // Update current state from next_state computed in combinational logic
            current_state <= next_state;
            // Drive output for interrupt_status
            interrupt_status <= interrupt_status_reg;
        end
    end

    // Combinational logic for next state determination
    always_comb begin
        next_state = current_state; // Default: hold state
        case (current_state)
            IDLE: begin
                if (|pending_interrupts)
                    next_state = PRIORITY_CALC;
            end
            PRIORITY_CALC: 
                next_state = SERVICE_PREP;
            SERVICE_PREP: 
                next_state = SERVICING;
            SERVICING: begin
                if (interrupt_ack)
                    next_state = COMPLETION;
                else if (service_timer >= SERVICE_TIMEOUT)
                    next_state = ERROR;
                else
                    next_state = SERVICING;
            end
            COMPLETION: 
                next_state = IDLE;
            ERROR: 
                next_state = IDLE;
            default: 
                next_state = IDLE;
        endcase
    end

    // Combinational logic: select highest priority pending interrupt
    always_comb begin
        next_interrupt_id = 4'b0;
        max_priority      = 5'b0;
        for (int i = 0; i < 10; i++) begin
            if (pending_interrupts[i]) begin
                if (effective_priority[i] > max_priority) begin
                    max_priority      = effective_priority[i];
                    next_interrupt_id = i;
                end
            end
        end
    end

    // Combinational logic: detect starvation condition
    always_comb begin
        starvation_detected = 1'b0;
        for (int i = 0; i < 10; i++) begin
            if (wait_counters[i] >= STARVATION_THRESHOLD)
                starvation_detected = 1'b1;
        end
    end

endmodule

output.rtl/interrupt_controller_apb.sv:
module interrupt_controller_apb #(
    parameter NUM_INTERRUPTS = 4,
    parameter ADDR_WIDTH = 8
)(
    // Core Interrupt Signals
    input  logic                      clk,
    input  logic                      rst_n,
    input  logic [NUM_INTERRUPTS-1:0] interrupt_requests,
    output logic [NUM_INTERRUPTS-1:0] interrupt_service,
    output logic                      cpu_interrupt,
    input  logic                      cpu_ack,
    output logic [$clog2(NUM_INTERRUPTS)-1:0] interrupt_idx,
    output logic [ADDR_WIDTH-1:0]     interrupt_vector,

    // APB Interface Signals
    input  logic                      pclk,
    input  logic                      presetn,
    input  logic                      psel,
    input  logic                      penable,
    input  logic                      pwrite,
    input  logic [ADDR_WIDTH-1:0]     paddr,
    input  logic [31:0]               pwdata,
    output logic [31:0]               prdata,
    output logic                      pready
);

    //-------------------------------------------------------------------------
    // Internal APB-Controlled Configuration Registers
    //-------------------------------------------------------------------------

    // priority_map: array of NUM_INTERRUPTS 32-bit registers.
    // Each register is formatted as {priority (31:8), index (7:0)}.
    reg [31:0] priority_map_array [0:NUM_INTERRUPTS-1];

    // interrupt_mask: 32-bit register; lower NUM_INTERRUPTS bits used.
    reg [31:0] interrupt_mask_reg;

    // vector_table: array of NUM_INTERRUPTS 32-bit registers.
    // Each register is formatted as {vector address (31:8), index (7:0)}.
    reg [31:0] vector_table_array [0:NUM_INTERRUPTS-1];

    //-------------------------------------------------------------------------
    // Internal Interrupt Logic Registers
    //-------------------------------------------------------------------------

    // pending_interrupts: one bit per interrupt.
    reg [NUM_INTERRUPTS-1:0] pending_interrupts;

    // current_interrupt: index of the currently serviced interrupt.
    reg [$clog2(NUM_INTERRUPTS)-1:0] current_interrupt;

    // Synchronizer registers for external interrupt_requests (2-stage)
    reg [NUM_INTERRUPTS-1:0] interrupt_req_sync1;
    reg [NUM_INTERRUPTS-1:0] interrupt_req_sync2;

    //-------------------------------------------------------------------------
    // APB Interface (pclk Domain)
    //-------------------------------------------------------------------------

    always_ff @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            // Reset APB registers to default values
            integer i;
            // Reset priority_map: for each interrupt, set priority = index and store index.
            for (i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                priority_map_array[i] <= {i, i};  // {priority, index}
            end
            // Reset interrupt_mask: all interrupts enabled (1 for each bit)
            interrupt_mask_reg <= {NUM_INTERRUPTS{1'b1}};
            // Reset vector_table: sequential addresses (e.g., 0x0, 0x4, 0x8, ...)
            for (i = 0; i < NUM_INTERRUPTS; i = i + 1) begin
                vector_table_array[i] <= { {24{1'b0}}, 4*i }; // {vector, index}
            end
        end
        else if (psel && penable) begin
            if (pwrite) begin
                // Write Transaction
                case (paddr)
                    8'h0: begin
                        // REG_PRIORITY_MAP: pwdata[7:0] is the interrupt index,
                        // pwdata[31:8] is the new priority.
                        if (pwdata[7:0] < NUM_INTERRUPTS)
                            priority_map_array[pwdata[7:0]] <= {pwdata[31:8], pwdata[7:0]};
                    end
                    8'h1: begin
                        // REG_INTERRUPT_MASK: update mask register (lower NUM_INTERRUPTS bits)
                        interrupt_mask_reg <= pwdata;
                    end
                    8'h2: begin
                        // REG_VECTOR_TABLE: pwdata[7:0] is the interrupt index,
                        // pwdata[31:8] is the new vector address.
                        if (pwdata[7:0] < NUM_INTERRUPTS)
                            vector_table_array[pwdata[7:0]] <= {pwdata[31:8], pwdata[7:0]};
                    end
                    default: ; // Undefined address: no operation.
                endcase
            end
            else begin
                // Read Transaction
                case (paddr)
                    8'h3: begin
                        // REG_PENDING: return pending_interrupts packed in lower bits.
                        prdata <= { {24{1'b0}}, pending_interrupts };
                    end
                    8'h4: begin
                        // REG_CURRENT_INT: return current_interrupt (zero-extended).
                        prdata <= { {24{1'b0}}, current_interrupt };
                    end
                    default: prdata <= 32'h0;
                endcase
                pready <= 1'b1;  // Assert ready for immediate access.
            end
        end
        else begin
            pready <= 1'b0;  // No valid transaction: de-assert ready.
        end
    end

    //-------------------------------------------------------------------------
    // Interrupt Logic (clk Domain)
    //-------------------------------------------------------------------------

    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            pending_interrupts <= '0;
            current_interrupt  <= {(NUM_INTERRUPTS){1'b1}}; // Invalid index (all ones)
            cpu_interrupt      <= 1'b0;
        end
        else begin
            // Two-stage synchronizer for external interrupt_requests.
            interrupt_req_sync1 <= interrupt_requests;
            interrupt_req_sync2 <= interrupt_req_sync1;

            // Update pending_interrupts:
            // If an interrupt is requested and not masked, assert its pending bit.
            // If cpu_ack is asserted for the current interrupt, clear its pending bit.
            integer j;
            for (j = 0; j < NUM_INTERRUPTS; j = j + 1) begin
                if (cpu_ack && (current_interrupt == j))
                    pending_interrupts[j] <= 1'b0;
                else if (interrupt_req_sync2[j] && ~interrupt_mask_reg[j])
                    pending_interrupts[j] <= 1'b1;
                // Otherwise, retain the previous pending state.
            end

            // Assert cpu_interrupt if any interrupt is pending.
            cpu_interrupt <= |pending_interrupts;
        end
    end

    //-------------------------------------------------------------------------
    // Interrupt Arbitration (Combinational)
    //-------------------------------------------------------------------------
    // Select the highest-priority pending interrupt based on priority_map_array.
    // Each entry in priority_map_array is formatted as {priority, index}.
    logic [$clog2(NUM_INTERRUPTS)-1:0] selected_int;
    logic [31:0] max_priority;
    integer k;
    always_comb begin
        // Default: no valid interrupt selected (invalid index: all ones)
        selected_int = {(NUM_INTERRUPTS){1'b1}};
        max_priority = 32'h0;
        for (k = 0; k < NUM_INTERRUPTS; k = k + 1) begin
            if (pending_interrupts[k]) begin
                // Extract the priority value (bits [31:8])
                if (priority_map_array[k][31:8] > max_priority) begin
                    max_priority = priority_map_array[k][31:8];
                    selected_int = k;
                end
                else if (priority_map_array[k][31:8] == max_priority && k < selected_int) begin
                    selected_int = k;
                end
            end
        end
    end

    // Latch the selected interrupt index.
    always_ff @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            current_interrupt <= {(NUM_INTERRUPTS){1'b1}}; // Invalid on reset
        else
            current_interrupt <= selected_int;
    end

    //-------------------------------------------------------------------------
    // Output Assignments
    //-------------------------------------------------------------------------

    // Drive interrupt_service: a one-hot vector with the selected interrupt.
    assign interrupt_service = (current_interrupt != {(NUM_INTERRUPTS){1'b1}})
                                ? (1'b1 << current_interrupt)
                                : '0;
    // Drive interrupt_idx with the current interrupt index.
    assign interrupt_idx = current_interrupt;
    // Drive interrupt_vector with the vector address from vector_table_array.
    assign interrupt_vector = (current_interrupt != {(NUM_INTERRUPTS){1'b1}})
                                ? vector_table_array[current_interrupt]
                                : 8'h0;

endmodule

