input.rtl/signed_sequential_booth_multiplier.s:
module signed_sequential_booth_multiplier #(parameter WIDTH = 8) (
    input  wire signed [WIDTH-1:0] A,
    input  wire signed [WIDTH-1:0] B,
    input  wire clk,
    input  wire rst,
    input  wire start,
    output reg  signed [2*WIDTH-1:0] result,
    output reg done
);

    // FSM states
    typedef enum logic [2:0] {
        IDLE     = 3'b000,
        ENCODE   = 3'b001, 
        PARTIAL  = 3'b010, 
        ADDITION = 3'b011, 
        DONE     = 3'b100
    } state_t;

    state_t state, next_state;

    // Registers for control and data signals
    reg signed [2*WIDTH-1:0] partial_products [0:WIDTH/2-1];
    reg signed [2*WIDTH-1:0] multiplicand;
    reg signed [WIDTH:0] booth_bits; 
    reg signed [2*WIDTH-1:0] accumulator;  
    reg [2:0] encoding_bits [0:WIDTH/2-1];
    reg [$clog2(WIDTH/2):0] addition_counter; // Counter for addition cycles
    integer i;

    // State machine: Sequential process for state transitions
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    // State machine: Combinational process for next-state logic
    always @(*) begin
        case (state)
            IDLE: begin
                if (start) begin
                    next_state = ENCODE;
                end else begin
                    next_state = IDLE;
                end
            end

            ENCODE: begin
                next_state = PARTIAL;
            end

            PARTIAL: begin
                next_state = ADDITION;
            end

            ADDITION: begin
                next_state = DONE;
            end

            DONE: begin
                if (!start) begin
                    next_state = IDLE;
                end else begin
                    next_state = DONE;
                end
            end

            default: begin
                next_state = IDLE;
            end
        endcase
    end

    // Signal assignments: Perform operations based on current state
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            done <= 0;
            result <= 0;
            accumulator <= 0;
            addition_counter <= 0;
            multiplicand <= 0;
            booth_bits <= 0;
            for (i = 0; i < WIDTH/2; i = i + 1) begin
                encoding_bits[i] <= 0;
                partial_products[i] <= 0;
            end
        end else begin
            case (state)
                IDLE: begin
                    // Prepare for new computation
                    done <= 0;
                    result <= 0;
                    if (start) begin
                        multiplicand <= {{(WIDTH){A[WIDTH-1]}}, A}; // Sign-extend A
                        booth_bits <= {B, 1'b0};
                        accumulator <= 0;
                        for (i = 0; i < WIDTH/2; i = i + 1) begin
                            partial_products[i] <= 0;
                        end
                    end
                end

                ENCODE: begin
                    // Extract 3-bit Booth segments
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        encoding_bits[i] <= booth_bits[2*i +: 3];
                    end
                end

                PARTIAL: begin
                    // Generate partial products based on Booth encoding
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                        case (encoding_bits[i])
                            3'b001, 3'b010: partial_products[i] <= (multiplicand << (2 * i));
                            3'b011:         partial_products[i] <= ((multiplicand << 1) << (2 * i));
                            3'b100:         partial_products[i] <= -((multiplicand << 1) << (2 * i));
                            3'b101, 3'b110: partial_products[i] <= -(multiplicand << (2 * i));
                            default:        partial_products[i] <= 0;
                        endcase
                    end
                end

                ADDITION: begin
                    accumulator <= 0;
                    for (i = 0; i < WIDTH/2; i = i + 1) begin
                      accumulator <= accumulator + partial_products[i];  
                    end
                end

                DONE: begin
                    // Output the result
                    result <= accumulator;
                    done <= 1;
                end
            endcase
        end
    end
endmodule

module pipelined_modified_booth_multiplier (
    input clk,
    input rst,
    input start,
    input signed [15:0] X,
    input signed [15:0] Y,
    output reg signed  [31:0] result,
    output reg done
);

    reg signed [31:0] partial_products [0:7];
    reg signed [15:0] X_reg, Y_reg;
    reg [4:0] valid_reg; // Extended valid register for more granular state control

    integer i;

    // Registers for pipelining the addition stages
    reg signed [31:0] s1, s2, s3, s4;
    reg signed [31:0] temp_products1, temp_products2;

    always @(posedge clk or posedge rst) 
    begin
        if (rst) 
        begin
            X_reg <= 16'd0;
            Y_reg <= 16'd0;
            valid_reg <= 5'd0;
            done <= 0;
            for (i = 0; i < 8; i = i + 1) 
            begin
                partial_products[i] <= 32'd0;
            end
            s1 <= 0; s2 <= 0; s3 <= 0; s4 <= 0;
            temp_products1 <= 0; temp_products2 <= 0;
            result <= 32'd0;
            done <= 1'b0;
        end 
        else 
        begin
            if (start && !valid_reg[0]) begin
                X_reg <= X;
                Y_reg <= Y;
                valid_reg[0] <= 1;  // Initiate state 1
            end
            else
              valid_reg[0] <= 0;  // Initiate state 1 

            // Process Booth multiplication
            if (valid_reg[0]) begin
                for (i = 0; i < 8; i = i + 1) begin
                    case ({Y_reg[2*i+1], Y_reg[2*i], (i == 0) ? 1'b0 : Y_reg[2*i-1]})
                        3'b000, 3'b111: partial_products[i] <= 32'd0;
                        3'b001, 3'b010: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i);
                        3'b011: partial_products[i] <= {{16{X_reg[15]}}, X_reg} >> (2*i + 1);
                        3'b100: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i + 1));
                        3'b101, 3'b110: partial_products[i] <= -({{16{X_reg[15]}}, X_reg} >> (2*i));
                        default: partial_products[i] <= 32'd0;
                    endcase
                end
                valid_reg[1] <= 1; // State 1 done, mark State 2 as ready
                valid_reg[0] <= 0; // Reset state 1 active flag
            end 
            else
              valid_reg[1] <= 0; // State 1 done, mark State 2 as ready

            // State 3: Partial Summation
            if (valid_reg[1]) begin 
                s1 <= partial_products[0] + partial_products[1] + partial_products[2];
                s2 <= partial_products[3] + partial_products[4] + partial_products[5];

                valid_reg[2] <= 1; // State 3 done, mark State 4 as ready
                valid_reg[1] <= 0; // Clear state 2 active flag
            end 
            else
              valid_reg[2] <= 0; // State 3 done, mark State 4 as ready 

            // State 4: Sum of Sums
            if (valid_reg[2]) begin 
                s3 <= s1 + s2;
                s4 <= partial_products[6] + partial_products[7];

                valid_reg[3] <= 1; // State 4 done, mark State 5 as ready
                valid_reg[2] <= 0; // Clear state 3 active flag
            end 
            else
              valid_reg[3] <= 0; // State 4 done, mark State 5 as ready


            // State 5: Final Result
            if (valid_reg[3]) begin
                result <= s3 + s4;
                done <= 1;  // Output done signal
                valid_reg[3] <= 0; // Reset state 5 active flag after result computation
            end 
            else
            begin
              result <= 0;
              done <= 1'b0; 
            end 

        end
    end

endmodule

module pipelined_modified_booth_multiplier (
    input clk,
    input rst,
    input start,
    input signed [15:0] X,
    input signed [15:0] Y,
    output reg signed [31:0] result,
    output reg done
);

    // Storage for the eight partial products.
    reg signed [31:0] partial_products [0:7];
    // Latched inputs.
    reg signed [15:0] X_reg, Y_reg;
    // Pipeline state register:
    //  0: Idle, 1: Booth encoding, 2: Partial Summation, 3: Sum of Sums, 4: Final Result.
    reg [2:0] state;
    integer i;

    // Registers for intermediate sums.
    reg signed [31:0] s1, s2, s3, s4;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            X_reg      <= 16'd0;
            Y_reg      <= 16'd0;
            state      <= 3'd0;
            done       <= 1'b0;
            for (i = 0; i < 8; i = i + 1)
                partial_products[i] <= 32'd0;
            s1 <= 32'd0; s2 <= 32'd0; s3 <= 32'd0; s4 <= 32'd0;
            result <= 32'd0;
        end else begin
            case (state)
                3'd0: begin
                    // Wait for the start signal.
                    if (start) begin
                        X_reg <= X;
                        Y_reg <= Y;
                        state <= 3'd1;
                    end
                end
                3'd1: begin
                    // Stage 1: Booth encoding and partial product generation.
                    // The multiplier Y_reg is divided into overlapping groups of 3 bits.
                    // For i=0, the group is {Y_reg[1], Y_reg[0], 1'b0}.
                    // For i>=1, the group is {Y_reg[2*i+1], Y_reg[2*i], Y_reg[2*i-1]}.
                    for (i = 0; i < 8; i = i + 1) begin
                        // Build the 3-bit group.
                        bit3 = (i == 0) ? 1'b0 : Y_reg[2*i-1];
                        case ({Y_reg[2*i+1], Y_reg[2*i], bit3})
                            // 000 and 111: No operation (0).
                            3'b000, 3'b111: partial_products[i] <= 32'd0;
                            // 001 or 010: Add the multiplicand (+X).
                            3'b001, 3'b010: partial_products[i] <= $signed({{16{X_reg[15]}}, X_reg}) << (2*i);
                            // 011: Add twice the multiplicand (+2X).
                            3'b011: partial_products[i] <= $signed({{16{X_reg[15]}}, X_reg}) << (2*i + 1);
                            // 100: Subtract twice the multiplicand (-2X).
                            3'b100: partial_products[i] <= -($signed({{16{X_reg[15]}}, X_reg}) << (2*i + 1));
                            // 101 or 110: Subtract the multiplicand (-X).
                            3'b101, 3'b110: partial_products[i] <= -($signed({{16{X_reg[15]}}, X_reg}) << (2*i));
                            default: partial_products[i] <= 32'd0;
                        endcase
                    end
                    state <= 3'd2;
                end
                3'd2: begin
                    // Stage 2: Partial Summation.
                    // Sum the first six partial products in two groups.
                    s1 <= partial_products[0] + partial_products[1] + partial_products[2];
                    s2 <= partial_products[3] + partial_products[4] + partial_products[5];
                    state <= 3'd3;
                end
                3'd3: begin
                    // Stage 3: Sum of Sums.
                    // Combine the two intermediate sums with the remaining partial products.
                    s3 <= s1 + s2;
                    s4 <= partial_products[6] + partial_products[7];
                    state <= 3'd4;
                end
                3'd4: begin
                    // Stage 4: Final Result.
                    // Add the two final partial sums to obtain the 32‐bit result.
                    result <= s3 + s4;
                    done  <= 1'b1;
                    state <= 3'd0;
                end
                default: state <= 3'd0;
            endcase
        end
    end

endmodule

