module reed_solomon_encoder #(
    parameter DATA_WIDTH = 8,   // Width of input data symbols
    parameter N = 255,         // Total number of symbols in the codeword
    parameter K = 223          // Number of data symbols
) (
    input  wire                clk,
    input  wire                reset,
    input  wire                enable,
    input  wire [DATA_WIDTH-1:0] data_in,
    input  wire                valid_in,
    output reg  [DATA_WIDTH-1:0] codeword_out,
    output reg                 valid_out,
    output reg  [DATA_WIDTH-1:0] parity_0,
    output reg  [DATA_WIDTH-1:0] parity_1
);

    localparam PARITY_SYMBOLS = N - K; // Number of parity symbols 

    // Internal registers for shift-register based encoding
    reg [DATA_WIDTH-1:0] feedback;
    reg [DATA_WIDTH-1:0] next_parity_0, next_parity_1;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            parity_0      <= 0;
            parity_1      <= 0;
            codeword_out  <= 0;
            valid_out     <= 0;
        end 
        else if (enable && valid_in) begin
            // Compute feedback from the input data symbol and the current parity_0
            feedback <= data_in ^ parity_0;
            // Compute new parity values using the generator polynomial coefficients.
            // Here, we use two coefficients: one for updating parity_0 and one for parity_1.
            next_parity_0 = parity_1 ^ (feedback & generator_polynomial(0));
            next_parity_1 = parity_0 ^ (feedback & generator_polynomial(1));
            // Update the parity registers
            parity_0 <= next_parity_0;
            parity_1 <= next_parity_1;
            // For demonstration, combine the data and parity symbols by XOR-ing them together.
            codeword_out <= data_in ^ parity_0 ^ parity_1;
            valid_out    <= 1;
        end
    end

    // Function to return the generator polynomial coefficient based on an index.
    // When index is 0, return 8'h1D; otherwise return 8'h33.
    function automatic [DATA_WIDTH-1:0] generator_polynomial;
       input int index;
       begin
          if (index == 0)
             generator_polynomial = 8'h1D;
          else
             generator_polynomial = 8'h33;
       end
    endfunction

endmodule

input.rtl/cvdp_copilot_register_file_2R1W.sv:
module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32  // Configurable data width
) (
    // Inputs
    input  logic [DATA_WIDTH-1:0] din,    // Input data
    input  logic [4:0] wad1,              // Write address
    input  logic [4:0] rad1,              // Read address 1
    input  logic [4:0] rad2,              // Read address 2
    input  logic wen1,                    // Write-enable signal
    input  logic ren1,                    // Read-enable signal 1
    input  logic ren2,                    // Read-enable signal 2
    input  logic clk,                     // Clock signal
    input  logic resetn,                  // Active-low reset

    // Outputs
    output logic [DATA_WIDTH-1:0] dout1,   // Output data 1
    output logic [DATA_WIDTH-1:0] dout2,   // Output data 2
    output logic collision                 // Collision flag
);

    // -------------------------------
    // Internal Registers and Wires
    // -------------------------------

    // Register file memory with 32 entries of DATA_WIDTH-bit words
    logic [DATA_WIDTH-1:0] rf_mem [0:31];
    logic [31:0] rf_valid;                   // Validity of each register entry
    integer i;

    // Clock Gating Enable Signal: High when any read or write operation is active
    wire clk_en = wen1 | ren1 | ren2;

    // Clock Gating Logic (Integrated from cgate module)
    logic gated_clk;    // Gated clock output
    logic en_latch;     // Enable latch

    // Latch to hold the enable signal when clk is low
    always @ (clk or clk_en) begin
        if (!clk)
            en_latch <= clk_en;
    end

    // Gated clock generation
    assign gated_clk = clk && en_latch;

    // -------------------------------
    // Register File Operations
    // -------------------------------

    // Reset and Write Operation Logic with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            // Initialize all memory locations to zero
            for (i = 0; i < 32; i = i + 1) begin
                rf_mem[i] <= {DATA_WIDTH{1'b0}};
            end
            rf_valid <= 0;  // Mark all entries as invalid
        end 
        else if (wen1) begin
            rf_mem[wad1]    <= din;  // Write operation
            rf_valid[wad1]  <= 1;    // Mark written address as valid
        end
    end

    // Read Data Output Logic for Port 1 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout1 <= 0;
        end 
        else if (ren1) begin
            dout1 <= rf_valid[rad1] ? rf_mem[rad1] : 0;
        end 
        else begin
            dout1 <= 0;
        end
    end

    // Read Data Output Logic for Port 2 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout2 <= 0;
        end 
        else if (ren2) begin
            dout2 <= rf_valid[rad2] ? rf_mem[rad2] : 0;
        end 
        else begin
            dout2 <= 0;
        end
    end

    // -------------------------------
    // Collision Detection Logic
    // -------------------------------

    // Collision Flag Logic with Original Clock (non-gated)
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            collision <= 0;
        end 
        else begin
            collision <= (
                (ren1 && ren2 && (rad1 == rad2)) ||          // Both reads to the same address
                (wen1 && ren1 && (wad1 == rad1)) ||          // Write and read to the same address
                (wen1 && ren2 && (wad1 == rad2))             // Write and read to the same address
            );
        end
    end

endmodule

output.rtl/cvdp_copilot_register_file_2R1W.sv:
module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32,  // Configurable data width
    parameter DEPTH      = 32   // Configurable register file depth
) (
    // Normal Operation Inputs
    input  logic [DATA_WIDTH-1:0] din,    // Input data
    input  logic [4:0]            wad1,   // Write address
    input  logic [4:0]            rad1,   // Read address 1
    input  logic [4:0]            rad2,   // Read address 2
    input  logic                  wen1,   // Write-enable signal
    input  logic                  ren1,   // Read-enable signal 1
    input  logic                  ren2,   // Read-enable signal 2
    input  logic                  clk,    // Clock signal
    input  logic                  resetn, // Active-low reset

    // BIST Control Signals
    input  logic                  test_mode, // Assert high to activate BIST
    output logic                  bist_done, // BIST sequence complete
    output logic                  bist_fail, // BIST failure flag

    // Normal Operation Outputs
    output logic [DATA_WIDTH-1:0] dout1,   // Output data 1
    output logic [DATA_WIDTH-1:0] dout2,   // Output data 2
    output logic                  collision // Collision flag
);

    // -------------------------------
    // Internal Registers and Wires
    // -------------------------------

    // Register file memory with DEPTH entries of DATA_WIDTH-bit words
    logic [DATA_WIDTH-1:0] rf_mem [0:DEPTH-1];
    logic [DEPTH-1:0]      rf_valid;  // Validity of each register entry
    integer                 i;

    // Clock Gating Enable Signal: High when any read or write operation is active (normal ops only)
    wire clk_en = wen1 | ren1 | ren2;

    // Clock Gating Logic (Integrated from cgate module)
    logic gated_clk;    // Gated clock output
    logic en_latch;     // Enable latch

    // Latch to hold the enable signal when clk is low
    always @ (posedge clk or negedge clk) begin
        if (!clk)
            en_latch <= clk_en;
    end

    // Gated clock generation
    assign gated_clk = clk && en_latch;

    // -------------------------------
    // BIST Internal Signals and State Machine
    // -------------------------------

    // BIST State Encoding
    localparam BIST_IDLE  = 2'd0,
               BIST_WRITE = 2'd1,
               BIST_READ  = 2'd2,
               BIST_DONE  = 2'd3;

    // BIST state register and address counter
    logic [1:0] bist_state;
    integer     bist_addr;

    // Internal registers for BIST outputs
    logic bist_done_reg;
    logic bist_fail_reg;

    // Register to capture read data during BIST read phase
    logic [DATA_WIDTH-1:0] read_data_reg;

    // BIST State Machine: Executes only when test_mode is asserted.
    // Normal operations are disabled in this mode.
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            bist_state     <= BIST_IDLE;
            bist_addr      <= 0;
            bist_done_reg  <= 0;
            bist_fail_reg  <= 0;
        end 
        else if (test_mode) begin
            case (bist_state)
                BIST_IDLE: begin
                    bist_state    <= BIST_WRITE;
                    bist_addr     <= 0;
                    bist_done_reg <= 0;
                    bist_fail_reg <= 0;
                end
                BIST_WRITE: begin
                    // Write Phase: Write a known pattern (the address value) to each register location.
                    rf_mem[bist_addr] <= bist_addr[DATA_WIDTH-1:0];
                    rf_valid[bist_addr] <= 1;
                    if (bist_addr == DEPTH - 1)
                        bist_state <= BIST_READ;
                    else
                        bist_state <= BIST_WRITE;
                    bist_addr <= bist_addr + 1;
                end
                BIST_READ: begin
                    // Read Phase: Read the value and compare it with the expected pattern.
                    read_data_reg <= rf_mem[bist_addr];
                    if (read_data_reg !== bist_addr[DATA_WIDTH-1:0])
                        bist_fail_reg <= 1;
                    if (bist_addr == DEPTH - 1)
                        bist_state <= BIST_DONE;
                    else
                        bist_state <= BIST_READ;
                    bist_addr <= bist_addr + 1;
                end
                BIST_DONE: begin
                    bist_done_reg <= 1;
                end
                default: begin
                    bist_state <= BIST_IDLE;
                end
            endcase
        end
    end

    // Drive BIST outputs
    assign bist_done = bist_done_reg;
    assign bist_fail = bist_fail_reg;

    // -------------------------------
    // Normal Operation: Register File Operations (Disabled when test_mode is high)
    // -------------------------------

    // Write Operation Logic with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            // Initialize all memory locations to zero
            for (i = 0; i < DEPTH; i = i + 1) begin
                rf_mem[i] <= {DATA_WIDTH{1'b0}};
            end
            rf_valid <= 0;  // Mark all entries as invalid
        end 
        else if (!test_mode && wen1) begin
            rf_mem[wad1]    <= din;  // Write operation
            rf_valid[wad1]  <= 1;    // Mark written address as valid
        end
    end

    // Read Data Output Logic for Port 1 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout1 <= 0;
        end 
        else if (!test_mode && ren1) begin
            // Output data is valid only if the register is marked valid
            dout1 <= rf_valid[rad1] ? rf_mem[rad1] : 0;
        end 
        else begin
            dout1 <= 0;
        end
    end

    // Read Data Output Logic for Port 2 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            dout2 <= 0;
        end 
        else if (!test_mode && ren2) begin
            dout2 <= rf_valid[rad2] ? rf_mem[rad2] : 0;
        end 
        else begin
            dout2 <= 0;
        end
    end

    // -------------------------------
    // Collision Detection Logic (Normal Operations only)
    // -------------------------------

    // Collision Flag Logic with Original Clock (non-gated)
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            collision <= 0;
        end 
        else if (!test_mode) begin
            collision <= (
                (ren1 && ren2 && (rad1 == rad2)) ||          // Both reads to the same address
                (wen1 && ren1 && (wad1 == rad1)) ||          // Write and read to the same address
                (wen1 && ren2 && (wad1 == rad2))             // Write and read to the same address
            );
        end
    end

endmodule

module cvdp_copilot_register_file_2R1W #(
    parameter DATA_WIDTH = 32  // Configurable data width
) (
    // Inputs
    input  logic [DATA_WIDTH-1:0] din,    // Input data
    input  logic [4:0] wad1,              // Write address
    input  logic [4:0] rad1,              // Read address 1
    input  logic [4:0] rad2,              // Read address 2
    input  logic wen1,                    // Write-enable signal
    input  logic ren1,                    // Read-enable signal 1
    input  logic ren2,                    // Read-enable signal 2
    input  logic clk,                     // Clock signal
    input  logic resetn,                  // Active-low reset

    // Outputs
    output logic [DATA_WIDTH-1:0] dout1,   // Output data 1
    output logic [DATA_WIDTH-1:0] dout2,   // Output data 2
    output logic collision                 // Collision flag
);

    // -------------------------------
    // Internal Registers and Wires
    // -------------------------------

    // Register file memory with 32 entries of DATA_WIDTH-bit words
    logic [DATA_WIDTH-1:0] rf_mem [0:31];
    logic [31:0] rf_valid;                   // Validity of each register entry
    integer i;

    // Clock Gating Enable Signal: High when any read or write operation is active
    wire clk_en = wen1 | ren1 | ren2;

    // Custom Clock Gating Logic
    logic gated_clk;    // Gated clock output
    logic en_latch;     // Enable latch

    // Enable latch generation logic
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn)
            en_latch <= 0;
        else
            en_latch <= clk_en;
    end

    // Gated clock output logic
    assign gated_clk = clk & en_latch;

    // -------------------------------
    // Register File Operations
    // -------------------------------

    // Reset and Write Operation Logic with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn) begin
            // Memory initialization on reset: clear all memory and validity flags
            for (i = 0; i < 32; i = i + 1) begin
                rf_mem[i] <= 0;
            end
            rf_valid <= 0;
        end 
        else if (wen1) begin
            // Write operation: update the memory at wad1 and mark it as valid
            rf_mem[wad1] <= din;
            rf_valid[wad1] <= 1;
        end
    end

    // Read Data Output Logic for Port 1 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn)
            dout1 <= 0;
        else if (ren1)
            // Output data if valid; otherwise 0
            dout1 <= (rf_valid[rad1] ? rf_mem[rad1] : 0);
        else
            dout1 <= 0;
    end

    // Read Data Output Logic for Port 2 with Gated Clock
    always_ff @(posedge gated_clk or negedge resetn) begin
        if (!resetn)
            dout2 <= 0;
        else if (ren2)
            // Output data if valid; otherwise 0
            dout2 <= (rf_valid[rad2] ? rf_mem[rad2] : 0);
        else
            dout2 <= 0;
    end

    // -------------------------------
    // Collision Detection Logic
    // -------------------------------

    // Collision Flag Logic with Original Clock (non-gated)
    always_ff @(posedge clk or negedge resetn) begin
        if (!resetn)
            collision <= 0;
        else begin
            // Collision occurs if:
            // - Both read ports are enabled and target the same address, OR
            // - A write operation conflicts with either read port.
            if ((ren1 && ren2 && (rad1 == rad2)) ||
                (wen1 && (rad1 == wad1)) ||
                (wen1 && (rad2 == wad1)))
                collision <= 1;
            else
                collision <= 0;
        end
    end

endmodule

output.rtl/reverse_bits.v:
module reverse_bits(
    input  [31:0] num_in,
    output [31:0] num_out
);

    // Reverse the bits of the 32-bit input.
    // The least significant bit (LSB) of num_in becomes the most significant bit (MSB) of num_out,
    // and so on.
    assign num_out = {num_in[0], num_in[1], num_in[2], num_in[3],
                      num_in[4], num_in[5], num_in[6], num_in[7],
                      num_in[8], num_in[9], num_in[10], num_in[11],
                      num_in[12], num_in[13], num_in[14], num_in[15],
                      num_in[16], num_in[17], num_in[18], num_in[19],
                      num_in[20], num_in[21], num_in[22], num_in[23],
                      num_in[24], num_in[25], num_in[26], num_in[27],
                      num_in[28], num_in[29], num_in[30], num_in[31]};

endmodule

