module axis_rgb2ycbcr #(
    parameter PIXEL_WIDTH = 16,
    parameter FIFO_DEPTH = 16
)(
    input  wire            aclk,
    input  wire            aresetn,

    // AXI Stream Slave Interface (Input)
    input  wire [15:0]     s_axis_tdata,
    input  wire            s_axis_tvalid,
    output wire            s_axis_tready,
    input  wire            s_axis_tlast,
    input  wire            s_axis_tuser,

    // AXI Stream Master Interface (Output)
    output wire [15:0]     m_axis_tdata,
    output wire            m_axis_tvalid,
    input  wire            m_axis_tready,
    output wire            m_axis_tlast,
    output wire            m_axis_tuser
);

    // -----------------------------
    // FIFO Buffer (16-depth buffer)
    // -----------------------------
    reg [15:0] fifo_data [0:FIFO_DEPTH-1];
    reg        fifo_tlast [0:FIFO_DEPTH-1];
    reg        fifo_tuser [0:FIFO_DEPTH-1];

    reg [3:0]  write_ptr, read_ptr; // 4-bit pointers for FIFO
    reg        full;
    wire       empty;

    wire       fifo_write = s_axis_tvalid && !full;
    wire       fifo_read  = !empty && m_axis_tready;

    // -----------------------------
    // RGB Extraction 
    // -----------------------------
    reg [7:0] r, g, b;
    always @(posedge aclk) begin
        if (!aresetn) begin
            r <= 0; g <= 0; b <= 0;
        end else if (fifo_write) begin
            r <= {s_axis_tdata[15:11], 3'b0}; // 5-bit to 8-bit
            g <= {s_axis_tdata[10:5],  2'b0}; // 6-bit to 8-bit
            b <= {s_axis_tdata[4:0],   3'b0}; // 5-bit to 8-bit
        end
    end

    // -----------------------------
    // RGB to YCbCr Conversion
    // -----------------------------
    wire [7:0] y_calc  = (( 77 * r + 150 * g +  29 * b) >> 8) + 16;
    wire [7:0] cb_calc = ((-43 * r - 85 * g + 128 * b) >> 8) + 128;
    wire [7:0] cr_calc = ((128 * r - 107 * g - 21 * b) >> 8) + 128;

    reg [7:0] y_reg, cb_reg, cr_reg;
    always @(posedge aclk) begin
        if (!aresetn) begin
            y_reg <= 0; cb_reg <= 0; cr_reg <= 0;
        end else if (fifo_write) begin
            y_reg  <= y_calc;
            cb_reg <= cb_calc;
            cr_reg <= cr_calc;
        end
    end

    // -----------------------------
    // FIFO Buffer Write
    // -----------------------------
    always @(posedge aclk) begin
        if (!aresetn) begin
            write_ptr <= 0;
            full <= 0;
        end else if (fifo_write) begin
            fifo_data[write_ptr] <= {y_reg[7:3], cb_reg[7:2], cr_reg[7:3]}; // Store YCbCr in buffer
            fifo_tlast[write_ptr] <= s_axis_tlast;
            fifo_tuser[write_ptr] <= s_axis_tuser;
            write_ptr <= write_ptr + 1;
            full <= (write_ptr == FIFO_DEPTH-1);
        end
    end

    // -----------------------------
    // FIFO Buffer Read
    // -----------------------------
    always @(posedge aclk) begin
        if (!aresetn) begin
            read_ptr <= 0;
            //empty <= 1;
        end else if (fifo_read) begin
            read_ptr <= read_ptr + 1;
        end
    end
    assign empty = (read_ptr == write_ptr);

    // -----------------------------
    // AXI-Stream Output Signals
    // -----------------------------
    assign s_axis_tready = !full; // Only accept data when FIFO is not full
    assign m_axis_tvalid = !empty; // Only transmit when FIFO has data
    assign m_axis_tdata  = fifo_data[read_ptr];
    assign m_axis_tlast  = fifo_tlast[read_ptr];
    assign m_axis_tuser  = fifo_tuser[read_ptr];

endmodule

output.rtl/axis_rgb2ycbcr.sv:
module axis_rgb2ycbcr #(
    parameter PIXEL_WIDTH = 16,
    parameter FIFO_DEPTH  = 16
)(
    input  wire            aclk,
    input  wire            aresetn,

    // AXI Stream Slave Interface (Input)
    input  wire [15:0]     s_axis_tdata,
    input  wire            s_axis_tvalid,
    output wire            s_axis_tready,
    input  wire            s_axis_tlast,
    input  wire            s_axis_tuser,

    // AXI Stream Master Interface (Output)
    output wire [15:0]     m_axis_tdata,
    output wire            m_axis_tvalid,
    input  wire            m_axis_tready,
    output wire            m_axis_tlast,
    output wire            m_axis_tuser
);

    // FIFO Buffer (16-depth buffer)
    reg [15:0] fifo_data [0:FIFO_DEPTH-1];
    reg        fifo_tlast [0:FIFO_DEPTH-1];
    reg        fifo_tuser [0:FIFO_DEPTH-1];

    reg [3:0]  write_ptr, read_ptr; // 4-bit pointers for FIFO
    reg        full;
    wire       empty;

    // Intermediate registers for RGB extraction and YCbCr conversion
    reg [7:0] r, g, b;
    reg [7:0] y_val, cb_val, cr_val;

    // Combined FIFO write and read process
    always @(posedge aclk) begin
        if (!aresetn) begin
            write_ptr <= 0;
            read_ptr  <= 0;
            full      <= 0;
            // Optional: clear FIFO memory (simulation only)
            // for (int i = 0; i < FIFO_DEPTH; i = i + 1) begin
            //     fifo_data[i]      <= 0;
            //     fifo_tlast[i]     <= 0;
            //     fifo_tuser[i]     <= 0;
            // end
        end else begin
            // Write operation: when input is valid and FIFO is not full
            if (s_axis_tvalid && !full) begin
                // Extract RGB components from input data
                r <= {s_axis_tdata[15:11], 3'b0}; // 5-bit to 8-bit
                g <= {s_axis_tdata[10:5],  2'b0}; // 6-bit to 8-bit
                b <= {s_axis_tdata[4:0],   3'b0}; // 5-bit to 8-bit

                // Compute YCbCr conversion values
                y_val  <= ((77  * r + 150 * g +  29 * b) >> 8) + 16;
                cb_val <= ((-43 * r - 85  * g + 128 * b) >> 8) + 128;
                cr_val <= ((128 * r - 107 * g - 21 * b) >> 8) + 128;

                // Write computed YCbCr pixel to FIFO buffer
                fifo_data[write_ptr]   <= {y_val[7:3], cb_val[7:2], cr_val[7:3]};
                fifo_tlast[write_ptr]  <= s_axis_tlast;
                fifo_tuser[write_ptr]  <= s_axis_tuser;
                write_ptr <= write_ptr + 1;
                full      <= (write_ptr == FIFO_DEPTH - 1);
            end

            // Read operation: when output is ready and FIFO is not empty
            if (m_axis_tready && !empty) begin
                read_ptr <= read_ptr + 1;
            end
        end
    end

    assign empty = (read_ptr == write_ptr);

    // AXI-Stream Output Signals
    assign s_axis_tready = !full;   // Accept data when FIFO is not full
    assign m_axis_tvalid = !empty;  // Transmit when FIFO has data
    assign m_axis_tdata  = fifo_data[read_ptr];
    assign m_axis_tlast  = fifo_tlast[read_ptr];
    assign m_axis_tuser  = fifo_tuser[read_ptr];

endmodule

input.rtl/round_robin_arbiter.sv:
module round_robin_arbiter #(
    parameter N = 4
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,   
    output reg  [N-1:0]     grant   
);

    reg [$clog2(N)-1:0] pointer;
    reg [$clog2(N)-1:0] pointer_next;
    reg found;

    integer i;
    always @(*) begin
        grant        = {N{1'b0}};
        pointer_next = pointer;

        if (req != 0) begin
           found = 1'b0;
            for (i = 0; i < N; i = i + 1) begin
                if (!found && req[(pointer + i) % N] == 1'b1) begin
                    grant[(pointer + i) % N] = 1'b1;

                    pointer_next = (pointer + i + 1) % N;
                    found        = 1'b1;                    
                end
            end
        end
    end

    always @(posedge clk or negedge rstn) begin
        if (!rstn) begin
            pointer <= 0;
        end else begin
            pointer <= pointer_next;
        end
    end

endmodule

output.rtl/round_robin_arbiter.sv:
module round_robin_arbiter #(
    parameter N       = 4,
    parameter TIMEOUT = 16  // Default timeout value (configurable)
)(
    input  wire             clk,
    input  wire             rstn,
    input  wire [N-1:0]     req,               
    input  wire [N-1:0]     priority_level,    // 1 = high priority, 0 = low priority
    output reg  [N-1:0]     grant,             // One-hot grant signal
    output reg             idle                // 1 when no active requests
);

   // Pointer for round-robin arbitration (using log2(N) bits)
   reg [$clog2(N)-1:0] pointer;
   reg [$clog2(N)-1:0] pointer_next;
   reg found;
   integer i;

   // Timeout counters for each channel (32-bit counters)
   reg [31:0] timeout_counter [0:N-1];

   // Combinational block: Determine grant signal and update pointer_next.
   // Also compute the idle signal.
   always @(*) begin
       // If no request is active, idle = 1; otherwise idle = 0.
       idle = ~(|req);
       grant = {N{1'b0}};
       pointer_next = pointer;
       found = 1'b0;

       // First, search for channels with effective high priority.
       // Effective high priority is defined as:
       //    (priority_level == 1) OR (timeout_counter >= TIMEOUT)
       for (i = 0; i < N; i = i + 1) begin
           int idx = (pointer + i) % N;
           if (!found && req[idx] == 1) begin
               if (priority_level[idx] == 1 || timeout_counter[idx] >= TIMEOUT) begin
                   grant[idx] = 1'b1;
                   pointer_next = (pointer + i + 1) % N;
                   found = 1'b1;
               end
           end
       end

       // If no high-priority (or timed-out) channel is found, 
       // then search for low-priority channels.
       if (!found) begin
           for (i = 0; i < N; i = i + 1) begin
               int idx = (pointer + i) % N;
               if (!found && req[idx] == 1) begin
                   // Only consider as low priority if the timeout counter has not expired.
                   if (priority_level[idx] == 0 && timeout_counter[idx] < TIMEOUT) begin
                       grant[idx] = 1'b1;
                       pointer_next = (pointer + i + 1) % N;
                       found = 1'b1;
                   end
               end
           end
       end
   end

   // Sequential block: Update pointer and timeout counters.
   always @(posedge clk or negedge rstn) begin
       if (!rstn) begin
           pointer <= 0;
           integer j;
           for (j = 0; j < N; j = j + 1) begin
               timeout_counter[j] <= 0;
           end
       end else begin
           pointer <= pointer_next;

           // For each channel, update its timeout counter.
           // If a channel's request is active (req) and it is not granted,
           // increment its timeout counter. Otherwise, reset it to 0.
           for (i = 0; i < N; i = i + 1) begin
               if (req[i] == 1 && grant[i] == 0) begin
                   if (timeout_counter[i] < TIMEOUT - 1)
                       timeout_counter[i] <= timeout_counter[i] + 1;
                   else
                       timeout_counter[i] <= TIMEOUT; // Saturate at TIMEOUT
               end else begin
                   timeout_counter[i] <= 0;
               end
           end
       end
   end

endmodule

output.rtl/rounding.sv:
module rounding #(
  parameter WIDTH = 24
)(
  input  logic [WIDTH-1:0] in_data,  // Input value for rounding (magnitude)
  input  logic              sign,   // Sign of input (0: positive, 1: negative)
  input  logic              roundin,// Round bit (guard)
  input  logic              stickyin,// Sticky bit (precision loss in trailing bits)
  input  logic [2:0]        rm,     // Rounding mode select
  output logic [WIDTH-1:0] out_data,// Rounded output value
  output logic             inexact,// Indicates precision loss
  output logic             cout,   // Overflow flag
  output logic             r_up    // Indicates that rounding (up) occurred
);

  // Define supported rounding modes
  localparam RNE = 3'b000; 
  localparam RTZ = 3'b001; 
  localparam RUP = 3'b010; 
  localparam RDN = 3'b011; 
  localparam RMM = 3'b100; 

  // Internal flag to indicate if a rounding increment (or decrement) is needed.
  // For positive numbers, a true flag means add 1; for negative numbers, it means subtract 1.
  logic rounding_up;

  // The maximum representable value for WIDTH bits.
  wire [WIDTH-1:0] max_val = {WIDTH{1'b1}};

  // Assume that the bit being dropped (the rounding bit) is the least significant bit.
  wire round_bit = in_data[0];

  // Determine rounding decision based on mode.
  // For RNE: if guard is 1 then round if either sticky is 1 or (if no sticky then round if the bit to be dropped is 1)
  // For RTZ: no rounding (truncate).
  // For RUP: round if any fractional bits are present.
  // For RDN: for positive numbers, do not round; for negative numbers, round (away from zero) if fractional bits exist.
  // For RMM: round away from zero regardless of sign.
  always_comb begin
    case (rm)
      RNE: rounding_up = roundin && (stickyin || round_bit);
      RTZ: rounding_up = 1'b0;
      RUP: rounding_up = roundin || stickyin;
      RDN: rounding_up = (sign ? (roundin || stickyin) : 1'b0);
      RMM: rounding_up = roundin || stickyin;
      default: rounding_up = 1'b0; // Unsupported mode: default to no rounding (RTZ behavior)
    endcase
  end

  // The rounded output is computed by adding or subtracting 1 based on the sign.
  // For positive numbers, add 1 if rounding_up is true; for negative numbers, subtract 1.
  assign out_data = (sign ? (in_data - rounding_up) : (in_data + rounding_up));

  // Precision loss (inexact) is flagged only when a supported rounding mode is selected.
  // If an unsupported mode is used, we do not signal inexact.
  assign inexact = ((rm == RNE || rm == RTZ || rm == RUP || rm == RDN || rm == RMM) ? (roundin || stickyin) : 1'b0);

  // Detect overflow:
  // For positive numbers, if (in_data + rounding_up) exceeds the maximum representable value, set cout.
  // For negative numbers, if in_data is less than rounding_up (i.e. underflow would occur when subtracting),
  // then set cout.
  assign cout = (sign ? (in_data < rounding_up) : ((in_data + rounding_up) > max_val));

  // r_up indicates that a rounding operation occurred.
  assign r_up = rounding_up;

endmodule

