output.rtl/intra_block.sv:
module intra_block #(
    parameter ROW_COL_WIDTH = 16,
    parameter DATA_WIDTH    = ROW_COL_WIDTH * ROW_COL_WIDTH
)(
    input  logic [DATA_WIDTH-1:0] in_data,  // Input: 256 bits
    output logic [DATA_WIDTH-1:0] out_data // Output: 256 bits rearranged
);

    // Optimized combinational logic:
    // Removed intermediate arrays (r_prime, c_prime, output_index, prev_out_data)
    // and merged the two always_comb blocks into one.
    // This reduces the number of wires/signals used in the combinational path.
    //
    // Note: The mapping function is computed on-the-fly for each bit.
    // For indices i < DATA_WIDTH/2, we use:
    //    r = (i - 2*(i/ROW_COL_WIDTH)) % ROW_COL_WIDTH
    //    c = (i - (i/ROW_COL_WIDTH)) % ROW_COL_WIDTH
    // For indices i >= DATA_WIDTH/2, we use:
    //    r = (i - 2*(i/ROW_COL_WIDTH) - 1) % ROW_COL_WIDTH
    //    c = (i - (i/ROW_COL_WIDTH) - 1) % ROW_COL_WIDTH
    //
    // The new index is computed as: new_index = r * ROW_COL_WIDTH + c.
    // The output bit is then taken from in_data[new_index].

    always_comb begin
        for (int i = 0; i < DATA_WIDTH; i++) begin
            if (i < DATA_WIDTH/2) begin
                int r = (i - 2*(i/ROW_COL_WIDTH)) % ROW_COL_WIDTH;
                int c = (i - (i/ROW_COL_WIDTH)) % ROW_COL_WIDTH;
                out_data[i] = in_data[r * ROW_COL_WIDTH + c];
            end else begin
                int r = (i - 2*(i/ROW_COL_WIDTH) - 1) % ROW_COL_WIDTH;
                int c = (i - (i/ROW_COL_WIDTH) - 1) % ROW_COL_WIDTH;
                out_data[i] = in_data[r * ROW_COL_WIDTH + c];
            end
        end
    end

endmodule

output.rtl/sdram_controller.sv:
module sdram_controller (
    input  logic               clk,
    input  logic               reset,
    input  logic [23:0]        addr,
    input  logic [15:0]        data_in,
    input  logic               read,
    input  logic               write,
    input  logic [15:0]        sdram_dq,  // SDRAM data output (for write operations)
    output logic [15:0]        data_out,  // Data output from read operations
    output logic               sdram_clk,
    output logic               sdram_cke,
    output logic               sdram_cs,
    output logic               sdram_ras,
    output logic               sdram_cas,
    output logic               sdram_we,
    output logic [23:0]        sdram_addr,
    output logic [1:0]         sdram_ba,
    output logic [15:0]        dq_out     // SDRAM data input (for read operations)
);

  //-------------------------------------------------------------------------
  // State Encoding
  //-------------------------------------------------------------------------
  typedef enum logic [2:0] {
    INIT     = 3'd0,
    IDLE     = 3'd1,
    ACTIVATE = 3'd2,
    READ     = 3'd3,
    WRITE    = 3'd4,
    REFRESH  = 3'd5
  } state_t;

  state_t current_state, next_state;

  // Parameters for timing
  parameter INIT_CYCLES  = 10;
  parameter IDLE_TIMEOUT = 1024;

  // Counters
  logic [3:0]   init_counter;   // 4 bits sufficient for 10 cycles
  logic [10:0]  idle_counter;   // 11 bits sufficient for 1024 cycles

  //-------------------------------------------------------------------------
  // Next State Logic
  //-------------------------------------------------------------------------
  always_comb begin
    next_state = current_state;  // default: hold state

    case (current_state)
      INIT: begin
        if (init_counter == INIT_CYCLES - 1)
          next_state = IDLE;
        else
          next_state = INIT;
      end

      IDLE: begin
        if (read || write) begin
          next_state = ACTIVATE;
        end
        else if (idle_counter == IDLE_TIMEOUT - 1) begin
          next_state = REFRESH;
        end
        else begin
          next_state = IDLE;
        end
      end

      ACTIVATE: begin
        // One-cycle delay; then decide based on input signals.
        if (read)
          next_state = READ;
        else if (write)
          next_state = WRITE;
        else
          next_state = IDLE;
      end

      READ:  next_state = IDLE;
      WRITE: next_state = IDLE;
      REFRESH: next_state = IDLE;
      default: next_state = IDLE;
    endcase
  end

  //-------------------------------------------------------------------------
  // State Register and Counter Updates
  //-------------------------------------------------------------------------
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      current_state <= INIT;
      init_counter  <= 0;
      idle_counter  <= 0;
    end
    else begin
      current_state <= next_state;

      case (current_state)
        INIT: begin
          if (init_counter == INIT_CYCLES - 1)
            init_counter <= 0;
          else
            init_counter <= init_counter + 1;
          idle_counter <= 0;
        end

        IDLE: begin
          if (read || write)
            idle_counter <= 0;
          else if (idle_counter < IDLE_TIMEOUT - 1)
            idle_counter <= idle_counter + 1;
          else
            idle_counter <= 0;
        end

        ACTIVATE: begin
          idle_counter <= 0;
        end

        READ: begin
          idle_counter <= 0;
        end

        WRITE: begin
          idle_counter <= 0;
        end

        REFRESH: begin
          idle_counter <= 0;
        end

        default: begin
          init_counter  <= 0;
          idle_counter  <= 0;
        end
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Output Logic Based on Current State
  //-------------------------------------------------------------------------
  always_comb begin
    // Default assignments
    data_out    = 16'b0;
    sdram_clk   = clk;
    sdram_cke   = 1'b1;
    sdram_cs    = 1'b0;
    sdram_ras   = 1'b0;
    sdram_cas   = 1'b0;
    sdram_we    = 1'b1;  // Active low
    sdram_addr  = 24'b0;
    sdram_ba    = 2'b0;
    sdram_dq    = 16'b0;
    dq_out      = 16'b0;

    case (current_state)
      INIT: begin
        // Initialization sequence: drive safe state for 10 cycles.
        sdram_cs    = 1'b1;
        sdram_ras   = 1'b1;
        sdram_cas   = 1'b1;
        sdram_we    = 1'b1;
        sdram_addr  = 24'b0;
        sdram_ba    = 2'b0;
        sdram_dq    = 16'b0;
      end

      IDLE: begin
        // Idle state: hold SDRAM in low-power state.
        sdram_cs    = 1'b0;
        sdram_ras   = 1'b0;
        sdram_cas   = 1'b0;
        sdram_we    = 1'b1;
        sdram_addr  = 24'b0;
        sdram_ba    = 2'b0;
        sdram_dq    = 16'b0;
      end

      ACTIVATE: begin
        // Activation command: assert CS, RAS, and CAS.
        sdram_cs    = 1'b1;
        sdram_ras   = 1'b1;
        sdram_cas   = 1'b1;
        sdram_we    = 1'b1;
        sdram_addr  = addr;
        sdram_ba    = 2'b0;
        sdram_dq    = 16'b0;
      end

      READ: begin
        // Read command: assert CS, CKE, with RAS low, CAS high, WE low.
        sdram_cs    = 1'b1;
        sdram_cke   = 1'b1;
        sdram_ras   = 1'b0;
        sdram_cas   = 1'b1;
        sdram_we    = 1'b0;
        sdram_addr  = addr;
        sdram_ba    = 2'b0;
        // Capture data from dq_out into data_out.
        data_out    = dq_out;
      end

      WRITE: begin
        // Write command: assert CS, CKE, with RAS low, CAS high, WE high.
        sdram_cs    = 1'b1;
        sdram_cke   = 1'b1;
        sdram_ras   = 1'b0;
        sdram_cas   = 1'b1;
        sdram_we    = 1'b1;
        sdram_addr  = addr;
        sdram_ba    = 2'b0;
        sdram_dq    = data_in;
      end

      REFRESH: begin
        // Auto-refresh command: assert CS, RAS, CAS; WE low; CKE high.
        sdram_cs    = 1'b1;
        sdram_cke   = 1'b1;
        sdram_ras   = 1'b1;
        sdram_cas   = 1'b1;
        sdram_we    = 1'b0;
        sdram_addr  = 24'b0;
        sdram_ba    = 2'b0;
        sdram_dq    = 16'b0;
      end

      default: begin
        // Default safe state.
        sdram_cs    = 1'b0;
        sdram_ras   = 1'b0;
        sdram_cas   = 1'b0;
        sdram_we    = 1'b1;
        sdram_addr  = 24'b0;
        sdram_ba    = 2'b0;
        sdram_dq    = 16'b0;
      end
    endcase
  end

endmodule

output.rtl/secure_read_write_bus_interface.v:
module secure_read_write_bus_interface #(
    parameter p_configurable_key = 8'hAA,
    parameter p_data_width       = 8,
    parameter p_addr_width       = 8
)(
    input  wire                      i_capture_pulse,  // Clock for capturing inputs
    input  wire                      i_read_write_enable, // 1: read, 0: write
    input  wire                      i_reset_bar,       // Asynchronous active-low reset
    input  wire [p_addr_width-1:0]   i_addr,            // Target address for read/write
    input  wire [p_data_width-1:0]   i_data_in,         // Data to be written (for write ops)
    input  wire [7:0]                i_key_in,          // 8-bit key provided for access
    output reg  [p_data_width-1:0]   o_data_out,        // Data output during read op
    output reg                       o_error            // Error flag: 1 if key mismatch
);

    // Memory array for storing data
    reg [p_data_width-1:0] mem [(1<<p_addr_width)-1:0];

    // Process for read/write operations and asynchronous reset
    always @(posedge i_capture_pulse or negedge i_reset_bar) begin
        if (!i_reset_bar) begin
            // Asynchronous reset: clear all memory and outputs
            integer j;
            for (j = 0; j < (1<<p_addr_width); j = j + 1) begin
                mem[j] <= 0;
            end
            o_data_out <= 0;
            o_error    <= 0;
        end else begin
            if (i_read_write_enable) begin
                // Read operation: if key matches, output memory data; else flag error
                if (i_key_in == p_configurable_key) begin
                    o_data_out <= mem[i_addr];
                    o_error    <= 0;
                end else begin
                    o_data_out <= 0;
                    o_error    <= 1;
                end
            end else begin
                // Write operation: if key matches, write data to memory; else flag error
                if (i_key_in == p_configurable_key) begin
                    mem[i_addr] <= i_data_in;
                    o_data_out <= 0;
                    o_error    <= 0;
                end else begin
                    o_data_out <= 0;
                    o_error    <= 1;
                end
            end
        end
    end

endmodule

output.rtl/secure_read_write_register_bank.v:
module secure_read_write_register_bank #(
  parameter int p_address_width = 8,
  parameter int p_data_width    = 8,
  parameter logic [p_data_width-1:0] p_unlock_code_0 = 8'hAB,
  parameter logic [p_data_width-1:0] p_unlock_code_1 = 8'hCD
)(
  input  logic                   i_capture_pulse,
  input  logic                   i_rst_n,
  input  logic [p_address_width-1:0] i_addr,
  input  logic [p_data_width-1:0]    i_data_in,
  input  logic                   i_read_write_enable, // 0: write, 1: read
  output logic [p_data_width-1:0]    o_data_out
);

  // State encoding:
  //  2'b00 : LOCKED
  //  2'b01 : WAIT_FOR_UNLOCK1 (unlock code 0 has been written correctly)
  //  2'b10 : UNLOCKED (both unlock codes have been written in immediate succession)
  localparam LOCKED          = 2'd0;
  localparam WAIT_FOR_UNLOCK1 = 2'd1;
  localparam UNLOCKED        = 2'd2;

  reg [1:0] state_r;

  // Memory array for register bank.
  // Size is 2^(p_address_width) registers. Assumes p_address_width is a constant.
  reg [p_data_width-1:0] reg_bank [0:((1 << p_address_width) - 1)];

  // Combined state machine and register bank operations.
  // Operations are triggered on the rising edge of i_capture_pulse.
  // i_rst_n is asynchronous active low.
  always_ff @(posedge i_capture_pulse or negedge i_rst_n) begin
    if (!i_rst_n) begin
      state_r <= LOCKED;
    end
    else begin
      if (i_read_write_enable == 0) begin  // Write operation
        if (state_r == LOCKED) begin
          // Only address 0 is allowed in LOCKED state for initiating unlock.
          if (i_addr == 0) begin
            if (i_data_in == p_unlock_code_0)
              state_r <= WAIT_FOR_UNLOCK1;
            else
              state_r <= LOCKED;
          end
          // Writing to address 1 while locked is invalid.
          else if (i_addr == 1) begin
            state_r <= LOCKED;
          end
          // For any other address, no write is allowed.
        end
        else if (state_r == WAIT_FOR_UNLOCK1) begin
          // In WAIT_FOR_UNLOCK1 state, only address 1 is allowed.
          if (i_addr == 1) begin
            if (i_data_in == p_unlock_code_1)
              state_r <= UNLOCKED;
            else
              state_r <= LOCKED;
          end
          else begin
            // Any write to an address other than 1 resets the unlock sequence.
            state_r <= LOCKED;
          end
        end
        else if (state_r == UNLOCKED) begin
          // When unlocked, allow write to any address.
          // Note: Addresses 0 and 1 remain write-only (read always returns 0).
          reg_bank[i_addr] <= i_data_in;
        end
        // For write operations, o_data_out is forced to 0.
        o_data_out <= '0;
      end
      else begin  // Read operation
        // Reading is allowed only when unlocked and for addresses other than 0 and 1.
        if (state_r == UNLOCKED && (i_addr != 0) && (i_addr != 1))
          o_data_out <= reg_bank[i_addr];
        else
          o_data_out <= '0;
      end
    end
  end

endmodule

output.rtl/secure_variable_timer.v:
module secure_variable_timer (
    input wire i_clk,           // Clock signal (rising-edge triggered)
    input wire i_rst_n,         // Active-low synchronous reset signal
    input wire i_data_in,       // Serial data input
    output reg [3:0] o_time_left, // 4-bit output showing remaining time during counting phase
    output reg o_processing,    // Asserted high when the timer is actively counting
    output reg o_completed,     // Asserted high when the timer completes its delay
    input wire i_ack            // Acknowledgment signal to reset after completion
);

    // Define FSM states
    localparam IDLE     = 2'b00,
               CONFIG   = 2'b01,
               COUNT    = 2'b10,
               DONE     = 2'b11;

    // Internal registers
    reg [1:0] state;           // FSM state register
    reg [3:0] shift_reg;       // 4-bit shift register for detecting the "1101" start sequence
    reg [3:0] delay_reg;       // 4-bit register to hold the delay value (configured after "1101")
    reg [1:0] config_counter;  // Counter for reading 4 bits in CONFIG state
    reg [9:0] cycle_counter;   // 10-bit counter to count within each 1000-cycle block
    reg [3:0] block_counter;   // Counts how many 1000-cycle blocks have elapsed

    // FSM and main logic
    always @(posedge i_clk or negedge i_rst_n) begin
        if (!i_rst_n) begin
            state          <= IDLE;
            shift_reg      <= 4'b0000;
            config_counter <= 0;
            cycle_counter  <= 0;
            block_counter  <= 0;
            delay_reg      <= 4'b0000;
            o_processing   <= 0;
            o_completed    <= 0;
            o_time_left    <= 4'b0000;
        end else begin
            case (state)
                IDLE: begin
                    // In IDLE, shift in i_data_in to detect the "1101" start sequence.
                    shift_reg <= {shift_reg[2:0], i_data_in};
                    if (shift_reg == 4'b1101) begin
                        state <= CONFIG;
                    end
                end

                CONFIG: begin
                    // In CONFIG state, read the next 4 bits (MSB first) to configure the delay.
                    if (config_counter < 4) begin
                        // Shift right: the first bit received becomes the MSB.
                        delay_reg     <= {delay_reg[2:0], i_data_in};
                        config_counter <= config_counter + 1;
                    end else begin
                        config_counter <= 0;
                        state          <= COUNT;
                        // Initialize counters for the counting phase.
                        cycle_counter  <= 0;
                        block_counter  <= 0;
                    end
                end

                COUNT: begin
                    // Count cycles within the current 1000-cycle block.
                    if (cycle_counter == 10'd1000) begin
                        cycle_counter  <= 0;
                        block_counter  <= block_counter + 1;
                    end else begin
                        cycle_counter <= cycle_counter + 1;
                    end

                    // Update o_time_left at the beginning of each new 1000-cycle block.
                    // o_time_left = delay_reg - block_counter.
                    if (cycle_counter == 0)
                        o_time_left <= delay_reg - block_counter;

                    // Assert o_processing during the counting phase.
                    o_processing <= 1;

                    // Check if the counting phase is complete.
                    // The timer counts for (delay_reg + 1) * 1000 cycles.
                    if (block_counter == delay_reg + 1)
                        state <= DONE;
                end

                DONE: begin
                    // In DONE state, assert o_completed and de-assert o_processing.
                    o_completed  <= 1;
                    o_processing <= 0;
                    // Wait for the acknowledgment signal (i_ack) to reset the module.
                    if (i_ack) begin
                        state          <= IDLE;
                        // Clear outputs and internal registers.
                        o_completed    <= 0;
                        o_time_left    <= 4'b0000;
                        delay_reg      <= 4'b0000;
                        cycle_counter  <= 0;
                        block_counter  <= 0;
                    end
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/binary_to_one_hot_decoder_sequential:
module binary_to_one_hot_decoder_sequencial #(
  parameter BINARY_WIDTH = 5,
  parameter OUTPUT_WIDTH = 32
)(
  input  wire                     i_clk,
  input  wire                     i_rstb,
  input  wire [BINARY_WIDTH-1:0]  i_binary_in,
  output reg  [OUTPUT_WIDTH-1:0]  o_one_hot_out
);

  // Ensure that OUTPUT_WIDTH is large enough to represent all values up to 2^BINARY_WIDTH - 1
  localparam integer MIN_OUTPUT_WIDTH = (1 << BINARY_WIDTH);

  initial begin
    if (OUTPUT_WIDTH < MIN_OUTPUT_WIDTH)
      $error("OUTPUT_WIDTH must be at least 2^BINARY_WIDTH");
  end

  integer j;
  reg [OUTPUT_WIDTH-1:0] one_hot;

  always @(posedge i_clk or negedge i_rstb) begin
    if (!i_rstb)
      o_one_hot_out <= 0;
    else begin
      one_hot = 0;
      for (j = 0; j < OUTPUT_WIDTH; j = j + 1) begin
        if (j == i_binary_in)
          one_hot[j] = 1;
        else
          one_hot[j] = 0;
      end
      o_one_hot_out <= one_hot;
    end
  end

endmodule

