            state   <= IDLE;
            i       <= 0;
            j       <= 0;
            done    <= 0;
            step    <= 0;
            key     <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        // Load the array from in_data
                        for (int k = 0; k < N; k = k + 1) begin
                            array[k] <= in_data[(k+1)*WIDTH-1 -: WIDTH];
                        end
                        // Start insertion sort from the second element (first element is already sorted)
                        i <= 1;
                        j <= i - 1;  // j = 0
                        state <= SORTING;
                        done <= 0;
                    end
                end

                SORTING: begin
                    // Use a case statement on 'step' to implement the insertion sort steps.
                    case (step)
                        0: begin
                            // Step 0: Read the key element from array[i]
                            key <= array[i];
                            step <= 1;
                        end

                        1: begin
                            // Step 1: Check if shifting is needed.
                            // For j==0, compare with the first element.
                            if (j == 0) begin
                                if (array[0] > key) begin
                                    // Shift array[0] to array[1]
                                    array[1] <= array[0];
                                end
                                step <= 2;  // Proceed to insertion step
                            end else begin
                                if (array[j] > key) begin
                                    // Shift array[j] to array[j+1] and decrement j
                                    array[j+1] <= array[j];
                                    j <= j - 1;
                                    step <= 1;  // Re-check condition after shifting
                                end else begin
                                    step <= 2;  // Correct position found; proceed to insertion
                                end
                            end
                        end

                        2: begin
                            // Step 2: Insert the key element into its correct position
                            array[j+1] <= key;
                            if (i < N-1) begin
                                // Prepare for the next element
                                i <= i + 1;
                                j <= i - 1;  // Set j to i-1 for the next iteration
                                step <= 0;  // Restart the steps for the next element
                            end else begin
                                // All elements have been processed; move to completion step
                                step <= 3;
                            end
                        end

                        3: begin
                            // Step 3: Transition to DONE state
                            state <= DONE;
                        end
                    endcase
                end

                DONE: begin
                    // Output the sorted array and assert the done signal
                    for (int m = 0; m < N; m = m + 1) begin
                        out_data[(m+1)*WIDTH-1 -: WIDTH] <= array[m];
                    end
                    done <= 1;
                end

                default: begin
                    state <= IDLE;
                end
            endcase
        end
    end

endmodule

module sorting_engine #(
    parameter N = 8,     
    parameter WIDTH = 8  
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    // Define FSM states
    localparam IDLE = 2'd0,
               LOAD = 2'd1,
               SORT = 2'd2,
               DONE = 2'd3;

    reg [1:0] state;
    reg [WIDTH-1:0] data_array [0:N-1];
    // pass_cnt counts the current pass (0 to N-1)
    reg [$clog2(N+1)-1:0] pass_cnt;
    // pair_idx counts the current comparison in the pass
    reg [$clog2(N/2+1)-1:0] pair_idx;

    // For even-numbered passes (pass_cnt[0]==0) we have N/2 comparisons.
    // For odd-numbered passes, we have (N/2 - 1) comparisons.
    wire [$clog2(N/2+1)-1:0] pairs_in_this_pass;
    assign pairs_in_this_pass = (pass_cnt[0] == 1'b0) ? (N/2) : ((N/2) - 1);

    // Synchronous state machine
    always_ff @(posedge clk or posedge rst) begin
        if (rst) begin
            state         <= IDLE;
            pass_cnt      <= 0;
            pair_idx      <= 0;
            done          <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (start)
                        state <= LOAD;
                    // Remain in IDLE until start is asserted.
                end

                LOAD: begin
                    // Load the input data into the internal array.
                    // Each element is WIDTH bits wide.
                    integer i;
                    for (i = 0; i < N; i = i + 1) begin
                        data_array[i] <= in_data[WIDTH*(i+1)-1 -: WIDTH];
                    end
                    pass_cnt <= 0;
                    pair_idx <= 0;
                    state    <= SORT;
                end

                SORT: begin
                    // In each clock cycle, perform one compare-and-swap.
                    if (pair_idx < pairs_in_this_pass) begin
                        // Even pass: compare even-indexed pairs.
                        if (pass_cnt[0] == 1'b0) begin
                            if (data_array[2*pair_idx] < data_array[2*pair_idx+1]) begin
                                reg [WIDTH-1:0] temp;
                                temp = data_array[2*pair_idx];
                                data_array[2*pair_idx] <= data_array[2*pair_idx+1];
                                data_array[2*pair_idx+1] <= temp;
                            end
                        end
                        // Odd pass: compare odd-indexed pairs.
                        else begin
                            if (data_array[2*pair_idx+1] < data_array[2*pair_idx+2]) begin
                                reg [WIDTH-1:0] temp;
                                temp = data_array[2*pair_idx+1];
                                data_array[2*pair_idx+1] <= data_array[2*pair_idx+2];
                                data_array[2*pair_idx+2] <= temp;
                            end
                        end
                        pair_idx <= pair_idx + 1;
                    end
                    else begin
                        // End of current pass: move to next pass or finish.
                        if (pass_cnt < N-1) begin
                            pass_cnt <= pass_cnt + 1;
                            pair_idx <= 0;
                        end
                        else begin
                            // Last pass complete; move to DONE state.
                            state <= DONE;
                        end
                    end
                end

                DONE: begin
                    // Pack the sorted array into out_data.
                    // According to the latency example, the sorted order is descending:
                    // the largest element goes to the MSB.
                    integer i;
                    reg [N*WIDTH-1:0] temp_out;
                    temp_out = 0;
                    for (i = 0; i < N; i = i + 1) begin
                        temp_out = {temp_out, data_array[N-1-i]};
                    end
                    out_data <= temp_out;
                    done     <= 1;  // Assert done for one clock cycle.
                    state    <= IDLE;
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

module sorting_engine #(
    parameter N = 8,          // number of elements to sort
    parameter WIDTH = 8       // bit-width of each element
)(
    input  wire                clk,
    input  wire                rst,
    input  wire                start,
    input  wire [N*WIDTH-1:0]  in_data,
    output reg                 done,
    output reg [N*WIDTH-1:0]   out_data
);

    //-----------------------------------------------------
    // State machine definitions
    //-----------------------------------------------------
    localparam [3:0]
        S_IDLE         = 4'd0,
        S_LOAD_INPUT   = 4'd1,
        S_FIND_MAX     = 4'd2,
        S_COUNT        = 4'd3,
        S_PREFIX_SUM   = 4'd4,
        S_BUILD_OUTPUT = 4'd5,
        S_COPY_OUTPUT  = 4'd6,
        S_DONE         = 4'd7;

    //-----------------------------------------------------
    // Registered signals (updated in sequential always)
    //-----------------------------------------------------
    reg [3:0]           current_state;
    reg [WIDTH-1:0]     data_array [0:N-1];
    reg [WIDTH-1:0]     out_array  [0:N-1];
    reg [$clog2(N):0]   count_array[0:(1<<WIDTH)-1];

    reg [WIDTH-1:0]     max_val;
    reg [$clog2(N):0]   load_cnt;
    reg [$clog2(N):0]   find_cnt;
    reg [$clog2(N):0]   count_cnt;
    reg [WIDTH-1:0]     prefix_cnt;
    reg [$clog2(N):0]   build_cnt;
    reg [$clog2(N):0]   copy_cnt;

    //-----------------------------------------------------
    // Wires/reg for "next" values (computed combinationally)
    //-----------------------------------------------------
    reg [3:0]           next_state;

    // Arrays get "shadow copies" for combinational updates
    reg [WIDTH-1:0]     next_data_array [0:N-1];
    reg [WIDTH-1:0]     next_out_array  [0:N-1];
    reg [$clog2(N):0]   next_count_array[0:(1<<WIDTH)-1];

    reg [WIDTH-1:0]     next_max_val;
    reg [$clog2(N):0]   next_load_cnt;
    reg [$clog2(N):0]   next_find_cnt;
    reg [$clog2(N):0]   next_count_cnt;
    reg [WIDTH-1:0]     next_prefix_cnt;
    reg [$clog2(N):0]   next_build_cnt;
    reg [$clog2(N):0]   next_copy_cnt;

    reg                 next_done;
    reg [N*WIDTH-1:0]   next_out_data;
    integer rev_idx;
    reg [WIDTH-1:0]     val;
    reg [$clog2(N):0]   pos;

    integer i;

    // Combinational logic: compute next state and next values
    always @(*) begin
        // Default assignments: copy current registers
        next_state         = current_state;
        next_load_cnt      = load_cnt;
        next_find_cnt      = find_cnt;
        next_count_cnt     = count_cnt;
        next_prefix_cnt    = prefix_cnt;
        next_build_cnt     = build_cnt;
        next_copy_cnt      = copy_cnt;
        next_max_val       = max_val;
        next_done          = 1'b0;
        next_out_data      = out_data;

        // Default: copy arrays
        for (i = 0; i < N; i = i + 1) begin
            next_data_array[i] = data_array[i];
            next_out_array[i]  = out_array[i];
        end
        for (i = 0; i < (1<<WIDTH); i = i + 1) begin
            next_count_array[i] = count_array[i];
        end

        case (current_state)
            S_IDLE: begin
                if (start) begin
                    next_state         = S_LOAD_INPUT;
                    next_load_cnt      = 0;
                    // Reset other counters
                    next_find_cnt      = 0;
                    next_count_cnt     = 0;
                    next_prefix_cnt    = 0;
                    next_build_cnt     = 0;
                    next_copy_cnt      = 0;
                end
            end

            S_LOAD_INPUT: begin
                next_load_cnt = load_cnt + 1;
                // Copy existing data_array then update the current index with new slice from in_data
                for (i = 0; i < N; i = i + 1)
                    next_data_array[i] = data_array[i];
                next_data_array[load_cnt] = in_data[WIDTH*(load_cnt+1)-1 -: WIDTH];
                if (load_cnt == N-1)
                    next_state = S_FIND_MAX;
                else
                    next_state = S_LOAD_INPUT;
            end

            S_FIND_MAX: begin
                next_find_cnt = find_cnt + 1;
                // Update max_val if current element is greater
                if (data_array[find_cnt] > max_val)
                    next_max_val = data_array[find_cnt];
                else
                    next_max_val = max_val;
                if (find_cnt == N-1)
                    next_state = S_COUNT;
                else
                    next_state = S_FIND_MAX;
            end

            S_COUNT: begin
                next_count_cnt = count_cnt + 1;
                // Copy current histogram then increment count for current element
                for (i = 0; i < (1<<WIDTH); i = i + 1)
                    next_count_array[i] = count_array[i];
                val = data_array[count_cnt];
                next_count_array[val] = count_array[val] + 1;
                if (count_cnt == N-1)
                    next_state = S_PREFIX_SUM;
                else
                    next_state = S_COUNT;
            end

            S_PREFIX_SUM: begin
                next_prefix_cnt = prefix_cnt + 1;
                // Copy current histogram then update cumulative sum at current index
                for (i = 0; i < (1<<WIDTH); i = i + 1)
                    next_count_array[i] = count_array[i];
                if (prefix_cnt == 0)
                    next_count_array[0] = count_array[0];
                else
                    next_count_array[prefix_cnt] = count_array[prefix_cnt] + count_array[prefix_cnt-1];
                if (prefix_cnt == max_val)
                    next_state = S_BUILD_OUTPUT;
                else
                    next_state = S_PREFIX_SUM;
            end

            S_BUILD_OUTPUT: begin
                next_build_cnt = build_cnt + 1;
                // Determine index in data_array to process (iterate from last to first)
                rev_idx = N - 1 - build_cnt;
                val = data_array[rev_idx];
                pos = count_array[val];
                // Place the value in the correct position in out_array
                next_out_array[pos - 1] = val;
                // Decrement the count in the histogram
                next_count_array[val] = count_array[val] - 1;
                if (build_cnt == N-1)
                    next_state = S_COPY_OUTPUT;
                else
                    next_state = S_BUILD_OUTPUT;
            end

            S_COPY_OUTPUT: begin
                next_copy_cnt = copy_cnt + 1;
                // Pack out_array into out_data bus
                next_out_data = {N*WIDTH{1'b0}};
                for (i = 0; i < N; i = i + 1)
                    next_out_data((i+1)*WIDTH-1:i*WIDTH) = out_array[i];
                if (copy_cnt == N-1)
                    next_state = S_DONE;
                else
                    next_state = S_COPY_OUTPUT;
            end

            S_DONE: begin
                next_done = 1'b1;
                next_state = S_IDLE;
            end

            default: begin
                next_state = S_IDLE;
            end
        endcase
    end

    // Sequential logic: update state and registers on clock edge
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            current_state <= S_IDLE;
            done          <= 1'b0;
            out_data      <= {N*WIDTH{1'b0}};
            max_val       <= {WIDTH{1'b0}};

            load_cnt      <= 0;
            find_cnt      <= 0;
            count_cnt     <= 0;
            prefix_cnt    <= 0;
            build_cnt     <= 0;
            copy_cnt      <= 0;

            // Clear arrays
            for (i = 0; i < N; i = i + 1) begin
                data_array[i] <= {WIDTH{1'b0}};
                out_array[i]  <= {WIDTH{1'b0}};
            end
            for (i = 0; i < (1<<WIDTH); i = i + 1)
                count_array[i] <= {($clog2(N)+1){1'b0}};
        end else begin
            current_state <= next_state;
            load_cnt      <= next_load_cnt;
            find_cnt      <= next_find_cnt;
            count_cnt     <= next_count_cnt;
            prefix_cnt    <= next_prefix_cnt;
            build_cnt     <= next_build_cnt;
            copy_cnt      <= next_copy_cnt;
            max_val       <= next_max_val;
            done          <= next_done;
            out_data      <= next_out_data;

            // Update arrays
            for (i = 0; i < N; i = i + 1) begin
                data_array[i] <= next_data_array[i];
                out_array[i]  <= next_out_array[i];
            end
            for (i = 0; i < (1<<WIDTH); i = i + 1)
                count_array[i] <= next_count_array[i];
        end
    end

endmodule

