output.rtl/soundgenerator.sv:
module soundgenerator #(
	parameter  CLOCK_HZ = 10_000_000
)(
	input wire clk,                                         // Input clock (10 MHz)
	input wire nrst,                                        // Active-low asynchronous reset
	input wire start,                                       // Start signal for sound generation
	input wire finish,                                      // Finish signal to end operation
	input wire [15:0] sond_dur_ms_i,                        // Duration in milliseconds for sound generation
	input wire [15:0] half_period_us_i,                     // Half-period (in microseconds) for soundwave frequency
	output wire soundwave_o,                                // Generated soundwave output
	output wire busy,                                       // Indicates that the system is active (generating sound)
	output wire done                                        // Indicates that the sound generation operation is complete
);

	//---------------------------------------------------------------------
	// Instantiate strobe generators for millisecond and microsecond ticks.
	//---------------------------------------------------------------------
	wire tick_milli;  // Pulse every 1 ms (1000 µs)
	wire tick_micro;  // Pulse every 1 µs

	// TickMilli: strobe every 1000 µs (1 ms)
	strob_gen #(
		.CLOCK_HZ(10_000_000),
		.PERIOD_US(1000)
	) tickMilli (
		.clk   (clk),
		.nrst  (nrst),
		.enable(1'b1),
		.strobe_o(tick_milli)
	);

	// tickMicro: strobe every 1 µs
	strob_gen #(
		.CLOCK_HZ(10_000_000),
		.PERIOD_US(1)
	) tickMicro (
		.clk   (clk),
		.nrst  (nrst),
		.enable(1'b1),
		.strobe_o(tick_micro)
	);

	//---------------------------------------------------------------------
	// Internal registers and wires
	//---------------------------------------------------------------------
	// busy_reg indicates if sound generation is active.
	// done_reg generates a pulse when busy transitions from high to low.
	// soundwave_reg holds the current state of the square wave.
	// duration_counter counts the remaining milliseconds.
	// halfperiod_timer counts down microseconds for the half-period.
	reg busy_reg, done_reg, soundwave_reg;
	reg [15:0] duration_counter;
	reg [15:0] halfperiod_timer;
	reg busy_prev;  // To detect falling edge of busy

	// Output assignments: soundwave_o is active only when busy.
	assign soundwave_o = busy_reg ? soundwave_reg : 1'b0;
	assign busy         = busy_reg;
	assign done         = done_reg;

	//---------------------------------------------------------------------
	// Main sequential logic
	//---------------------------------------------------------------------
	always @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			// Asynchronous reset: clear all internal states.
			busy_reg     <= 1'b0;
			done_reg     <= 1'b0;
			busy_prev    <= 1'b0;
			duration_counter <= 16'd0;
			halfperiod_timer <= 16'd0;
			soundwave_reg <= 1'b0;
		end
		else begin
			// Save previous busy state for done pulse detection.
			busy_prev <= busy_reg;

			//-----------------------------------------------------------------
			// Check finish condition: if finish is asserted, immediately stop.
			//-----------------------------------------------------------------
			if (finish) begin
				busy_reg     <= 1'b0;
				duration_counter <= 16'd0;
				halfperiod_timer <= 16'd0;
				soundwave_reg <= 1'b0;
			end
			else begin
				//-----------------------------------------------------------------
				// If start is asserted, initialize the system and start generation.
				//-----------------------------------------------------------------
				if (start) begin
					busy_reg     <= 1'b1;
					duration_counter <= sond_dur_ms_i;
					halfperiod_timer <= half_period_us_i;
					soundwave_reg <= 1'b0;
				end

				//-----------------------------------------------------------------
				// Only update counters and generate soundwave when busy.
				//-----------------------------------------------------------------
				if (busy_reg) begin
					// Decrement the millisecond duration counter on each tick_milli.
					if (tick_milli) begin
						duration_counter <= duration_counter - 1;
					end

					// Decrement the half-period timer on each tick_micro.
					if (tick_micro) begin
						if (halfperiod_timer == 16'd0) begin
							// Toggle the soundwave output to generate a square wave.
							soundwave_reg <= ~soundwave_reg;
							// Reload the halfperiod timer.
							halfperiod_timer <= half_period_us_i;
						end
						else begin
							halfperiod_timer <= halfperiod_timer - 1;
						end
					end
				end
				else begin
					// Ensure soundwave output is 0 when not busy.
					soundwave_reg <= 1'b0;
				end

				//-----------------------------------------------------------------
				// Generate a done pulse when busy goes from high to low.
				//-----------------------------------------------------------------
				if (busy_prev && !busy_reg)
					done_reg <= 1'b1;
				else
					done_reg <= 1'b0;
			end
		end
	end

endmodule

//---------------------------------------------------------------------
// strob_gen module: Generates a periodic strobe signal.
//---------------------------------------------------------------------
module strob_gen #(
	parameter CLOCK_HZ	= 10_000_000,
	parameter PERIOD_US	= 100
)(
	input wire  clk,
	input wire  nrst,
	input wire  enable,
	output reg  strobe_o
);

	//---------------------------------------------------------------------
	// Calculate the delay value (number of clock cycles) for the strobe.
	// DELAY = (CLOCK_HZ / 1,000,000) * PERIOD_US
	//---------------------------------------------------------------------
	localparam integer DELAY = (CLOCK_HZ / 1_000_000) * PERIOD_US;

	reg [31:0] count;

	always @(posedge clk or negedge nrst) begin
		if (!nrst) begin
			count     <= DELAY;
			strobe_o  <= 1'b0;
		end
		else begin
			if (!enable) begin
				// When disabled, reset the counter and suppress strobe.
				count     <= DELAY;
				strobe_o  <= 1'b0;
			end
			else begin
				if (count == 32'd0) begin
					// Pulse strobe high for one clock cycle.
					strobe_o <= 1'b1;
					count    <= DELAY;
				end
				else begin
					strobe_o <= 1'b0;
					count    <= count - 1;
				end
			end
		end
	end

endmodule

output.rtl/sprite_fsm.sv:
module sprite_controller_fsm #(
   parameter MEM_ADDR_WIDTH = 16,
   parameter PIXEL_WIDTH    = 24,
   parameter SPRITE_WIDTH   = 16,
   parameter SPRITE_HEIGHT  = 16,
   parameter WAIT_WIDTH     = 4,
   parameter N_ROM          = 256
)(
   input  logic clk,
   input  logic rst_n,
   input  logic [WAIT_WIDTH-1:0] i_wait,
   output logic rw,                             
   output logic [MEM_ADDR_WIDTH-1:0] write_addr,
   output logic [PIXEL_WIDTH-1:0] write_data,   
   output logic [SPRITE_WIDTH-1:0] x_pos,       
   output logic [SPRITE_HEIGHT-1:0] y_pos,      
   input  logic [PIXEL_WIDTH-1:0] pixel_out,    
   output logic done                            
);

   // FSM state declaration
   typedef enum logic [2:0] {
       IDLE,
       INIT_WRITE,
       WRITE,
       INIT_READ,
       READ,
       WAIT,
       DONE
   } state_t;

   state_t current_state, next_state;

   // Counters for addressing and data
   logic [MEM_ADDR_WIDTH-1:0] addr_counter; 
   logic [PIXEL_WIDTH-1:0]    data_counter;    
   logic [WAIT_WIDTH-1:0]     wait_counter;     

   // FSM sequential process: state transitions and counter updates
   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n) begin
         current_state <= IDLE;
         addr_counter  <= 0;
         data_counter  <= 0;
         wait_counter  <= 0;
         rw            <= 0;
         done          <= 0;
      end else begin
         case (current_state)
           IDLE: begin
               // Reset all counters and outputs
               addr_counter  <= 0;
               data_counter  <= 0;
               wait_counter  <= 0;
               rw            <= 0;
               done          <= 0;
               current_state <= INIT_WRITE;
           end
           INIT_WRITE: begin
               // Prepare for write operations
               addr_counter <= 0;
               rw           <= 1;  // Set write mode
               current_state<= WRITE;
           end
           WRITE: begin
               // Write pixel data into memory sequentially.
               // Check if the last address has been reached.
               if (addr_counter == N_ROM - 1)
                   current_state <= INIT_READ;
               else begin
                   addr_counter <= addr_counter + 1;
                   data_counter <= data_counter + 1;
                   current_state<= WRITE;
               end
           end
           INIT_READ: begin
               // Prepare for read operations
               addr_counter <= 0;
               rw           <= 0;  // Set read mode
               current_state<= READ;
           end
           READ: begin
               // Read data from memory using addr_counter.
               // Calculate x_pos and y_pos from addr_counter.
               if (addr_counter == N_ROM - 1)
                   current_state <= WAIT;
               else begin
                   addr_counter <= addr_counter + 1;
                   current_state<= READ;
               end
           end
           WAIT: begin
               // Wait for the specified number of cycles.
               if (wait_counter == i_wait)
                   current_state <= DONE;
               else begin
                   wait_counter <= wait_counter + 1;
                   current_state<= WAIT;
               end
           end
           DONE: begin
               // Assert done for one cycle then return to IDLE.
               done <= 1;
               current_state<= IDLE;
           end
         endcase
      end
   end

   // Output assignments based on current state and counters
   always_comb begin
      // Default assignments
      rw          = 0;
      write_addr  = addr_counter;
      write_data  = data_counter;
      x_pos       = addr_counter % SPRITE_WIDTH;
      y_pos       = addr_counter / SPRITE_WIDTH;

      // In INIT_WRITE state, override write_data to 24'hFF0000.
      if (current_state == INIT_WRITE)
         write_data = 24'hFF0000;
      // In WRITE state, ensure rw is asserted.
      else if (current_state == WRITE)
         rw = 1;
   end

endmodule

input.rtl/Bitstream.sv:
module Bitstream(input  logic clk,rst_n,
                 input  logic enb,
                 input  logic rempty_in,
                 input  logic rinc_in,
                 input  logic [7:0] i_byte,
                 output logic o_bit,
                 output logic rempty_out,
                 output logic rinc_out);

    parameter IDLE  = 3'b000;
    parameter WaitR = 3'b001;
    parameter Ready = 3'b010;
    logic [1:0] curr_state,next_state;

    logic [0:7] byte_buf;
    logic [3:0] bp;
    logic rde;

    //FSM block

    always_ff @(posedge clk) begin
        if(!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case(curr_state)
            IDLE: next_state = Ready;
            IDLE:begin
                if(enb)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR:begin
                if(rempty_in)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready:begin
                if(rde)begin
                    if(rempty_in)begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end
                    else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end
            default:begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

