    always_ff @(posedge clk) begin
        if(!rst_n) curr_state <= IDLE;
        else curr_state <= next_state;
    end

    always_comb begin
        case(curr_state)
            IDLE: next_state = Ready;
            IDLE:begin
                if(enb)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = IDLE;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
            end
            WaitR:begin
                if(rempty_in)begin
                    next_state = WaitR;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b0;
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b1;
                    rinc_out   = 1'b1;
                end
            end
            Ready:begin
                if(rde)begin
                    if(rempty_in)begin
                        next_state = WaitR;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b0;
                    end
                    else begin
                        next_state = Ready;
                        rempty_out = 1'b1;
                        rinc_out   = 1'b1;
                    end
                end
                else begin
                    next_state = Ready;
                    rempty_out = 1'b0;
                    rinc_out   = 1'b0;
                end
            end
            default:begin
                next_state = IDLE;
                rempty_out = 1'b1;
                rinc_out   = 1'b0;
            end
        endcase
    end

    always @(posedge clk) begin
        if(rinc_out) 
           byte_buf <= i_byte[7:1];
    end

    always @(posedge clk) begin
        if(rinc_out) 
            bp <= 4'b0;
        else 
            if(rinc_in & ~rempty_out) 
               bp <= bp + 1'b1;
    end

    //Other comb logic

    assign rde = bp[3];
    assign o_bit = byte_buf[bp];

endmodule

input.rtl/square_root.sv:
module square_root #(parameter WIDTH = 16) (
    input  wire [WIDTH-1:0] num,       
    output reg  [WIDTH/2-1:0] root     
);
    reg [WIDTH-1:0] remainder,square;         
    reg [WIDTH/2-1:0] test_bit, temp_square;        
    integer i,j;

    always @(*) 
    begin
        remainder = num;               
        root = 0;                      
        temp_square = 0;


        for (i = WIDTH/2-1; i >= 0; i = i - 1) 
        begin
            test_bit = 1'b1 << i;      
            temp_square = (root | test_bit);        
            square = 0; 
            for (j = 0; j < WIDTH; j = j + 1) 
            begin
              if (temp_square[j]) 
              begin 
                  square = square + (temp_square << j); 
              end 
            end

            if (square <= remainder) 
            begin
                root = root | test_bit; 
            end
        end
    end
endmodule

output.rtl/square_root_seq.sv:
module square_root_seq #(parameter WIDTH = 16) (
    input  wire clk,
    input  wire rst,
    input  wire start,
    input  wire [WIDTH-1:0] num,
    output reg [WIDTH/2-1:0] final_root,
    output reg done
);

    // State definitions
    localparam IDLE    = 1'b0;
    localparam COMPUTE = 1'b1;

    // Internal registers for the subtraction-based square root algorithm
    reg state;
    reg [WIDTH-1:0] remainder; // Holds the current remainder value
    reg [WIDTH-1:0] odd;       // Current odd number to subtract
    reg [WIDTH/2-1:0] root;    // Accumulates the square root result

    // Sequential process implementing the state machine
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state        <= IDLE;
            remainder    <= 0;
            odd          <= 0;
            root         <= 0;
            final_root   <= 0;
            done         <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (start) begin
                        // Initialization: set remainder to input num, odd to 1, and reset root
                        remainder <= num;
                        odd       <= 1;
                        root      <= 0;
                        state     <= COMPUTE;
                    end else begin
                        // Stay in IDLE and ensure done is cleared when not computing
                        state     <= IDLE;
                        done      <= 0;
                    end
                end

                COMPUTE: begin
                    if (remainder >= odd) begin
                        // Subtract the current odd number from remainder,
                        // increment the square root result, and update odd (next odd = odd + 2)
                        remainder <= remainder - odd;
                        root      <= root + 1;
                        odd       <= odd + 2;
                        state     <= COMPUTE;
                    end else begin
                        // Termination: remainder is less than the current odd number.
                        // Assign the computed square root to final_root and assert done.
                        final_root <= root;
                        done       <= 1;
                        state      <= IDLE;
                    end
                end

                default: state <= IDLE;
            endcase
        end
    end

endmodule

output.rtl/static_branch_predict.sv:
module static_branch_predict (
  input  wire [31:0] fetch_rdata_i,  // Fetched 32-bit instruction
  input  wire [31:0] fetch_pc_i,     // Current program counter
  input  wire        fetch_valid_i,  // 1'b1 if the fetched instruction is valid
  output reg  [0:0]  predict_branch_taken_o, // 1'b1 if branch/jump is predicted as taken
  output reg [31:0]  predict_branch_pc_o     // Predicted target address if taken
);

  // Local parameters for opcodes
  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  //-------------------------------------------------------------------------
  // Intermediate signal declarations
  //-------------------------------------------------------------------------

  // Opcode extracted from the lower 7 bits of the instruction.
  wire [6:0] opcode;
  assign opcode = fetch_rdata_i[6:0];

  // Uncompressed branch immediate extraction:
  // For a 32-bit branch instruction, the immediate is:
  //   imm_b_type = {{19{instr[12]}}, instr[12:1], 1'b0};
  wire [31:0] imm_uncompressed_branch;
  assign imm_uncompressed_branch = {{19{fetch_rdata_i[12]}}, fetch_rdata_i[12:1], 1'b0};

  // Compressed branch immediate extraction:
  // For C.BEQZ/C.BNEZ, the equivalent 32-bit uncompressed encoding is:
  //   imm_cb_type = {{7{imm_cb[24]}}, imm_cb}
  // where
  //   imm_cb = { {4{instr[12]}}, instr[6:5], instr[2], 5'b0, 2'b01, instr[9:7],
  //              2'b00, instr[13], instr[11:10], instr[4:3], instr[12] }.
  wire [24:0] imm_cb_temp;
  assign imm_cb_temp = { {4{fetch_rdata_i[12]}},
                         fetch_rdata_i[6:5],
                         fetch_rdata_i[2],
                         5'b0,
                         2'b01,
                         fetch_rdata_i[9:7],
                         2'b00,
                         fetch_rdata_i[13],
                         fetch_rdata_i[11:10],
                         fetch_rdata_i[4:3],
                         fetch_rdata_i[12] };
  wire [31:0] imm_compressed_branch;
  assign imm_compressed_branch = {{7{imm_cb_temp[24]}}, imm_cb_temp};

  // Uncompressed jump (JAL) immediate extraction:
  // For JAL, the immediate is:
  //   imm_j_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0};
  wire [31:0] imm_jump;
  assign imm_jump = {{12{fetch_rdata_i[31]}},
                     fetch_rdata_i[19:12],
                     fetch_rdata_i[20],
                     fetch_rdata_i[30:21],
                     1'b0};

  // Uncompressed jump register (JALR) immediate extraction:
  // For JALR, the immediate is:
  //   imm_jalr = {{20{instr[31]}}, instr[31:20]};
  wire [31:0] imm_jalr;
  assign imm_jalr = {{20{fetch_rdata_i[31]}}, fetch_rdata_i[31:20]};

  // Signals for final immediate value, branch prediction and target address calculation.
  wire [31:0] branch_imm;
  wire        taken;
  wire [31:0] target;

  //-------------------------------------------------------------------------
  // Combinational logic for branch/jump prediction
  //-------------------------------------------------------------------------

  always_comb begin
    if (!fetch_valid_i) begin
      // When the fetched instruction is not valid, predict not-taken.
      taken    = 1'b0;
      target   = fetch_pc_i;
    end
    else begin
      case (opcode)
        // For branch instructions (BXXX, C.BEQZ, C.BNEZ)
        OPCODE_BRANCH: begin
          // Distinguish between uncompressed and compressed branch.
          // Uncompressed branches have rs2 in bits [24:20] (nonzero typically),
          // while compressed branches have these bits = 5'b00000.
          if (fetch_rdata_i[24:20] == 5'b00000)
            branch_imm = imm_compressed_branch;
          else
            branch_imm = imm_uncompressed_branch;
          // For branch instructions, predict taken if the sign bit of the immediate is 1.
          taken = branch_imm[31];
          // Target address is PC plus the sign-extended immediate.
          target = fetch_pc_i + branch_imm;
        end

        // For jump instructions (JAL, C.JAL) - always predict taken.
        OPCODE_JAL: begin
          branch_imm = imm_jump;
          taken      = 1'b1;
          target     = fetch_pc_i + branch_imm;
        end

        // For jump register instructions (JALR) - always predict taken.
        OPCODE_JALR: begin
          branch_imm = imm_jalr;
          taken      = 1'b1;
          // For JALR, add the rs1 register value (bits [19:15]) to the target.
          target     = fetch_pc_i + branch_imm + fetch_rdata_i[19:15];
        end

        // For any other instructions, predict not-taken.
        default: begin
          taken = 1'b0;
          target = fetch_pc_i;
        end
      endcase
    end
  end

  //-------------------------------------------------------------------------
  // Output assignments
  //-------------------------------------------------------------------------

  // Only drive outputs when fetch_valid_i is high.
  assign predict_branch_taken_o = fetch_valid_i ? taken : 1'b0;
  assign predict_branch_pc_o     = fetch_valid_i ? target   : fetch_pc_i;

endmodule

input.rtl/static_branch_predict.sv:
module static_branch_predict (

  // Instruction from fetch stage
  input  logic [31:0] fetch_rdata_i,
  input  logic [31:0] fetch_pc_i,
  input  logic [31:0] register_addr_i,
  input  logic        fetch_valid_i,

  // Prediction for supplied instruction
  output logic        predict_branch_taken_o,
  output logic [31:0] predict_branch_pc_o
);
  logic [31:0] reg_addr;
  logic [31:0] imm_jal_type;
  logic [31:0] imm_jalr_type;
  logic [31:0] imm_b_type;
  logic [31:0] imm_cj_type;
  logic [31:0] imm_cb_type;

  logic [31:0] branch_imm;

  logic [31:0] instr;

  logic instr_jal;
  logic instr_jalr;
  logic instr_b;
  logic instr_cj;
  logic instr_cb;

  logic instr_b_taken;


  localparam OPCODE_BRANCH = 7'h63;
  localparam OPCODE_JAL    = 7'h6F;
  localparam OPCODE_JALR   = 7'h67;

  assign instr = fetch_rdata_i;
  assign reg_addr = register_addr_i;

  assign imm_jal_type = {{12{instr[31]}}, instr[19:12], instr[20], instr[30:21], 1'b0 };
  assign imm_jalr_type = {{20{instr[31]}}, instr[31:20]}+reg_addr;
  assign imm_b_type = { {19{instr[31]}}, instr[31], instr[7], instr[30:25], instr[11:8], 1'b0 };

  assign imm_cj_type = { {20{instr[12]}}, instr[12], instr[8], instr[10:9], instr[6], instr[7],
    instr[2], instr[11], instr[5:3], 1'b0 };

  assign imm_cb_type = { {23{instr[12]}}, instr[12], instr[6:5], instr[2], instr[11:10],
    instr[4:3], 1'b0};

  assign instr_b    = instr[6:0] == OPCODE_BRANCH;
  assign instr_jal  = instr[6:0] == OPCODE_JAL;
  assign instr_jalr = instr[6:0] == OPCODE_JALR;

  assign instr_cb = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b110) | (instr[15:13] == 3'b111));
  assign instr_cj = (instr[1:0] == 2'b01) & ((instr[15:13] == 3'b101) | (instr[15:13] == 3'b001));

  always_comb begin
    branch_imm = imm_b_type;

    case(1'b1)
      instr_jal  : branch_imm = imm_jal_type;
      instr_jalr : branch_imm = imm_jalr_type;
      instr_b    : branch_imm = imm_b_type;
      instr_cj   : branch_imm = imm_cj_type;
      instr_cb   : branch_imm = imm_cb_type;
      default    : ;
    endcase
  end
  assign predict_branch_pc_o    = fetch_pc_i + branch_imm; 
  assign instr_b_taken = (instr_b & imm_b_type[31]) | (instr_cb & imm_cb_type[31]);
  assign predict_branch_taken_o = fetch_valid_i & (instr_jal | instr_jalr | instr_cj | instr_b_taken);

endmodule

