module sync_lifo #
  (
   parameter DATA_WIDTH = 8,
   parameter ADDR_WIDTH = 3
   )
  (
   input  logic         clock,
   input  logic         reset,
   input  logic         write_en,
   input  logic         read_en,
   input  logic [DATA_WIDTH-1:0] data_in,
   output logic         empty,
   output logic         full,
   output logic [DATA_WIDTH-1:0] data_out
   );

   // Memory array for LIFO storage
   reg [DATA_WIDTH-1:0] mem [0: (1<<ADDR_WIDTH)-1];

   // Stack pointer (points to the top of the LIFO)
   reg [ADDR_WIDTH-1:0] sp;

   // Registered output for data_out
   reg [DATA_WIDTH-1:0] data_out_reg;
   assign data_out = data_out_reg;

   // Combinational flags for empty and full conditions
   assign empty = (sp == 0);
   assign full  = (sp == ((1<<ADDR_WIDTH)-1));

   // Synchronous operations on rising edge of clock
   always_ff @(posedge clock) begin
      if (reset) begin
         // Synchronous reset: clear stack pointer, output, and memory array
         sp                    <= 0;
         data_out_reg          <= '0;
         integer i;
         for (i = 0; i < (1<<ADDR_WIDTH); i = i + 1)
            mem[i]             <= '0;
      end
      else begin
         // Use an intermediate variable for stack pointer updates
         integer next_sp;
         next_sp = sp;  // Default: no change

         // Write operation: push new data if not full
         if (write_en && !full) begin
            mem[sp] <= data_in;
            next_sp = sp + 1;
         end

         // Read operation: pop data if not empty
         if (read_en && !empty) begin
            // Use the updated pointer (if push occurred) for pop operation
            data_out_reg <= mem[next_sp];
            next_sp = next_sp - 1;
         end

         // Update the stack pointer
         sp <= next_sp;
      end
   end

endmodule

output.rtl/sync_serial_communication_top.sv:
Module: tx_block
// Description: Serializes parallel data based on the sel input.
//              Supports 8, 16, 32, or 64-bit transmission.
//              Generates a serial_out and a gated serial_clk.
//-----------------------------------------------------------------
module tx_block (
  input  logic         clk,
  input  logic         reset_n,
  input  logic [63:0]  data_in,
  input  logic [2:0]   sel,
  output logic         serial_out,
  output logic         done,
  output logic         serial_clk
);

  // State encoding: 0 = IDLE, 1 = TX
  logic state;
  // Bit counter (max 64 bits)
  logic [5:0] bit_count;
  // Shift register for serialization (only lower bits used)
  logic [63:0] shift_reg;
  // Computed bit width based on sel input
  logic [5:0] bit_width;

  // Determine bit_width based on sel.
  // Valid cases: 3'h1 -> 8, 3'h2 -> 16, 3'h3 -> 32, 3'h4 -> 64.
  // For sel==3'h0 or any other value, bit_width = 0 (no transmission).
  always_comb begin
    case (sel)
      3'h0, default: bit_width = 6'd0;
      3'h1: bit_width = 6'd8;
      3'h2: bit_width = 6'd16;
      3'h3: bit_width = 6'd32;
      3'h4: bit_width = 6'd64;
    endcase
  end

  // State machine for transmission.
  always_ff @(posedge clk or negedge reset_n) begin
    if (!reset_n) begin
      state         <= 1'b0;
      bit_count     <= 6'd0;
      shift_reg     <= 64'd0;
      done          <= 1'b0;
    end
    else begin
      case (state)
        1'b0: begin  // IDLE state
          done <= 1'b0;
          // Only start transmission if a valid data width is selected.
          if (bit_width != 6'd0) begin
            // Load the appropriate bits from data_in.
            case (sel)
              3'h1: shift_reg <= data_in[7:0];
              3'h2: shift_reg <= data_in[15:0];
              3'h3: shift_reg <= data_in[31:0];
              3'h4: shift_reg <= data_in;
              default: shift_reg <= 64'd0;
            endcase
            // Initialize bit counter (number of shifts required)
            bit_count <= bit_width - 6'd1;
            state     <= 1'b1;  // Move to TX state
          end
        end
        1'b1: begin  // TX state: shifting out bits
          // Output the LSB of the shift register.
          serial_out <= shift_reg[0];
          // Shift right by one bit.
          shift_reg  <= shift_reg >> 1;
          if (bit_count == 6'd0) begin
            // Transmission complete; assert done for one cycle.
            done <= 1'b1;
            state <= 1'b0;  // Return to IDLE
          end
          else begin
            bit_count <= bit_count - 6'd1;
            done      <= 1'b0;
          end
        end
      endcase
    end
  end

  // Generate serial_clk: when transmitting, use clk; otherwise, hold low.
  assign serial_clk = (state) ? clk : 1'b0;

endmodule


//-----------------------------------------------------------------
// Module: rx_block
// Description: Captures incoming serial data (data_in) and
//              reconstructs it into a 64-bit parallel output (data_out)
//              based on the sel input.
//              Supports 8, 16, 32, or 64-bit reception.
//-----------------------------------------------------------------
module rx_block (
  input  logic         clk,
  input  logic         reset_n,
  input  logic         data_in,     // Serialized data from transmitter.
  input  logic [2:0]   sel,
  input  logic         serial_clk,  // Clock used for sampling serial data.
  output logic [63:0]  data_out,
  output logic         done
);

  // State encoding: 0 = IDLE, 1 = RX
  logic state;
  // Bit counter (max 64 bits)
  logic [5:0] bit_count;
  // Shift register for receiving bits (accumulates LSB-first).
  logic [63:0] shift_reg;
  // Computed bit width based on sel input.
  logic [5:0] bit_width;

  // Determine bit_width based on sel.
  always_comb begin
    case (sel)
      3'h0, default: bit_width = 6'd0;
      3'h1: bit_width = 6'd8;
      3'h2: bit_width = 6'd16;
      3'h3: bit_width = 6'd32;
      3'h4: bit_width = 6'd64;
    endcase
  end

  // State machine for reception, triggered by serial_clk.
  always_ff @(posedge serial_clk or negedge reset_n) begin
    if (!reset_n) begin
      state         <= 1'b0;
      bit_count     <= 6'd0;
      shift_reg     <= 64'd0;
      data_out      <= 64'd0;
      done          <= 1'b0;
    end
    else begin
      case (state)
        1'b0: begin  // IDLE state
          done <= 1'b0;
          if (bit_width != 6'd0) begin
            // Initialize shift register and bit counter.
            shift_reg    <= 64'd0;
            bit_count    <= bit_width - 6'd1;
            state        <= 1'b1;  // Move to RX state
          end
        end
        1'b1: begin  // RX state: capturing bits
          // Shift left and insert the new bit at LSB.
          // This accumulates bits in LSB-first order.
          shift_reg <= {shift_reg[63:1], data_in};
          if (bit_count == 6'd0) begin
            // Reception complete; assign received data to data_out.
            data_out  <= shift_reg;
            done      <= 1'b1;  // Assert done for one cycle.
            state     <= 1'b0;  // Return to IDLE
          end
          else begin
            bit_count <= bit_count - 6'd1;
            done      <= 1'b0;
          end
        end
      endcase
    end
  end

endmodule


//-----------------------------------------------------------------
// Top-Level Module: sync_serial_communication_top
// Description: Integrates the tx_block and rx_block modules.
//              Connects the transmitter's serial outputs to the
//              receiver's serial inputs.
//-----------------------------------------------------------------
module sync_serial_communication_top (
  input  logic         clk,
  input  logic         reset_n,
  input  logic [63:0]  data_in,  // Data to be transmitted.
  input  logic [2:0]   sel,      // Controls the data width for TX.
  output logic [63:0]  data_out, // Reconstructed data from RX.
  output logic         done      // Indicates valid output from RX.
);

  // Wires between modules.
  wire serial_out;
  wire tx_done;      // Not used externally.
  wire serial_clk;

  // Instantiate the transmitter block.
  tx_block u_tx (
    .clk        (clk),
    .reset_n    (reset_n),
    .data_in    (data_in),
    .sel        (sel),
    .serial_out (serial_out),
    .done       (tx_done),
    .serial_clk (serial_clk)
  );

  // Instantiate the receiver block.
  rx_block u_rx (
    .clk          (clk),
    .reset_n      (reset_n),
    .data_in      (serial_out), // Connect transmitter's serial_out.
    .sel          (sel),
    .serial_clk   (serial_clk),
    .data_out     (data_out),
    .done         (done)
  );

endmodule

output.rtl/thermostat.v:
module thermostat (
    input  wire         i_clk,    // Clock for sequential logic
    input  wire         i_rst,    // Asynchronous active-low reset
    input  wire [5:0]   i_temp_feedback, // Temperature feedback bits:
                                        // bit5: i_full_cold, bit4: i_medium_cold,
                                        // bit3: i_low_cold, bit2: i_low_hot,
                                        // bit1: i_medium_hot, bit0: i_full_hot
    input  wire         i_fan_on, // Manual fan override (1 = on)
    input  wire         i_enable, // Enable thermostat (0 = off)
    input  wire         i_fault,  // Fault condition (1 = fault)
    input  wire         i_clr,    // Clear fault condition
    output reg          o_heater_full,
    output reg          o_heater_medium,
    output reg          o_heater_low,
    output reg          o_aircon_full,
    output reg          o_aircon_medium,
    output reg          o_aircon_low,
    output reg          o_fan,
    output reg [2:0]    o_state   // Current FSM state
);

   // State Encoding
   localparam HEAT_LOW   = 3'b000;
   localparam HEAT_MED   = 3'b001;
   localparam HEAT_FULL  = 3'b010;
   localparam AMBIENT    = 3'b011;
   localparam COOL_LOW   = 3'b100;
   localparam COOL_MED   = 3'b101;
   localparam COOL_FULL  = 3'b110;

   // Next state logic (combinational)
   // Priority: Cold conditions (if any cold bit is asserted) then Hot conditions, else AMBIENT.
   // Also, if fault, disable, or clear is active, force next state to AMBIENT.
   reg [2:0] next_state;
   always @(*) begin
      if (i_fault || !i_enable || i_clr)
         next_state = AMBIENT;
      else begin
         // Default to AMBIENT
         next_state = AMBIENT;
         if (i_temp_feedback[5])   // i_full_cold
            next_state = HEAT_FULL;
         else if (i_temp_feedback[4]) // i_medium_cold
            next_state = HEAT_MED;
         else if (i_temp_feedback[3]) // i_low_cold
            next_state = HEAT_LOW;
         else if (i_temp_feedback[0]) // i_full_hot
            next_state = COOL_FULL;
         else if (i_temp_feedback[1]) // i_medium_hot
            next_state = COOL_MED;
         else if (i_temp_feedback[2]) // i_low_hot
            next_state = COOL_LOW;
      end
   end

   // Sequential state register and output logic
   always @(posedge i_clk or negedge i_rst) begin
      if (!i_rst) begin
         // Asynchronous reset: Force state to AMBIENT and all outputs to 0
         o_state          <= AMBIENT;
         o_heater_full    <= 1'b0;
         o_heater_medium  <= 1'b0;
         o_heater_low     <= 1'b0;
         o_aircon_full    <= 1'b0;
         o_aircon_medium  <= 1'b0;
         o_aircon_low     <= 1'b0;
         o_fan            <= 1'b0;
      end
      else begin
         // Fault, disable, or clear override: Force outputs off and state to AMBIENT
         if (i_fault || !i_enable || i_clr) begin
            o_state          <= AMBIENT;
            o_heater_full    <= 1'b0;
            o_heater_medium  <= 1'b0;
            o_heater_low     <= 1'b0;
            o_aircon_full    <= 1'b0;
            o_aircon_medium  <= 1'b0;
            o_aircon_low     <= 1'b0;
            o_fan            <= 1'b0;
         end
         else begin
            // Normal operation: Update state and outputs based on temperature feedback
            o_state <= next_state;
            case (o_state)
               HEAT_FULL: begin
                  o_heater_full    <= 1'b1;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
               HEAT_MED: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b1;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
               HEAT_LOW: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b1;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
               COOL_FULL: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b1;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
               COOL_MED: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b1;
                  o_aircon_low     <= 1'b0;
               end
               COOL_LOW: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b1;
               end
               AMBIENT: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
               default: begin
                  o_heater_full    <= 1'b0;
                  o_heater_medium  <= 1'b0;
                  o_heater_low     <= 1'b0;
                  o_aircon_full    <= 1'b0;
                  o_aircon_medium  <= 1'b0;
                  o_aircon_low     <= 1'b0;
               end
            endcase

            // Fan control: o_fan is 1 if any heating/cooling output is active OR if i_fan_on is asserted.
            if (o_state == HEAT_FULL || o_state == HEAT_MED || o_state == HEAT_LOW ||
                o_state == COOL_FULL || o_state == COOL_MED || o_state == COOL_LOW)
               o_fan <= 1'b1;
            else
               o_fan <= i_fan_on;
         end
      end
   end

endmodule

output.rtl/ttc_counter_lite.sv:
module ttc_counter_lite (
  input  logic         clk,
  input  logic         reset,
  input  logic [3:0]   axi_addr,
  input  logic [31:0]  axi_wdata,
  input  logic         axi_write_en,
  input  logic         axi_read_en,
  output logic [31:0]  axi_rdata,
  output logic         interrupt
);

  // Internal registers
  // The counter, match_value, and reload_value are 16-bit wide.
  reg  [15:0] count;
  reg  [15:0] match_value;
  reg  [15:0] reload_value;
  // Control register: bit0 = Enable, bit1 = Interval Mode, bit2 = Interrupt Enable.
  reg  [31:0] control;
  // Status register: bit0 = Interrupt status.
  reg  [31:0] status;
  // match_flag indicates that a match event has occurred.
  reg         match_flag;
  // old_count holds the previous cycle's counter value for match detection.
  reg  [15:0] old_count;

  // Main always_ff block: Handles AXI write operations, timer update, and match detection.
  always_ff @(posedge clk or posedge reset) begin
    if (reset) begin
      count        <= 16'd0;
      match_value  <= 16'd0;
      reload_value <= 16'd0;
      control      <= 32'd0;
      status       <= 32'd0;
      match_flag   <= 1'b0;
      old_count    <= 16'd0;
    end
    else begin
      // AXI Write Operations
      if (axi_write_en) begin
        case (axi_addr)
          4'h0: begin
            // Count Register is read-only; ignore writes.
          end
          4'h1: begin
            match_value <= axi_wdata[15:0];
          end
          4'h2: begin
            reload_value <= axi_wdata[15:0];
          end
          4'h3: begin
            control <= axi_wdata;
          end
          4'h4: begin
            status <= axi_wdata;
            // Writing a 0 to bit0 clears the interrupt flag.
            if (axi_wdata[0] == 1'b0)
              match_flag <= 1'b0;
          end
          default: begin
            // Invalid address; no operation.
          end
        endcase
      end

      // Timer Operation: Update counter if enabled.
      if (control[0]) begin  // if timer is enabled
        if (count == match_value) begin
          if (control[1]) begin
            // Interval mode: Reload counter to reload_value on match.
            count <= reload_value;
          end
          else begin
            // Non-interval mode: Hold counter at match_value.
            count <= count; // no change
          end
        end
        else begin
          // Normal increment.
          count <= count + 1;
        end
      end

      // Match Detection:
      // Detect a transition to the match value.
      if (control[0]) begin  // only check when timer is enabled
        if ((count == match_value) && (old_count != match_value))
          match_flag <= 1'b1;
        // In interval mode, when the counter is not at match_value, clear the flag.
        else if (control[1] && (count != match_value))
          match_flag <= 1'b0;
      end

      // Update old_count with the value of count from the beginning of the clock cycle.
      old_count <= count;
    end
  end

  // AXI Read Logic: Generate read data based on the current register values.
  always_comb begin
    // Default assignment.
    axi_rdata = 32'd0;
    case (axi_addr)
      4'h0: axi_rdata = {16'd0, count};          // Count Register (lower 16 bits)
      4'h1: axi_rdata = {16'd0, match_value};      // Match Value Register
      4'h2: axi_rdata = {16'd0, reload_value};     // Reload Value Register
      4'h3: axi_rdata = control;                   // Control Register
      4'h4: axi_rdata = status;                    // Status Register
      default: axi_rdata = 32'd0;
    endcase
  end

  // Interrupt Generation: Assert interrupt if a match event is flagged and interrupts are enabled.
  assign interrupt = match_flag & control[2];

endmodule

output.rtl/unpack_one_hot.v:
module unpack_one_hot (
  input           sign,         // 1-bit sign control: 1 = signed, 0 = unsigned
  input           size,         // 1-bit size control (used when one_hot_selector == 3'b100)
  input  [2:0]    one_hot_selector, // One-hot encoded selector for unpacking granularity
  input  [255:0]  source_reg,   // 256-bit packed input data
  output reg [511:0] destination_reg // 512-bit destination register
);

  // Default assignment: destination_reg lower 256 bits = source_reg, rest zero.
  // This default will be overridden by valid one_hot_selector cases.
  always @(*) begin
    destination_reg = {256'b0, source_reg};

    case (one_hot_selector)
      3'b001: begin
        // Case 1: Each 1-bit segment of source_reg is unpacked into an 8-bit segment.
        // We use only the lower 64 segments (64*8 = 512 bits).
        integer i;
        for (i = 0; i < 64; i = i + 1) begin
          // Extract 1-bit chunk from source_reg at position i.
          bit bit_val = source_reg[i];
          if (sign)
            destination_reg[i*8 +: 8] = {7{bit_val}};
          else
            destination_reg[i*8 +: 8] = {7'b0, bit_val};
        end
      end

      3'b010: begin
        // Case 2: Each 2-bit segment of source_reg is unpacked into an 8-bit segment.
        // We use only the lower 64 segments (64*8 = 512 bits).
        integer i;
        for (i = 0; i < 64; i = i + 1) begin
          // Extract 2-bit chunk starting at bit 2*i.
          bit [1:0] chunk;
          {chunk} = source_reg[2*i +: 2];
          if (sign)
            destination_reg[i*8 +: 8] = {{6{chunk[1]}}, chunk};
          else
            destination_reg[i*8 +: 8] = {6'b0, chunk};
        end
      end

      3'b100: begin
        // Case 3: Size-dependent behavior.
        if (size) begin
          // When size == 1: Each 8-bit segment of source_reg is unpacked into a 16-bit segment.
          // 256/8 = 32 segments, each 16 bits -> 32*16 = 512 bits.
          integer i;
          for (i = 0; i < 32; i = i + 1) begin
            // Extract 8-bit chunk starting at bit 8*i.
            bit [7:0] chunk;
            {chunk} = source_reg[8*i +: 8];
            if (sign)
              destination_reg[i*16 +: 16] = {{7{chunk[7]}}, chunk};
            else
              destination_reg[i*16 +: 16] = {7'b0, chunk};
          end
        end
        else begin
          // When size == 0: Each 4-bit segment of source_reg is unpacked into an 8-bit segment.
          // 256/4 = 64 segments, each 8 bits -> 64*8 = 512 bits.
          integer i;
          for (i = 0; i < 64; i = i + 1) begin
            // Extract 4-bit chunk starting at bit 4*i.
            bit [3:0] chunk;
            {chunk} = source_reg[4*i +: 4];
            if (sign)
              destination_reg[i*8 +: 8] = {{3{chunk[3]}}, chunk};
            else
              destination_reg[i*8 +: 8] = {3'b0, chunk};
          end
        end
      end

      default: begin
        // Default case: No valid one_hot_selector provided.
        // The source_reg is directly assigned to the lower 256 bits of destination_reg.
        destination_reg = {256'b0, source_reg};
      end
    endcase
  end

endmodule

output.rtl/vending_machine.sv:
module vending_machine (
    input  logic         clk,
    input  logic         rst,
    input  logic         item_button,
    input  logic [2:0]   item_selected,
    input  logic [3:0]   coin_input,
    input  logic         cancel,
    output logic         dispense_item,
    output logic         return_change,
    output logic [4:0]   item_price,
    output logic [4:0]   change_amount,
    output logic [2:0]   dispense_item_id,
    output logic         error,
    output logic         return_money
);

  // Define FSM states
  typedef enum logic [2:0] {
    IDLE              = 3'd0,
    ITEM_SELECTION    = 3'd1,
    PAYMENT_VALIDATION= 3'd2,
    DISPENSING_ITEM   = 3'd3,
    RETURN_CHANGE     = 3'd4,
    RETURN_MONEY      = 3'd5
  } state_t;

  state_t state, next_state;

  // Registers for coin accumulation and selected item info
  logic [5:0] coins_accumulated;  // 6-bit accumulator to allow for excess coins
  logic [4:0] current_item_price;
  logic [2:0] current_item_id;

  // Registers for edge detection of toggle signals
  logic item_button_prev;
  logic cancel_prev;

  // Combinational block: Next state logic and output assignments
  always_comb begin
    // Default assignments
    next_state         = state;
    dispense_item      = 1'b0;
    return_change      = 1'b0;
    error              = 1'b0;
    return_money       = 1'b0;
    item_price         = 5'd0;
    change_amount      = 5'd0;
    dispense_item_id   = 3'd0;

    case (state)
      IDLE: begin
        // If coins are inserted without item_button press, trigger error.
        if (coin_input != 4'd0) begin
          next_state = RETURN_MONEY;
        end
        // Detect rising edge of item_button to start transaction.
        else if (item_button && !item_button_prev) begin
          next_state = ITEM_SELECTION;
        end
      end

      ITEM_SELECTION: begin
        // Cancel transaction: rising edge of cancel triggers error.
        if (cancel && !cancel_prev) begin
          next_state = RETURN_MONEY;
        end
        // Valid item selection: only 001, 010, 011, and 100 are accepted.
        else if ((item_selected == 3'b001) ||
                 (item_selected == 3'b010) ||
                 (item_selected == 3'b011) ||
                 (item_selected == 3'b100)) begin
          // Map item selection to item price and ID.
          case (item_selected)
            3'b001: current_item_price = 5'd5;
            3'b010: current_item_price = 5'd7;
            3'b011: current_item_price = 5'd10;
            3'b100: current_item_price = 5'd15;
            default: current_item_price = 5'd0;
          endcase
          current_item_id = item_selected;
          next_state = PAYMENT_VALIDATION;
        end
        // Invalid item selection triggers error.
        else begin
          next_state = RETURN_MONEY;
        end
      end

      PAYMENT_VALIDATION: begin
        // Cancel transaction during payment.
        if (cancel && !cancel_prev) begin
          next_state = RETURN_MONEY;
        end
        else begin
          // Only accept coin values of 1, 2, 5, or 10.
          if (((coin_input == 4'd1) || (coin_input == 4'd2) ||
               (coin_input == 4'd5) || (coin_input == 4'd10))) begin
            // Check if accumulated coins meet/exceed the item price.
            if ((coins_accumulated + coin_input) >= current_item_price) begin
              next_state = DISPENSING_ITEM;
            end
            else begin
              next_state = PAYMENT_VALIDATION;
            end
          end
          // Invalid coin input triggers error.
          else begin
            next_state = RETURN_MONEY;
          end
        end
      end

      DISPENSING_ITEM: begin
        // Assert dispense_item pulse for one cycle.
        dispense_item = 1'b1;
        // If excess coins were inserted, calculate change and move to RETURN_CHANGE.
        if (coins_accumulated > current_item_price) begin
          next_state = RETURN_CHANGE;
        end
        else begin
          next_state = IDLE;
        end
      end

      RETURN_CHANGE: begin
        // Assert return_change pulse for one cycle.
        return_change = 1'b1;
        change_amount = coins_accumulated - current_item_price;
        next_state = IDLE;
      end

      RETURN_MONEY: begin
        // Assert return_money pulse for one cycle.
        return_money = 1'b1;
        next_state = IDLE;
      end

      default: next_state = IDLE;
    endcase

    // Generate error pulse when transitioning to RETURN_MONEY from a non-RETURN_MONEY state.
    if ((next_state == RETURN_MONEY) && (state != RETURN_MONEY)) begin
      error = 1'b1;
    end
  end

  // Sequential block: Update state and registers on clock edge.
  always_ff @(posedge clk or posedge rst) begin
    if (rst) begin
      state             <= IDLE;
      coins_accumulated <= 6'd0;
      current_item_price<= 5'd0;
      current_item_id   <= 3'd0;
      item_button_prev  <= 1'b0;
      cancel_prev       <= 1'b0;
    end
    else begin
      state <= next_state;
      // Update edge detection registers.
      item_button_prev <= item_button;
      cancel_prev      <= cancel;
      // In PAYMENT_VALIDATION state, accumulate valid coin input.
      if (state == PAYMENT_VALIDATION) begin
        if (((coin_input == 4'd1) || (coin_input == 4'd2) ||
             (coin_input == 4'd5) || (coin_input == 4'd10))) begin
          coins_accumulated <= coins_accumulated + coin_input;
        end
      end
      // No coin accumulation in other states.
    end
  end

  // Output block: Drive item_price and dispense_item_id only during ITEM_SELECTION.
  always_comb begin
    if (state == ITEM_SELECTION) begin
      item_price      = current_item_price;
      dispense_item_id= current_item_id;
    end
    else begin
      item_price      = 5'd0;
      dispense_item_id= 3'd0;
    end
  end

endmodule

output.rtl/vga_controller.sv:
module vga_controller(
    input  logic clock,
    input  logic reset,
    input  logic [7:0] color_in,
    output logic hsync,
    output logic vsync,
    output logic [7:0] red,
    output logic [7:0] green,
    output logic [7:0] blue,
    output logic [9:0] next_x,
    output logic [9:0] next_y,
    output logic sync,
    output logic clk,
    output logic blank
);

   //-------------------------------------------------------------------------
   // Timing Parameters for 640x480 @25MHz
   //-------------------------------------------------------------------------
   localparam integer H_ACTIVE  = 640;   // Active display pixels per row
   localparam integer H_FRONT   = 16;    // Front porch (in pixels)
   localparam integer H_PULSE   = 96;    // Horizontal sync pulse (in pixels)
   localparam integer H_BACK    = 48;    // Back porch (in pixels)
   localparam integer H_TOTAL   = H_ACTIVE + H_FRONT + H_PULSE + H_BACK; // 800 pixels per line

   localparam integer V_ACTIVE  = 480;   // Active display lines per frame
   localparam integer V_FRONT   = 10;    // Vertical front porch (in lines)
   localparam integer V_PULSE   = 2;     // Vertical sync pulse (in lines)
   localparam integer V_BACK    = 33;    // Vertical back porch (in lines)
   localparam integer V_TOTAL   = V_ACTIVE + V_FRONT + V_PULSE + V_BACK; // 525 lines per frame

   //-------------------------------------------------------------------------
   // Internal Registers
   //-------------------------------------------------------------------------
   reg [9:0] h_counter;
   reg [9:0] v_counter;
   reg hsync_reg;
   reg vsync_reg;
   reg blank_reg;
   reg [9:0] next_x_reg;
   reg [9:0] next_y_reg;
   reg [7:0] red_reg;
   reg [7:0] green_reg;
   reg [7:0] blue_reg;

   //-------------------------------------------------------------------------
   // Single always_ff Block: Sequential Logic & Signal Generation
   //-------------------------------------------------------------------------
   always_ff @(posedge clock or posedge reset) begin
      if (reset) begin
         h_counter    <= 10'd0;
         v_counter    <= 10'd0;
         hsync_reg    <= 1'b1;  // Start with active (HIGH) state
         vsync_reg    <= 1'b1;
         blank_reg    <= 1'b0;
         next_x_reg   <= 10'd0;
         next_y_reg   <= 10'd0;
         red_reg      <= 8'd0;
         green_reg    <= 8'd0;
         blue_reg     <= 8'd0;
      end
      else begin
         //-----------------------------------------------------------------
         // Horizontal Counter Update
         //-----------------------------------------------------------------
         if (h_counter == H_TOTAL - 1) begin
            h_counter <= 10'd0;
            // At end of horizontal line, update vertical counter
            if (v_counter == V_TOTAL - 1)
               v_counter <= 10'd0;
            else
               v_counter <= v_counter + 1;
         end
         else begin
            h_counter <= h_counter + 1;
         end

         //-----------------------------------------------------------------
         // Generate hsync Signal
         // hsync is HIGH during active and porch periods,
         // and LOW during the horizontal sync pulse.
         // Active + Front Porch: 0 to (H_ACTIVE + H_FRONT - 1) = 0 to 655
         // Sync Pulse: 656 to 751 (96 cycles)
         // Back Porch: 752 to 799 (48 cycles)
         //-----------------------------------------------------------------
         hsync_reg <= ((h_counter < (H_ACTIVE + H_FRONT)) ||
                       (h_counter >= (H_ACTIVE + H_FRONT + H_PULSE + H_BACK))) ? 1'b1 : 1'b0;

         //-----------------------------------------------------------------
         // Generate vsync Signal
         // vsync is HIGH during active and porch periods,
         // and LOW during the vertical sync pulse.
         // Active + Front Porch: 0 to 489
         // Sync Pulse: 490 to 491 (2 lines)
         // Back Porch: 492 to 524 (33 lines)
         //-----------------------------------------------------------------
         vsync_reg <= ((v_counter < (V_ACTIVE + V_FRONT)) ||
                       (v_counter >= (V_ACTIVE + V_FRONT + V_PULSE + V_BACK))) ? 1'b1 : 1'b0;

         //-----------------------------------------------------------------
         // Blank Signal: ACTIVE HIGH when outside the active display area.
         // Active display is when h_counter < H_ACTIVE and v_counter < V_ACTIVE.
         //-----------------------------------------------------------------
         blank_reg <= (h_counter >= H_ACTIVE) || (v_counter >= V_ACTIVE);

         //-----------------------------------------------------------------
         // Pixel Position Tracking: next_x and next_y are valid only during
         // the active region. Outside active region, they are set to 0.
         //-----------------------------------------------------------------
         next_x_reg <= (h_counter < H_ACTIVE) ? h_counter : 10'd0;
         next_y_reg <= (v_counter < V_ACTIVE) ? v_counter : 10'd0;

         //-----------------------------------------------------------------
         // Color Outputs: Use color_in during active display; blank otherwise.
         // red   = {color_in[7:5], 5'd0};
         // green = {color_in[4:2], 5'd0};
         // blue  = {color_in[1:0], 6'd0};
         //-----------------------------------------------------------------
         if ((h_counter < H_ACTIVE) && (v_counter < V_ACTIVE)) begin
            red_reg    <= {color_in[7:5], 5'd0};
            green_reg  <= {color_in[4:2], 5'd0};
            blue_reg   <= {color_in[1:0], 6'd0};
         end
         else begin
            red_reg    <= 8'd0;
            green_reg  <= 8'd0;
            blue_reg   <= 8'd0;
         end
      end
   end

   //-------------------------------------------------------------------------
   // Output Assignments
   //-------------------------------------------------------------------------
   assign hsync   = hsync_reg;
   assign vsync   = vsync_reg;
   assign red     = red_reg;
   assign green   = green_reg;
   assign blue    = blue_reg;
   assign next_x  = next_x_reg;
   assign next_y  = next_y_reg;
   assign sync    = 1'b0;   // Fixed to LOW as per design specification
   assign clk     = clock;  // Direct connection to input clock
   assign blank   = blank_reg;

endmodule

module vga_controller (
    input  logic         clock,      // 25 MHz
    input  logic         reset,      // Active high
    input  logic [7:0]   color_in,   // Pixel color data (RRRGGGBB)
    output logic [9:0]   next_x,     // x-coordinate of NEXT pixel that will be drawn
    output logic [9:0]   next_y,     // y-coordinate of NEXT pixel that will be drawn
    output logic         hsync,      // HSYNC (to VGA connector)
    output logic         vsync,      // VSYNC (to VGA connector)
    output logic [7:0]   red,        // RED (to resistor DAC VGA connector)
    output logic [7:0]   green,      // GREEN (to resistor DAC to VGA connector)
    output logic [7:0]   blue,       // BLUE (to resistor DAC to VGA connector)
    output logic         sync,       // SYNC to VGA connector
    output logic         clk,        // CLK to VGA connector
    output logic         blank,      // BLANK to VGA connector
    output logic [7:0]   h_state,    // States of Horizontal FSM
    output logic [7:0]   v_state     // States of Vertical FSM
);

    // Timing parameters
    parameter logic [9:0] H_ACTIVE  = 10'd640;
    parameter logic [9:0] H_FRONT   = 10'd16;
    parameter logic [9:0] H_PULSE   = 10'd96;
    parameter logic [9:0] H_BACK    = 10'd48;
    parameter logic [9:0] V_ACTIVE  = 10'd480;
    parameter logic [9:0] V_FRONT   = 10'd10;
    parameter logic [9:0] V_PULSE   = 10'd2;
    parameter logic [9:0] V_BACK    = 10'd33;

    // State definitions
    parameter logic LOW         = 1'b0;
    parameter logic HIGH        = 1'b1;
    parameter logic [7:0] H_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] H_FRONT_STATE   = 8'd1;
    parameter logic [7:0] H_PULSE_STATE   = 8'd2;
    parameter logic [7:0] H_BACK_STATE    = 8'd3;
    parameter logic [7:0] V_ACTIVE_STATE  = 8'd0;
    parameter logic [7:0] V_FRONT_STATE   = 8'd1;
    parameter logic [7:0] V_PULSE_STATE   = 8'd2;
    parameter logic [7:0] V_BACK_STATE    = 8'd3;

    // Internal signals
    logic         line_done;
    logic [9:0]   h_counter;
    logic [9:0]   v_counter;
    logic         hsync_reg;
    logic         vsync_reg;

    // FSM and RGB signal handling
    always_ff @(posedge clock or posedge reset) begin
        if (reset) begin
            h_counter   <= 10'd0;
            v_counter   <= 10'd0;
            h_state     <= H_ACTIVE_STATE;
            v_state     <= V_ACTIVE_STATE;
            line_done   <= LOW;
        end
        else begin
            // Horizontal FSM
            case (h_state)
                H_ACTIVE_STATE: begin
                    if (h_counter < H_ACTIVE - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_ACTIVE_STATE;
                    end
                    else begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_FRONT_STATE;
                    end
                end
                H_FRONT_STATE: begin
                    if (h_counter < H_FRONT - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_FRONT_STATE;
                    end
                    else begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_PULSE_STATE;
                    end
                end
                H_PULSE_STATE: begin
                    if (h_counter < H_PULSE - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_PULSE_STATE;
                    end
                    else begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_BACK_STATE;
                    end
                end
                H_BACK_STATE: begin
                    if (h_counter < H_BACK - 1) begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_BACK_STATE;
                    end
                    else begin
                        h_counter <= h_counter + 1;
                        h_state   <= H_ACTIVE_STATE;
                        line_done <= HIGH;
                    end
                end
            endcase

            // Vertical FSM: update only at the end of a line (when line_done is HIGH)
            if (line_done == HIGH) begin
                case (v_state)
                    V_ACTIVE_STATE: begin
                        if (v_counter < V_ACTIVE - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_ACTIVE_STATE;
                        end
                        else begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_FRONT_STATE;
                        end
                    end
                    V_FRONT_STATE: begin
                        if (v_counter < V_FRONT - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_FRONT_STATE;
                        end
                        else begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_PULSE_STATE;
                        end
                    end
                    V_PULSE_STATE: begin
                        if (v_counter < V_PULSE - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_PULSE_STATE;
                        end
                        else begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_BACK_STATE;
                        end
                    end
                    V_BACK_STATE: begin
                        if (v_counter < V_BACK - 1) begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_BACK_STATE;
                        end
                        else begin
                            v_counter <= v_counter + 1;
                            v_state   <= V_ACTIVE_STATE;
                        end
                    end
                endcase
            end

            // RGB signal handling:
            // During active display (H_ACTIVE_STATE and V_ACTIVE_STATE) use color_in.
            // Otherwise, set RGB outputs to zero.
            if ((h_state == H_ACTIVE_STATE) && (v_state == V_ACTIVE_STATE)) begin
                red   <= color_in;
                green <= color_in;
                blue  <= color_in;
            end
            else begin
                red   <= 8'd0;
                green <= 8'd0;
                blue  <= 8'd0;
            end
        end
    end

    // Generate hsync and vsync based on state
    assign hsync_reg = (h_state == H_PULSE_STATE) ? LOW : HIGH;
    assign vsync_reg = (v_state == V_PULSE_STATE) ? LOW : HIGH;

    // Output assignments
    assign hsync = hsync_reg;
    assign vsync = vsync_reg;
    assign blank = hsync_reg & vsync_reg;
    assign sync  = 1'b0;
    assign clk   = clock;

    // Next pixel coordinates (active only during active display)
    assign next_x = (h_state == H_ACTIVE_STATE) ? h_counter : 10'd0;
    assign next_y = (v_state == V_ACTIVE_STATE) ? v_counter : 10'd0;

endmodule

