  // Function: byte_swap
  // Description: Swaps the byte order of a 32-bit word.
  //-------------------------------------------------------------------------
  function automatic logic [31:0] byte_swap(input logic [31:0] data);
    begin
      byte_swap = { data[7:0], data[15:8], data[23:16], data[31:24] };
