module Bit_Difference_Counter
#(
    parameter BIT_WIDTH    = 3,            // Width of the input vectors
    parameter COUNT_WIDTH  = $clog2(BIT_WIDTH+1)  // Width required to represent the maximum count
)
(
    input  wire [BIT_WIDTH-1:0] input_A,
    input  wire [BIT_WIDTH-1:0] input_B,
    output reg  [COUNT_WIDTH-1:0] bit_difference_count
);

    // Compute XOR between input_A and input_B using Data_Reduction module
    // Pack input_A and input_B into a 2*BIT_WIDTH vector so that each bit position
    // corresponds across the two vectors.
    wire [BIT_WIDTH-1:0] xor_result;
    Data_Reduction #(
        .REDUCTION_OP(3'b010), // Use XOR operation
        .DATA_WIDTH(BIT_WIDTH),
        .DATA_COUNT(2)
    ) xor_inst (
        .data_in({input_A, input_B}),
        .reduced_data_out(xor_result)
    );

    // Count the number of set bits (1's) in the XOR result.
    // This count represents the Hamming distance between input_A and input_B.
    integer i;
    always_comb begin
        bit_difference_count = 0;
        for (i = 0; i < BIT_WIDTH; i = i + 1) begin
            if (xor_result[i])
                bit_difference_count = bit_difference_count + 1;
        end
    end

endmodule

